&gt;136&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;137&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;138&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;139&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;140&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;141&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;142&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;143&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;144&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;145&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;146&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;147&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;148&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;149&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;150&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;151&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;152&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;153&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;154&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;155&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;156&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;157&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;158&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;159&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;160&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;161&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;162&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;163&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;164&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;165&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;166&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;167&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;168&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;169&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;170&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;171&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;172&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;173&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;174&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;175&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;176&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;177&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;178&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;179&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;180&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;181&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;182&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;183&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;184&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;185&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;186&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;187&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;188&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;189&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;原始数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b = a.reshape(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;修改后的数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(b)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;).reshape((&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;原始数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; row &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; a:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(row)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;迭代后的数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; element &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; a.flat:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(element)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;原数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;展开后的数组:&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a.flatten())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;以F风格顺序展开的数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a.flatten(order=&lt;span class=&#34;string&#34;&gt;&amp;quot;F&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# numpy.ravel() 展平的数组元素，顺序通常是&amp;quot;C风格&amp;quot;，返回的是数组视图（view，有点类似 C/C++引用reference的意味），修改会影响原始数组。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;原数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;调用 ravel 函数之后：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a.ravel())&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;以 F 风格顺序调用 ravel 函数之后：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a.ravel(order=&lt;span class=&#34;string&#34;&gt;&amp;quot;F&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;12&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.transpose(a))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a.T)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 创建了三维的 ndarray&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;原数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;获取数组中一个值：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.where(a == &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;])  &lt;span class=&#34;comment&#34;&gt;# 为 6&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 将轴 2 滚动到轴 0（宽度到深度）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;调用 rollaxis 函数：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b = np.rollaxis(a, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(b)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 查看元素 a[1,1,0]，即 6 的坐标，变成 [0, 1, 1]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 最后一个 0 移动到最前面&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.where(b == &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 将轴 2 滚动到轴 1：（宽度到高度）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;调用 rollaxis 函数：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c = np.rollaxis(a, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(c)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 查看元素 a[1,1,0]，即 6 的坐标，变成 [1, 0, 1]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 最后的 0 和 它前面的 1 对换位置&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.where(c == &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 创建了三维的 ndarray&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;原数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 现在交换轴 0（深度方向）到轴 2（宽度方向）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;调用 swapaxes 函数后的数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.swapaxes(a, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# numpy.broadcast_to 函数将数组广播到新形状。它在原始数组上返回只读视图。 它通常不连续。 如果新形状不符合 NumPy 的广播规则，该函数可能会抛出ValueError。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;原数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;调用 broadcast_to 函数之后：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.broadcast_to(a, (&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# numpy.expand_dims 函数通过在指定位置插入新的轴来扩展数组形状，函数格式如下:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;x = np.array(([&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;数组 x：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;y = np.expand_dims(x, axis=&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;数组 y：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(y)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;数组 x 和 y 的形状：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(x.shape, y.shape)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 在位置 1 插入轴&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;y = np.expand_dims(x, axis=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;在位置 1 插入轴之后的数组 y：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(y)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;x.ndim 和 y.ndim：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(x.ndim, y.ndim)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;x.shape 和 y.shape：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(x.shape, y.shape)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# numpy.squeeze 函数从给定数组的形状中删除一维的条目，函数格式如下：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;x = np.arange(&lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;数组 x：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;y = np.squeeze(x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;数组 y：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(y)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;数组 x 和 y 的形状：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(x.shape, y.shape)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# numpy.concatenate 函数用于沿指定轴连接相同形状的两个或多个数组&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.array([[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;]])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b = np.array([[&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;]])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;沿着轴0链接两个数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.concatenate((a, b)))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;沿着轴1链接两个数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.concatenate((a, b), axis=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.concatenate((a, b), axis=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;).shape)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# numpy.stack 函数用于沿新轴连接数组序列&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.array([[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;]])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;第一个数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b = np.array([[&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;]])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;第二个数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(b)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;沿轴 0 堆叠两个数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.stack((a, b), &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;沿轴 1 堆叠两个数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.stack((a, b), &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.stack((a, b), &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;).shape)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.stack((a, b), &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;).shape)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;函数&lt;/th&gt;
&lt;th&gt;数组及操作&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;split&lt;/td&gt;
&lt;td&gt;将一个数组分割为多个子数组&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;hsplit&lt;/td&gt;
&lt;td&gt;将一个数组水平分割为多个子数组（按列）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;vsplit&lt;/td&gt;
&lt;td&gt;将一个数组垂直分割为多个子数组（按行）&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;第一个数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;将数组分为三个大小相等的数组:&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.split(a, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;标明位置的分割：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.split(a, [&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;rest&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.split(a, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;)[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;16&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;第一个数组：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;默认分割（0轴）：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b = np.split(a,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(b)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;沿水平方向分割：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c = np.split(a,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(c)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;沿水平方向分割：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;d= np.hsplit(a,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(d)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;数组元素的添加与删除&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数组元素的添加与删除&#34;&gt;#&lt;/a&gt; 数组元素的添加与删除&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;函数&lt;/th&gt;
&lt;th&gt;元素及描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;resize&lt;/td&gt;
&lt;td&gt;返回指定形状的新数组&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;append&lt;/td&gt;
&lt;td&gt;将值添加到数组末尾&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;insert&lt;/td&gt;
&lt;td&gt;沿指定轴将值插入到指定下标之前&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;delete&lt;/td&gt;
&lt;td&gt;删掉某个轴的子数组，并返回删除后的新数组&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;unique&lt;/td&gt;
&lt;td&gt;查找数组内的唯一元素&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.array([[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;]])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b = np.resize(a, (&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c = np.resize(a, (&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;b:&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(b)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;c:&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(c)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.append(a, [&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.append(a, [[&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;]], axis=&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.append(a, [[&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;]], axis=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.array([[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;]])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;未传递Axis参数，在删除之前输入数组会被展开&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.insert(a, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, [&lt;span class=&#34;number&#34;&gt;11&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;12&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;未传递Axis参数，会广播值数组来匹配输入数组&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.insert(a, &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;11&lt;/span&gt;, axis=&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.insert(a, &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;11&lt;/span&gt;, axis=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.arange(&lt;span class=&#34;number&#34;&gt;12&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;未传递Axis参数，在删除之前输入数组会被展开&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.delete(a, &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;删除第二列：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.delete(a, &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, axis=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;包含从数组中删除的替代值的切片：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.array([&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.delete(a, np.s_[::&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.array([&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;第一个数组的去重值：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.unique(a))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;去重数组的索引数组：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;u, indices = np.unique(a, return_index=&lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(indices)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;去重数组的下标：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;u, indices = np.unique(a, return_inverse=&lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(indices)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(u[indices])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;返回去重元素的重复数量：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;u, indices = np.unique(a, return_counts=&lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(u)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(indices)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;位运算&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#位运算&#34;&gt;#&lt;/a&gt; 位运算&lt;/h2&gt;
&lt;p&gt;略&lt;/p&gt;
&lt;h2 id=&#34;字符串函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#字符串函数&#34;&gt;#&lt;/a&gt; 字符串函数&lt;/h2&gt;
&lt;p&gt;虽然似乎用不上（主要是看累了），但还是把表列出来&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;函数&lt;/th&gt;
&lt;th&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;add()&lt;/td&gt;
&lt;td&gt;对两个数组的逐个字符串元素进行连接&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;multiply()&lt;/td&gt;
&lt;td&gt;返回按元素多重连接后的字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;center()&lt;/td&gt;
&lt;td&gt;居中字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;capitalize()&lt;/td&gt;
&lt;td&gt;将字符串第一个字母转换为大写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;title()&lt;/td&gt;
&lt;td&gt;将字符串的每个单词的第一个字母转换为大写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;lower()&lt;/td&gt;
&lt;td&gt;数组元素转换为小写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;upper()&lt;/td&gt;
&lt;td&gt;数组元素转换为大写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;split()&lt;/td&gt;
&lt;td&gt;指定分隔符对字符串进行分割，并返回数组列表&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;splitlines()&lt;/td&gt;
&lt;td&gt;返回元素中的行列表，以换行符分割&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;strip()&lt;/td&gt;
&lt;td&gt;移除元素开头或者结尾处的特定字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;join()&lt;/td&gt;
&lt;td&gt;通过指定分隔符来连接数组中的元素&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;replace()&lt;/td&gt;
&lt;td&gt;使用新字符串替换字符串中的所有子字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;decode()&lt;/td&gt;
&lt;td&gt;数组元素依次调用 str.decode&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;encode()&lt;/td&gt;
&lt;td&gt;数组元素依次调用 str.encode&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;连接两个字符串：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.char.add([&lt;span class=&#34;string&#34;&gt;&amp;quot;hello&amp;quot;&lt;/span&gt;], [&lt;span class=&#34;string&#34;&gt;&amp;quot; xyz&amp;quot;&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;连接示例：&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.char.add([&lt;span class=&#34;string&#34;&gt;&amp;quot;hello&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;hi&amp;quot;&lt;/span&gt;], [&lt;span class=&#34;string&#34;&gt;&amp;quot; abc&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot; xyz&amp;quot;&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.char.multiply(&lt;span class=&#34;string&#34;&gt;&amp;quot;Runoob &amp;quot;&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 分隔符默认为空格&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.char.split(&lt;span class=&#34;string&#34;&gt;&amp;quot;i love you&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 分隔符指定&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(np.char.split(&lt;span class=&#34;string&#34;&gt;&amp;quot;www.baidu.com&amp;quot;&lt;/span&gt;, sep=&lt;span class=&#34;string&#34;&gt;&amp;quot;.&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# numpy.char.splitlines() 函数以换行符作为分隔符来分割字符串，并返回数组。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 换行符 \n&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.char.splitlines(&lt;span class=&#34;string&#34;&gt;&amp;#x27;i\nlike runoob?&amp;#x27;&lt;/span&gt;)) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.char.splitlines(&lt;span class=&#34;string&#34;&gt;&amp;#x27;i\rlike runoob?&amp;#x27;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 操作字符串&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.char.join(&lt;span class=&#34;string&#34;&gt;&amp;#x27;:&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;runoob&amp;#x27;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 指定多个分隔符操作数组元素&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.char.join([&lt;span class=&#34;string&#34;&gt;&amp;#x27;:&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;-&amp;#x27;&lt;/span&gt;],[&lt;span class=&#34;string&#34;&gt;&amp;#x27;runoob&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;google&amp;#x27;&lt;/span&gt;]))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.char.replace (&lt;span class=&#34;string&#34;&gt;&amp;#x27;i like runoob&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;oo&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;cc&amp;#x27;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;数学函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数学函数&#34;&gt;#&lt;/a&gt; 数学函数&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;np.sin()&lt;/li&gt;
&lt;li&gt;np.cos()&lt;/li&gt;
&lt;li&gt;np.tan()&lt;/li&gt;
&lt;li&gt;np.around () 四舍五入&lt;/li&gt;
&lt;li&gt;np.floor()&lt;/li&gt;
&lt;li&gt;np.ceil()&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;算术函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#算术函数&#34;&gt;#&lt;/a&gt; 算术函数&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;np.add()&lt;/li&gt;
&lt;li&gt;np.subtract()&lt;/li&gt;
&lt;li&gt;np.multiply()&lt;/li&gt;
&lt;li&gt;np.divide()&lt;/li&gt;
&lt;li&gt;np.reciprocal () 求倒数&lt;/li&gt;
&lt;li&gt;np.power () 幂函数&lt;/li&gt;
&lt;li&gt;np.mod () 取模&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;统计函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#统计函数&#34;&gt;#&lt;/a&gt; 统计函数&lt;/h2&gt;
&lt;p&gt;numpy.amin () 用于计算数组中的元素沿指定轴的最小值。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;numpy.amin(a, axis=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, out=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, keepdims=&amp;lt;no value&amp;gt;, initial=&amp;lt;no value&amp;gt;, where=&amp;lt;no value&amp;gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;numpy.amax () 用于计算数组中的元素沿指定轴的最大值。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;numpy.amax(a, axis=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, out=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, keepdims=&amp;lt;no value&amp;gt;, initial=&amp;lt;no value&amp;gt;, where=&amp;lt;no value&amp;gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;参数说明：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;a: 输入的数组，可以是一个 NumPy 数组或类似数组的对象。&lt;/li&gt;
&lt;li&gt;axis: 可选参数，用于指定在哪个轴上计算最小值。如果不提供此参数，则返回整个数组的最小值。可以是一个整数表示轴的索引，也可以是一个元组表示多个轴。&lt;/li&gt;
&lt;li&gt;out: 可选参数，用于指定结果的存储位置。&lt;/li&gt;
&lt;li&gt;keepdims: 可选参数，如果为 True，将保持结果数组的维度数目与输入数组相同。如果为 False（默认值），则会去除计算后维度为 1 的轴。&lt;/li&gt;
&lt;li&gt;initial: 可选参数，用于指定一个初始值，然后在数组的元素上计算最小值。&lt;/li&gt;
&lt;li&gt;where: 可选参数，一个布尔数组，用于指定仅考虑满足条件的元素。&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.array([[&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;],[&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;],[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;]])  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;我们的数组是：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;调用 amin() 函数：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.amin(a,&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;再次调用 amin() 函数：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.amin(a,&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;调用 amax() 函数：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.amax(a))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;再次调用 amax() 函数：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.amax(a, axis =  &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;numpy.ptp () 函数计算数组中元素最大值与最小值的差（最大值 - 最小值）。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;numpy.ptp(a, axis=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, out=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, keepdims=&amp;lt;no value&amp;gt;, initial=&amp;lt;no value&amp;gt;, where=&amp;lt;no value&amp;gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;numpy.percentile()&lt;br&gt;
 百分位数是统计中使用的度量，表示小于这个值的观察值的百分比。 函数 numpy.percentile () 接受以下参数。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;numpy.percentile(a, q, axis)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.array([[&lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;], [&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]])&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;我们的数组是：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;调用 percentile() 函数：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 50% 的分位数，就是 a 里排序之后的中位数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.percentile(a, &lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;)) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# axis 为 0，在纵列上求&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.percentile(a, &lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;, axis=&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# axis 为 1，在横行上求&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.percentile(a, &lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;, axis=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 保持维度不变&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.percentile(a, &lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;, axis=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;, keepdims=&lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;numpy.median () 函数用于计算数组 a 中元素的中位数（中值）&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;numpy.median(a, axis=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, out=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, overwrite_input=&lt;span class=&#34;literal&#34;&gt;False&lt;/span&gt;, keepdims=&amp;lt;no value&amp;gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;numpy.mean () 函数返回数组中元素的算术平均值，如果提供了轴，则沿其计算。&lt;/p&gt;
&lt;p&gt;算术平均值是沿轴的元素的总和除以元素的数量。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;numpy.mean(a, axis=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, dtype=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, out=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, keepdims=&amp;lt;no value&amp;gt;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;numpy.average () 函数根据在另一个数组中给出的各自的权重计算数组中元素的加权平均值。&lt;/p&gt;
&lt;p&gt;该函数可以接受一个轴参数。 如果没有指定轴，则数组会被展开。&lt;/p&gt;
&lt;p&gt;加权平均值即将各数值乘以相应的权数，然后加总求和得到总体值，再除以总的单位数。&lt;/p&gt;
&lt;p&gt;考虑数组 [1,2,3,4] 和相应的权重 [4,3,2,1]，通过将相应元素的乘积相加，并将和除以权重的和，来计算加权平均值。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;numpy.average(a, axis=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, weights=&lt;span class=&#34;literal&#34;&gt;None&lt;/span&gt;, returned=&lt;span class=&#34;literal&#34;&gt;False&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a = np.array([&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;])  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;我们的数组是：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (a)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;调用 average() 函数：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.average(a))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 不指定权重时相当于 mean 函数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;wts = np.array([&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;])  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;再次调用 average() 函数：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.average(a,weights = wts))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;\n&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 如果 returned 参数设为 true，则返回权重的和  &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;权重的和：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.average([&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;,  &lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;],weights =  [&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;], returned =  &lt;span class=&#34;literal&#34;&gt;True&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;标准差：np.std ()&lt;br&gt;
 方差：np.var ()&lt;/p&gt;
&lt;h2 id=&#34;排序-条件筛选函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#排序-条件筛选函数&#34;&gt;#&lt;/a&gt; 排序、条件筛选函数&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;种类&lt;/th&gt;
&lt;th&gt;速度&lt;/th&gt;
&lt;th&gt;最坏情况&lt;/th&gt;
&lt;th&gt;工作空间&lt;/th&gt;
&lt;th&gt;稳定性&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&#39;quicksort&#39;（快速排序）&lt;/td&gt;
&lt;td&gt;1&lt;/td&gt;
&lt;td&gt;O(n^2)&lt;/td&gt;
&lt;td&gt;0&lt;/td&gt;
&lt;td&gt;否&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&#39;mergesort&#39;（归并排序）&lt;/td&gt;
&lt;td&gt;2&lt;/td&gt;
&lt;td&gt;O(n*log(n))&lt;/td&gt;
&lt;td&gt;~n/2&lt;/td&gt;
&lt;td&gt;是&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&#39;heapsort&#39;（堆排序）&lt;/td&gt;
&lt;td&gt;3&lt;/td&gt;
&lt;td&gt;O(n*log(n))&lt;/td&gt;
&lt;td&gt;0&lt;/td&gt;
&lt;td&gt;否&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;numpy.sort(a, axis, kind, order)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;numpy.argsort () 函数返回的是数组值从小到大的索引值。&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;函数&lt;/th&gt;
&lt;th&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;msort(a)&lt;/td&gt;
&lt;td&gt;数组按第一个轴排序，返回排序后的数组副本。np.msort (a) 相等于 np.sort (a, axis=0)。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;sort_complex(a)&lt;/td&gt;
&lt;td&gt;对复数按照先实部后虚部的顺序进行排序。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;partition(a, kth[, axis, kind, order])&lt;/td&gt;
&lt;td&gt;指定一个数，对数组进行分区&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;argpartition(a, kth[, axis, kind, order])&lt;/td&gt;
&lt;td&gt;可以通过关键字 kind 指定算法沿着指定轴对数组进行分区&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;numpy.argmax () 和 numpy.argmin () 函数分别沿给定轴返回最大和最小元素的索引。&lt;/p&gt;
&lt;p&gt;numpy.nonzero () 函数返回输入数组中非零元素的索引。&lt;/p&gt;
&lt;p&gt;numpy.where () 函数返回输入数组中满足给定条件的元素的索引。&lt;/p&gt;
&lt;p&gt;numpy.extract () 函数根据某个条件从数组中抽取元素，返回满条件的元素。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;x = np.arange(&lt;span class=&#34;number&#34;&gt;9.&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;,  &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;)  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;我们的数组是：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (x)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 定义条件, 选择偶数元素&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;condition = np.mod(x,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;)  ==  &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;按元素的条件值：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (condition)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;使用条件提取元素：&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; (np.extract(condition, x))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;矩阵库npmatlib&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#矩阵库npmatlib&#34;&gt;#&lt;/a&gt; 矩阵库 np.matlib&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;matlib.empty () 函数返回一个新的矩阵&lt;/li&gt;
&lt;li&gt;numpy.matlib.zeros () 函数创建一个以 0 填充的矩阵。&lt;/li&gt;
&lt;li&gt;numpy.matlib.ones () 函数创建一个以 1 填充的矩阵。&lt;/li&gt;
&lt;li&gt;numpy.matlib.eye () 函数返回一个矩阵，对角线元素为 1，其他位置为零。&lt;/li&gt;
&lt;li&gt;numpy.matlib.identity () 函数返回给定大小的单位矩阵。&lt;/li&gt;
&lt;li&gt;numpy.matlib.rand () 函数创建一个给定大小的矩阵，数据是随机填充的。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;线性代数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#线性代数&#34;&gt;#&lt;/a&gt; 线性代数&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;函数&lt;/th&gt;
&lt;th&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;dot&lt;/td&gt;
&lt;td&gt;两个数组的点积，即元素对应相乘。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;vdot&lt;/td&gt;
&lt;td&gt;两个向量的点积&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;inner&lt;/td&gt;
&lt;td&gt;两个数组的内积&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;matmul&lt;/td&gt;
&lt;td&gt;两个数组的矩阵积&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;determinant&lt;/td&gt;
&lt;td&gt;数组的行列式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;solve&lt;/td&gt;
&lt;td&gt;求解线性矩阵方程&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;inv&lt;/td&gt;
&lt;td&gt;计算矩阵的乘法逆矩阵&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;io&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#io&#34;&gt;#&lt;/a&gt; IO&lt;/h2&gt;
&lt;p&gt;savetxt () 函数是以简单的文本文件格式存储数据，对应的使用 loadtxt () 函数来获取数据。&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;np.loadtxt(FILENAME, dtype=&lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;, delimiter=&lt;span class=&#34;string&#34;&gt;&amp;#x27; &amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;np.savetxt(FILENAME, a, fmt=&lt;span class=&#34;string&#34;&gt;&amp;quot;%d&amp;quot;&lt;/span&gt;, delimiter=&lt;span class=&#34;string&#34;&gt;&amp;quot;,&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a=np.arange(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;0.5&lt;/span&gt;).reshape(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,-&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;np.savetxt(&lt;span class=&#34;string&#34;&gt;&amp;quot;out.txt&amp;quot;&lt;/span&gt;,a,fmt=&lt;span class=&#34;string&#34;&gt;&amp;quot;%d&amp;quot;&lt;/span&gt;,delimiter=&lt;span class=&#34;string&#34;&gt;&amp;quot;,&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;# 改为保存为整数，以逗号分隔&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;b = np.loadtxt(&lt;span class=&#34;string&#34;&gt;&amp;quot;out.txt&amp;quot;&lt;/span&gt;,delimiter=&lt;span class=&#34;string&#34;&gt;&amp;quot;,&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;# load 时也要指定为逗号分隔&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(b)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;matlibplot&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#matlibplot&#34;&gt;#&lt;/a&gt; matlibPlot&lt;/h2&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; matplotlib &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; pyplot &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; plt &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;x = np.arange(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;11&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;y =  &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;  * x +  &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.title(&lt;span class=&#34;string&#34;&gt;&amp;quot;Matplotlib demo&amp;quot;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.xlabel(&lt;span class=&#34;string&#34;&gt;&amp;quot;x axis caption&amp;quot;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.ylabel(&lt;span class=&#34;string&#34;&gt;&amp;quot;y axis caption&amp;quot;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.plot(x,y) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.show()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; numpy &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; np &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; matplotlib.pyplot &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; plt &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 计算正弦和余弦曲线上的点的 x 和 y 坐标 &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;x = np.arange(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;,  &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;  * np.pi,  &lt;span class=&#34;number&#34;&gt;0.1&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;y_sin = np.sin(x) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;y_cos = np.cos(x)  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 建立 subplot 网格，高为 2，宽为 1  &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 激活第一个 subplot&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.subplot(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,  &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,  &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 绘制第一个图像 &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.plot(x, y_sin) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.title(&lt;span class=&#34;string&#34;&gt;&amp;#x27;Sine&amp;#x27;&lt;/span&gt;)  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 将第二个 subplot 激活，并绘制第二个图像&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.subplot(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,  &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,  &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.plot(x, y_cos) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.title(&lt;span class=&#34;string&#34;&gt;&amp;#x27;Cosine&amp;#x27;&lt;/span&gt;)  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 展示图像&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.show()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# pyplot 子模块提供 bar() 函数来生成条形图。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; matplotlib &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; pyplot &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; plt &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;x =  [&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;] &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;y =  [&lt;span class=&#34;number&#34;&gt;12&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;16&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;] &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;x2 =  [&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;11&lt;/span&gt;] &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;y2 =  [&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;15&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;] &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.bar(x, y, align =  &lt;span class=&#34;string&#34;&gt;&amp;#x27;center&amp;#x27;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.bar(x2, y2, color =  &lt;span class=&#34;string&#34;&gt;&amp;#x27;g&amp;#x27;&lt;/span&gt;, align =  &lt;span class=&#34;string&#34;&gt;&amp;#x27;center&amp;#x27;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.title(&lt;span class=&#34;string&#34;&gt;&amp;#x27;Bar graph&amp;#x27;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.ylabel(&lt;span class=&#34;string&#34;&gt;&amp;#x27;Y axis&amp;#x27;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.xlabel(&lt;span class=&#34;string&#34;&gt;&amp;#x27;X axis&amp;#x27;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;plt.show()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;不仅是第一次来爵士酒吧，也是第一次来酒吧，有吧台，有调酒师，舞台上面摆着乐器，总共有 60、70 个观众的席位，意外的是座位基本都是满的，可能是周日晚上大家都来最后的放纵了吧。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/MeetingJazz2025-04-26-1.jpg&#34; alt&gt;&lt;br&gt;
先说酒，点的 “古典”（old fashion），外表上看，在酒吧内昏暗的灯光下散发着橘子皮的光芒，里面融着一块冰块，冰块上点缀着柠檬皮。第一口下去没怎么注意，喝的稍许偏多，且没怎么过舌头的味蕾。酒水在口腔中荡漾时不知是不是冰的原因，显得十分润滑且没品出酒味，直到酒水过到喉咙里味道才绽放出来。第一反应是很润滑，感觉酒水是粘稠在一起的，伴随而来的便是一阵苦涩的味道来对酒味进行中和，而这苦味也显得很合适，刚好在酸味中和的差不多时便随之消散。酒味并没有那么冲，直到酒水入肚，酒气才慢慢上到头脑，整体来说还是很不错的。等喝着差不多一半的时候，那种又冰所带来的润滑的感觉逐渐消散了，苦味占据了高地，喝下去虽然没有那种涩的感觉，而且苦味消散的也很快，但确实是缺少了最开始粘稠的感觉。喝到最后的时候，得益于冰的融化，甜味重新占领了味觉，不知是不是柠檬的原因，口感十分的清爽。&lt;br&gt;
&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/MeetingJazz2025-04-26-2.jpg&#34; alt&gt;&lt;br&gt;
来的时候我并不知道演出的内容是什么，表演者是两位男士，也没有什么预热，直接便开始了演奏。一位负责弹奏电子琴，另一位则负责 voicing 的部分。第一首曲子是十分经典的《Autumn Leaves》。说实话，一开始我并没有听出来，最开始的旋律比起《Autumn Leaves》更像是《贝加尔湖畔》，正当我困惑的时候，也不是因为旋律很明显，反倒是因为和弦走向比较熟悉，很快便意识到了他们在弹什么。他们也没有背稿，很明显就是全程的即兴。虽然我听不出来他们弹的是什么音阶，但是很多地方都很有个人的色彩，例如钢琴师总是不舒舒服服的去解决和弦，而是留有一些余地就紧接着下面的乐句了。人声部分主要是那个人在哼哼，利用人声去模拟 Bass 或者吉他的那种弹 solo 的感觉。That&#39;s True Music。我目前的音乐鉴赏水平来说，或者说我的音乐审美来说，我是比较排斥人声的。音乐难道不就是音高、音响和音色的组合吗，为什么非要假如歌词这种其它形式的类似诗词的东西进来。在我看来，虽然歌词能够辅助人去理解音乐，但就像人透过语言去了解一个人一样，虽然门槛降低了，这难道不也是一种对事物本身的一种阉割吗？当然可能是我偏激了。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/MeetingJazz2025-04-26-3.png&#34; alt&gt;&lt;br&gt;
虽说有 60 多个观众，但大部分人目测是没怎么接触过爵士的，更多是来作为一个清净的，看起来还很高雅的地方来供人们社交。也有能看出来是冲着爵士来的，最前面有一位男大学生，一个人来的，坐的笔直；坐在我们右边的应该是一对俄罗斯夫妇，当演奏出现那种很有意思的段子的时候他们发自内心的笑容也让人感到音乐的魅力。还有一对情侣一个外国男生和一个中国女生，看起来那个外国男生比较拘束，但不时和女生在聊演奏的内容。坐的靠远的地方是 5、6 位男大学生，有一位卖弄地向他的朋友说着曲子。&lt;/p&gt;
&lt;p&gt;我只听了四首歌，从 8：30 开始的演奏听到 10：40 实在熬不住便先行离开了。中间除了开始的《Autumn Leaves》，中间的两首歌都没有听出来是什么标准曲，这里面其中一首是 voicing 报幕时坦言自己很喜欢的曲目，他演奏起来也是十分的惬意，和钢琴手相互呼应，你哼一段乐句，我对上一段 solo，炫技成分很高但大家都玩的开心，观众也看得开心。最后一首是《All of Me》，由于我也没听太多的爵士曲，险些没有听出来，虽然都是标准曲，也都是即兴的演奏，但也挺不错的了。&lt;/p&gt;
&lt;p&gt;以后应该还会来，下次挑一场有吉他的学学技术。综合评价来说能给到 7 分。&lt;/p&gt;

 &lt;p&gt;感觉这个东西配起来十分的恶心，我打算按照&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9sYXp5dmltLWFtYml0aW91cy1kZXZzLnBoaWxsaXBzLmNvZGVzL2NvdXJzZS9jaGFwdGVyLTEvI19pbnN0YWxsX2xhenl2aW0=&#34;&gt;官方&lt;/span&gt;的操作来做一遍。&lt;/p&gt;
&lt;p&gt;一方面自己大四闲的要死，找点事做总是好的，另一方面网络上确实关于 lazyvim 的教程要么收费，要么浅尝辄止没有深入或系统的指导，所以我自己开个坑，希望能系统而全面的介绍在 windows 系统下的对于 LazyVim 和 NeoVim 的使用和书写方法。&lt;/p&gt;
&lt;p&gt;当然我也没学过 lua，若有不够严谨的地方多多包涵。&lt;/p&gt;
&lt;h1 id=&#34;windows-terminal&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#windows-terminal&#34;&gt;#&lt;/a&gt; Windows Terminal&lt;/h1&gt;
&lt;p&gt;首先我们参考官方推荐的在 Windows 使用的终端。&lt;/p&gt;
&lt;p&gt;推荐安装 Windows Terminal，然后再打开系统自带的 PowerShell，这里可以直接在&lt;em&gt;开始菜单&lt;/em&gt;搜索 Power Shell，效果如下：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/neovim1.png&#34; alt=&#34;neovim1&#34;&gt;&lt;/p&gt;
&lt;p&gt;然后可以去&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cubmVyZGZvbnRzLmNvbS9mb250LWRvd25sb2Fkcw==&#34;&gt; Nerd Font&lt;/span&gt; 中下载自己感兴趣的字体，这里我使用的是&lt;em&gt; JetBrainsMono Nerd Font&lt;/em&gt;, 解压安装包，双击其中一个 ttf 文件，点击安装。然后重新打开 PowerShell，点击上方的倒三角，点击设置，即可设置字体。&lt;br&gt;
&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/neovim2.png&#34; alt&gt;&lt;/p&gt;
&lt;h1 id=&#34;neovim安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#neovim安装&#34;&gt;#&lt;/a&gt; NeoVim 安装&lt;/h1&gt;
&lt;p&gt;去&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9uZW92aW0uaW8v&#34;&gt;官网&lt;/span&gt;安装。&lt;br&gt;
我的 Windows 杂七杂八安装了太多东西，例如 WSL，所以有的问题可能我没遇到但是作者提及了。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;在 Windows 上，我建议使用 Windows Linux 子系统 (WSL) 并在其中进行所有开发。WSL 远远超出了本书的讨论范围，但微软和许多在线教程都对它进行了详尽的说明。选择兼容 WSL 的 Linux 发行版、进行设置并在所选终端中运行后，即可按照以下 Linux 说明安装 Neovim。&lt;/p&gt;
&lt;p&gt;如果您有理由（或偏好）在原生 Windows 上进行开发，最简单的方法是从 GitHub 上的&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL25lb3ZpbS9uZW92aW0v&#34;&gt; neovim/neovim&lt;/span&gt; 存储库的发布部分获取 MSI 安装程序。&lt;/p&gt;
&lt;p&gt;如果您已经使用 Winget、Chocolatey 或 Scoop 来管理 Windows 机器上的包，那么它们每个中都有一个 Neovim 包。&lt;/p&gt;
&lt;p&gt;请注意，如果您使用的 Windows 系统没有 WSL，则还需要安装 C 编译器才能获得 treesitter 支持（这基本上意味着更好的语法高亮和代码导航支持）。遗憾的是，这并非易事。相关文档已记录在 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL252aW0tdHJlZXNpdHRlci9udmltLXRyZWVzaXR0ZXI=&#34;&gt;nvim-treesitter/nvim-treesitter&lt;/span&gt; GitHub 仓库中，因此我在此不再赘述。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;这里可以先跳过这个所谓的 C 语言编译的板块，后面遇到了再做处理。&lt;/p&gt;
&lt;h1 id=&#34;安装lazyvim&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装lazyvim&#34;&gt;#&lt;/a&gt; 安装 LazyVim&lt;/h1&gt;
&lt;p&gt;一般我们涉及到的文件夹是在  &lt;code&gt;C:\Users\你的名字\AppData\Local&lt;/code&gt;  下的 nvim (自己创建的) 和 nvim-data 文件夹，这里先对它们进行清空。&lt;br&gt;
然后我们便可以克隆 LazyVim 的启动模板，然后删除.git 文件夹（要是 powershell 内删不了直接手动定位过去删除一样的）&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git &lt;span class=&#34;built_in&#34;&gt;clone&lt;/span&gt; https://github.com/LazyVim/starter &lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:LOCALAPPDATA\nvim&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Remove-Item &lt;span class=&#34;variable&#34;&gt;$env&lt;/span&gt;:LOCALAPPDATA\nvim\.git -Recurse -Force&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;在 PowerShell 中输入 nvim 回车，等待它下载。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/neovim3.png&#34; alt&gt;&lt;br&gt;
然后就进入到 LazyVim 界面了&lt;br&gt;
&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/neovim4.png&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;按 l 键可以进入插件管理界面，Lazy.nvim 拥有众多实用功能，其中最引人注目的是仅在需要时加载插件（因此得名 “Lazy”），这样你的编辑器启动速度就能飞快。它还拥有一个美观的用户界面，方便管理插件的安装和更新。如下图所示&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/neovim5.png&#34; alt&gt;&lt;/p&gt;
&lt;h1 id=&#34;插件的安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#插件的安装&#34;&gt;#&lt;/a&gt; 插件的安装&lt;/h1&gt;
&lt;h2 id=&#34;markdown-preview&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#markdown-preview&#34;&gt;#&lt;/a&gt; markdown-preview&lt;/h2&gt;
&lt;p&gt;我自己有写日志的习惯，所以我首先安装了对于 Markdown 的相关配置&lt;br&gt;
我在&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kb3RmeWxlLmNvbS9uZW92aW0vcGx1Z2lucy90cmVuZGluZw==&#34;&gt;这个网站&lt;/span&gt;搜索 markdown，并选择了 markdown-preview 插件，然后我们可以看到它提供的相关代码：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/neovim6.png&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;接下来我们可以在./lua/plugins/ 下创建 markdown-preview.lua 文件，并在文件中写入 return 加上大括号里面的内容即可。同时我们也可以进入它提供的 github 的&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL2lhbWNjby9tYXJrZG93bi1wcmV2aWV3Lm52aW0=&#34;&gt;官网&lt;/span&gt;。在 MarkdownPreview Config 中可以看到它默认的配置和相关的键位。这里我认为 MarkdownPreview 指令太长了，于是我改了一下键位，并且设置了不自动预览和当离开 markdown buffer 时 Zion 给关闭浏览器预览。&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;&amp;quot;iamcco/markdown-preview.nvim&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  build = &lt;span class=&#34;string&#34;&gt;&amp;quot;cd app &amp;amp;&amp;amp; npm install&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  ft = &amp;#123; &lt;span class=&#34;string&#34;&gt;&amp;quot;markdown&amp;quot;&lt;/span&gt; &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  cmd = &amp;#123; &lt;span class=&#34;string&#34;&gt;&amp;quot;MarkdownPreview&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;MarkdownPreviewStop&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;MarkdownPreviewToggle&amp;quot;&lt;/span&gt; &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  init = &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_auto_start = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_auto_close = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_refresh_slow = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_open_to_the_world = &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_browser = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_theme = &lt;span class=&#34;string&#34;&gt;&amp;quot;dark&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;end&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  keys = &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;leader&amp;gt;mp&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;cmd&amp;gt;MarkdownPreviewToggle&amp;lt;cr&amp;gt;&amp;quot;&lt;/span&gt;, desc = &lt;span class=&#34;string&#34;&gt;&amp;quot;Toggle Markdown Preview&amp;quot;&lt;/span&gt; &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;中文标红的解决&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#中文标红的解决&#34;&gt;#&lt;/a&gt; 中文标红的解决&lt;/h2&gt;
&lt;p&gt;在写 markdown 文档时我发现中文的字符往往由于拼写检查标红了。我又添加了拼写检查英文、中日韩都合法的操作，完整的代码如下&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;&amp;quot;iamcco/markdown-preview.nvim&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  build = &lt;span class=&#34;string&#34;&gt;&amp;quot;cd app &amp;amp;&amp;amp; npm install&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  ft = &amp;#123; &lt;span class=&#34;string&#34;&gt;&amp;quot;markdown&amp;quot;&lt;/span&gt; &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  cmd = &amp;#123; &lt;span class=&#34;string&#34;&gt;&amp;quot;MarkdownPreview&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;MarkdownPreviewStop&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;MarkdownPreviewToggle&amp;quot;&lt;/span&gt; &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  init = &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_auto_start = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_auto_close = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_refresh_slow =  &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_open_to_the_world = &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_browser = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.g.mkdp_theme = &lt;span class=&#34;string&#34;&gt;&amp;quot;dark&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    vim.api.nvim_create_autocmd(&lt;span class=&#34;string&#34;&gt;&amp;quot;FileType&amp;quot;&lt;/span&gt;, &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      pattern = &lt;span class=&#34;string&#34;&gt;&amp;quot;markdown&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      callback = &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        vim.opt.spell = &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        vim.opt.spelllang = &amp;#123; &lt;span class=&#34;string&#34;&gt;&amp;quot;en&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;cjk&amp;quot;&lt;/span&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;end&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;end&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  keys = &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;leader&amp;gt;mp&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;cmd&amp;gt;\begin&amp;#123;figure&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;    \centering&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;    \includegraphics[width=1\linewidth]&amp;#123;bioPic.png&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;    \caption&amp;#123;Human Liver和Stereo-seq的空间域划分&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;    \label&amp;#123;fig:enter-label&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;\end&amp;#123;figure&amp;#125;MarkdownPreviewToggle&amp;lt;cr&amp;gt;&amp;quot;&lt;/span&gt;, desc = &lt;span class=&#34;string&#34;&gt;&amp;quot;Toggle Markdown Preview&amp;quot;&lt;/span&gt; &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;\begin&amp;#123;figure&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    \centering&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    \includegraphics[width=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;\linewidth]&amp;#123;bioPic.png&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    \caption&amp;#123;Human Liver和Stereo-seq的空间域划分&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    \label&amp;#123;fig:enter-label&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;\&lt;span class=&#34;keyword&#34;&gt;end&lt;/span&gt;&amp;#123;figure&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;配置ai&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#配置ai&#34;&gt;#&lt;/a&gt; 配置 AI&lt;/h2&gt;
&lt;p&gt;在 PowerShell 中输入 nvim 回车，输入 x 进入 Lazy Extras，然后找到 copilot，定位到对应的位置输入 x 启用。重新进入 nvim。输入 &lt;code&gt;:Copilot auth&lt;/code&gt;  启用账户并按照提示操作，具体是找到对应的弹窗，进入它提示的网址，输入弹窗给出的验证码进入 github 进行验证。验证完毕后即可使用。具体操作我简单试了一下 Copilot-bot，应该还具有代码补全的操作：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/neovim7.png&#34; alt&gt;&lt;/p&gt;
&lt;h1 id=&#34;个性化的一些设置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#个性化的一些设置&#34;&gt;#&lt;/a&gt; 个性化的一些设置&lt;/h1&gt;
&lt;h2 id=&#34;打开terminal时自动定位到当前文件夹&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#打开terminal时自动定位到当前文件夹&#34;&gt;#&lt;/a&gt; 打开 terminal 时自动定位到当前文件夹&lt;/h2&gt;
&lt;p&gt;考虑到跑 python 代码时，重新 ding&lt;/p&gt;

 &lt;p&gt;角铜真实&lt;br&gt;
&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/jiaotongzhenshi1.jpg&#34; alt&gt;&lt;br&gt;
此前并没有听过这个乐队的歌，正好在平台上看见了他们的演出，一看 tag 是氛围 / 民谣 / 独立便觉得可以试试。然而在 b 站上试听了几首实在觉得风格过于实验性有点接受不来。最终看了现场的切片和实在天天跑代码受不了想换换脑子便买了票来到西安音乐厅。&lt;/p&gt;
&lt;p&gt;起初我认为这种小众且风格具有门槛的乐队哪会有人掏 200 块钱来看。于是便卡着点，一看门口长长的队伍等着买周边。我仍然觉得这些人不过是凑热闹，于是自欺欺人的我很遗憾的没能买到周边。&lt;/p&gt;
&lt;p&gt;好在座位很靠前，在第二排，坐在位置上能清楚的看到例如贝斯、吉他、提琴、鼓等等乐器。有些东西却看不太懂，电子琴和类似合成器尚能理解，一个小水缸，葫芦丝，鼓上挂着的铃铛样的东西又是什么。这些东西垒在一起更让人疑惑，有种现代与古典交织的不和谐感。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/jiaotongzhenshi2.jpg&#34; alt&gt;&lt;br&gt;
乐队成员上场了，两个带着像是从哪个宗教色彩浓厚的部落里偷来的面具，另外几个倒是正常打扮。角铜真实应该是那位带着面具的女生了。看网易云上的照片感觉不怎么好看，现场一看那种活力与热情的身姿让人印象深刻。很快演出便开始了。&lt;/p&gt;
&lt;p&gt;预想中的复杂和不和谐的音乐并没有出现，反倒是乐队成员的互相配合营造出了一种氛围。这下我便深刻体会到了 ambient 的魅力。我一直在想为什么 ambient 非要把氛围给突出出来，在我看来很多古典曲目仍能达到烘托出氛围的效果。然而氛围音乐，起码是这个乐队中，大量重复的乐段并不会让人感到乏味，正儿八经的把人给送入到这种氛围之中。不会乏味的理由也很简单，不时加入新的乐器，或是简单的改变某个音却不破坏整个氛围，再加上绝佳的动态，让氛围不改变的同时情绪自然的流淌。&lt;/p&gt;
&lt;p&gt;我并不太会听氛围音乐，于是我按照自己的方式进行了品鉴。首先我注意到的是乐队成员，主音即负责大部分旋律段的角铜真实和另一位吉他手年龄都不大，而提琴手、鼓手、贝斯都是起码父辈到祖父辈的人了。这里就十分有趣，三位经验丰富的乐手凭借着丰富的演奏经验和扎实的基本功让演出处在一个极高的水平，例如贝斯烘托了律动，提琴在延伸情绪的表达上，特别是鼓手绝佳的音量控制，当我看到他以超高的速度又富有力量感弹奏又稳定的停下来时不由得感到震撼。而两位年轻人则是把年轻人的活泼和创新展现了出来，无论是与现场观众的互动抑或是使用复杂多样的音乐器材，虽说稍显稚嫩，但也是整场演出的灵魂所在。&lt;/p&gt;
&lt;p&gt;在我看来，乐器音色的选择是极为苛刻的，最为直观的来说，不同的歌手的嗓音往往适合不同风格的歌曲，更别提把诸如水的流动声，纸张的晃动声，鼓棒在擦片上的摩擦声，有些音色光是在现实生活中听到便觉得不适更何况是在演奏会上。&lt;/p&gt;
&lt;p&gt;他们是怎么平衡的呢？不得不说角铜真实的天赋之高。这些本应不会出现在此的音色在他们的演奏中却塑造了一种 “原始” 的 “梦幻” 的氛围。这具体是一种怎样的氛围呢？好比你行走在野生、神秘而又被遗弃的原始部落里，无论是鸟叫还是树木断裂的声音，甚至于裂开的天空传来的呼救。一切都是被允许的，因为我的内心是渴求的，而在渴求中这份神秘又让我得到了满足。这是前三分之一的歌曲带给我的感受。&lt;/p&gt;
&lt;p&gt;渴求仍在继续，这种渴求转变成了具体的东西。中间有一首大意是 “我想要说话” 的歌我认为很出彩。由压抑中爆发，主唱开始喋喋不休的不停的表达自己，又哑然失语，返璞归真，在咿呀中不知所云，到了第三乐章，主唱开始不再一昧表达自己，转而看向周围：这是椅子、这是鼓、这是鞋子…… 从认识世界中变得成熟与温和。配上主唱的面具和她夸张的动作，十分 drama 的场景扑面而来，这里一定是借鉴了音乐剧的表现形式，不仅在音乐中释放自己的情感，更是直观的向观众展现。&lt;/p&gt;
&lt;p&gt;到了最后，角铜真实以一首 flower everywhere 结束了整场演出。这首曲子也非常有趣，听到这个名字我以为是欢快的曲子，但上来就是听都听不懂的像在砸琴键的和弦开场且这个和弦贯穿整个曲子。我不禁想，花在哪呢？可随着各种乐器的加入，虽说整个曲子的氛围虽然没有变但在各种 “规整” 的声音加入后，不和谐的声音也变得能够接受，更神奇的是由于和弦的不断规律重复，似乎隐隐之中让人产生了有它才正常的错觉。这种表达方式我还是第一次见。花在哪里呢？若是处在鲜花盛开的地方，诉说到处都是花似乎很合理。然而世界上总有不美丽的花，人也是如此。当在此种情形下你仍能觉得 flower everywhere，爱也从中体现。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/jiaotongzhenshi3.jpg&#34; alt&gt;&lt;br&gt;
有人说为什么一定要去演奏会听音乐，自己在家带个耳机不也是挺好的吗？在我开始听这场演奏会的时候，最大的感受就是 “音质高”，我能够清晰的分辨出哪里是鼓，哪里是贝斯，而不是像平时听歌一样各种声音糊在了一起。其次来说的话就是仪式感不一样，身边的人都在跟你一起听曲子，就像看电影一样，一种集体的氛围感油然而生，再加上这不单单是听曲子，场上演奏者与观众的互动，场下观众与演奏者的互动都是演出的一部分。我迄今为止听过两场演奏会，起码在我听的这两场里，有一个很好的元素就是返场。演奏者假装演奏完最后在观众的呼声中返场再演奏最后的曲目，这种类似于社交属性的行为是耳机无法取代的。但从音乐的角度说，这场演出给我最大的感受是听歌不仅仅是用耳朵去听而是用身体去感受，在我听到快结束时，我缩在靠凳里，感觉不光是耳膜在与音乐共振，更重要的是身体感觉在发热，一方面可能是现场的气氛，另一方面能利用自己的身体感受到音乐的起伏，我认为这是耳机所替代不了的。&lt;/p&gt;
&lt;p&gt;总的来说，这场演出让我感受到了氛围音乐的魅力，乐队成员的配合和音色的选择都让我印象深刻。虽然我对氛围音乐的理解还不够深入，但这场演出让我对这种风格有了更深的认识和体会。唯一有点遗憾的是可能是这种音乐风格的特点，我无法记住音乐演出过程中的旋律或者其它更能量化它的东西，只单单留下了对音乐的感受，但即便如此也是让人十分满意的一场演出了。综合的来评价的话我觉得能打个 9 分。&lt;/p&gt;

 &lt;p&gt;问了问 chatGPT 相关内容，挺有用的。&lt;/p&gt;
&lt;p&gt;Q：哲学上精神分析的 “倒错” 是一个什么概念&lt;br&gt;
 A:&lt;br&gt;
 在精神分析中，“倒错”（Perversion）是一个具有特定意义的概念，最初由弗洛伊德（Sigmund Freud）提出，并在拉康（Jacques Lacan）等后继精神分析学者的理论中进一步发展。&lt;/p&gt;
&lt;h3 id=&#34;1-弗洛伊德的倒错&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-弗洛伊德的倒错&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. 弗洛伊德的 “倒错”&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;在弗洛伊德的理论框架中，&lt;strong&gt;倒错主要指的是一种与常规性行为不同的性发展模式&lt;/strong&gt;。他认为，人类的性本能（libido）并非天生就指向 “正常” 的异性恋关系，而是经过复杂的发展过程逐渐形成的。在童年时期，个体的性欲并未集中于生殖器，而是通过不同的 **“性化” 阶段 **（口腔期、肛门期、性器期）发展出来。在这个过程中，某些欲望可能会停滞在非生殖性的目标上，比如恋物癖（fetishism）、施虐 - 受虐（sadomasochism）等。这种 “停滞” 或 “偏离” 被弗洛伊德称为 “倒错”。&lt;/p&gt;
&lt;p&gt;简单来说，&lt;strong&gt;倒错在弗洛伊德那里是一种与生殖目标不同的性取向或性实践&lt;/strong&gt;，但并不等同于 “病态”，而是人类普遍存在的潜在倾向。&lt;/p&gt;
&lt;h3 id=&#34;2-拉康对倒错的再解释&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-拉康对倒错的再解释&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. 拉康对 “倒错” 的再解释&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;拉康在精神分析的结构主义框架下重新定义了 “倒错”，他认为倒错不仅是一种性实践，而是一种&lt;strong&gt;主体结构&lt;/strong&gt;，与 “精神病” 和 “神经症” 并列。拉康的核心观点包括：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;倒错者（Pervers）与象征秩序（Symbolic Order）&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在拉康看来，神经症（Neurosis）个体通常会受到象征秩序（Symbolic Order，如社会规范、法律、父权功能等）的压抑，而精神病（Psychosis）个体则完全排斥这个秩序。&lt;/li&gt;
&lt;li&gt;但倒错者（Pervers）并不完全拒绝象征秩序，而是通过一种特殊的方式与之 “玩弄” 或 “操纵”—— 他并不直接服从规则，而是通过越界、戏弄规则来维持规则的存在。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;倒错者的幻想结构&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拉康认为倒错的本质在于，&lt;strong&gt;倒错者试图扮演 “他者的享乐工具”&lt;/strong&gt;。也就是说，倒错者不是简单地追求自己的快感，而是希望成为 **“大他者”（the Big Other，象征秩序的代表）享乐的对象 **。&lt;/li&gt;
&lt;li&gt;例如，在施虐者（sadist）的情况下，他并不是单纯地以折磨他人为目的，而是以自己成为 “法则执行者” 的身份，从中获得快感 —— 他相信自己在 “完成” 某种象征性的任务，而非仅仅满足私欲。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;倒错与父亲的名义（Nom-du-Père）&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拉康认为，倒错者在成长过程中通常没有完全认同父亲的象征功能，因此他们无法完全接受法律和道德的中介，而是采用另一种方式来建立自我的主体性。&lt;/li&gt;
&lt;li&gt;这意味着，倒错者在某种程度上挑战了主流社会的道德体系，但他们又通过扮演 “规则执行者” 的角色来维持秩序的存在。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3-哲学上的扩展倒错的社会-政治含义&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-哲学上的扩展倒错的社会-政治含义&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. 哲学上的扩展：倒错的社会 - 政治含义&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;在哲学和批判理论中，倒错的概念被进一步扩展，不仅限于精神分析的个体心理，而涉及到&lt;strong&gt;社会、政治、权力关系&lt;/strong&gt;等。例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;** 齐泽克（Slavoj Žižek）** 借助拉康的理论讨论意识形态的 “倒错结构”。他认为，现代资本主义社会本身就是一种倒错机制 —— 它并不直接压制人的欲望，而是通过提供无限的消费可能性，让人陷入一种 “无止境的享乐”（Jouissance）循环。&lt;/li&gt;
&lt;li&gt;** 福柯（Michel Foucault）** 在《性史》中分析了权力如何通过性规范来定义正常与异常，这实际上与倒错概念有关，因为 “倒错” 往往是在社会话语建构下形成的，而非自然存在的 “病态”。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;总结&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结&#34;&gt;#&lt;/a&gt; &lt;strong&gt;总结&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;倒错在精神分析中经历了从&lt;strong&gt;弗洛伊德的性发展理论&lt;/strong&gt;到&lt;strong&gt;拉康的主体结构理论&lt;/strong&gt;的演变。它不仅仅指涉性偏好，而是一种更深层的心理机制 —— 倒错者试图操纵或戏弄象征秩序，而非单纯地拒绝它。在哲学层面，倒错的概念被拓展到社会、政治、意识形态等领域，揭示了现代社会如何通过某种 “扭曲的享乐结构” 维持自身运作。&lt;/p&gt;
&lt;p&gt;你是想从精神分析的角度理解这个概念，还是希望讨论它在哲学、社会批判方面的应用？&lt;/p&gt;
&lt;p&gt;Q：那倒错而产生的致死欲是怎么推断出来的&lt;br&gt;
 A:&lt;strong&gt; 倒错与 “致死欲”（Death Drive）的关系&lt;/strong&gt;主要源于弗洛伊德晚期的理论，特别是《超越快乐原则》（Beyond the Pleasure Principle, 1920）。拉康继承并发展了这一概念，并在主体结构的框架下重新解释了倒错如何与致死欲相关。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;1-弗洛伊德的致死欲death-drive&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-弗洛伊德的致死欲death-drive&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. 弗洛伊德的致死欲（Death Drive）&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;在最初的精神分析理论中，弗洛伊德认为&lt;strong&gt;人的行为由 “快乐原则”（Pleasure Principle）驱动&lt;/strong&gt;，即个体会追求快乐并避免痛苦。然而，在研究战争创伤患者的反复梦境时，他发现某些体验似乎无法用 “寻求快乐” 来解释 ——&lt;strong&gt; 个体会不断重复痛苦经历，而不是回避它&lt;/strong&gt;。这促使弗洛伊德提出了 “强迫性重复”（Repetition Compulsion）和 “致死欲”（Todestrieb）的概念。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;致死欲 vs. 生本能&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;生本能（Eros）&lt;/strong&gt;：推动个体寻求生存、繁衍、联结（例如性欲、创造力）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;致死欲（Thanatos）&lt;/strong&gt;：一种趋向于静止、毁灭、回归无机状态的冲动，它驱使个体不断重复创伤、甚至自毁。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;强迫性重复（Repetition Compulsion）&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;致死欲的表现之一是 “强迫性重复”，即个体不断重演痛苦或破坏性的模式，而非遵循 “快乐原则” 寻求幸福。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;2-倒错如何与致死欲相关&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-倒错如何与致死欲相关&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. 倒错如何与致死欲相关？&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;在精神分析中，&lt;strong&gt;倒错不仅是性行为的 “偏离”，而是一种特殊的主体结构&lt;/strong&gt;。拉康认为，倒错者并非单纯追求快感，而是主动扮演一个 “他者享乐的工具”，甚至在这个过程中涉及某种自我毁灭的倾向。&lt;/p&gt;
&lt;h3 id=&#34;1-倒错者的欲望结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-倒错者的欲望结构&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(1) 倒错者的欲望结构&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;弗洛伊德认为，倒错的本质是一种&lt;strong&gt;未完成的俄狄浦斯过程&lt;/strong&gt;，即个体未能完全接受 “父的律法”。&lt;/li&gt;
&lt;li&gt;拉康进一步指出，倒错者的核心问题在于，他们不是简单地抗拒社会规范，而是&lt;strong&gt;主动去确认并实施它们，以便支撑象征秩序&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;例如，施虐者（Sadist）并非简单地享受折磨别人，而是试图成为 “象征秩序” 的执行者，让受虐者承受某种 “客观必然” 的痛苦。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2-倒错与享乐jouissance&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-倒错与享乐jouissance&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(2) 倒错与 “享乐”（Jouissance）&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;拉康引入 “&lt;strong&gt;享乐（Jouissance）&lt;/strong&gt;” 概念来描述超越快乐原则的痛苦快感：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;普通的 “快乐” 受快乐原则约束，而 “享乐” 是&lt;strong&gt;一种超越快乐、甚至包含痛苦的快感&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;倒错者的行为往往涉及 “过度享乐”（excessive Jouissance）—— 即，他们不仅追求快感，还试图跨越 “象征秩序” 的边界，以体验更极端的满足。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;在这个过程中，&lt;strong&gt;致死欲被激活&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;倒错者的享乐通常带有破坏性&lt;/strong&gt;，无论是对自己还是对他人。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;倒错行为的重复性&lt;/strong&gt;符合弗洛伊德的 “强迫性重复” 理论 —— 即个体不断重演相同的模式，而不是逃离痛苦。&lt;/li&gt;
&lt;li&gt;施虐 - 受虐关系（Sadomasochism）是倒错结构的典型例子：
&lt;ul&gt;
&lt;li&gt;施虐者在折磨他人时，实际上是为了成为 “象征秩序” 的执行者，他的快感来源于&lt;strong&gt;支撑某种 “律法”&lt;/strong&gt;，而非单纯的暴力。&lt;/li&gt;
&lt;li&gt;受虐者通过被折磨获得快感，这意味着他们不仅接受痛苦，还将痛苦本身视为一种&lt;strong&gt;命运般的享乐&lt;/strong&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3-倒错与死亡的隐喻&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-倒错与死亡的隐喻&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(3) 倒错与死亡的隐喻&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;致死欲的最终目标是&lt;strong&gt;回归静止、无生命的状态&lt;/strong&gt;。在倒错中，我们可以看到类似的机制：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;倒错者的行为具有&lt;strong&gt;强迫性重复&lt;/strong&gt;的特征，他们不断地回到某种极端情境，而不是寻求新的可能性。&lt;/li&gt;
&lt;li&gt;倒错者的 “享乐” 往往指向&lt;strong&gt;极端的痛苦、屈辱甚至死亡&lt;/strong&gt;，这在极端的性倒错、虐待狂或自残行为中尤为明显。&lt;/li&gt;
&lt;li&gt;这种行为模式暗示着&lt;strong&gt;个体在享乐的极限中试图接近某种 “终极静止”&lt;/strong&gt;，也就是死亡。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;3-结论倒错如何推导出致死欲&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-结论倒错如何推导出致死欲&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. 结论：倒错如何推导出致死欲？&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;倒错之所以会导致致死欲，可以归纳如下：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;倒错行为的 “强迫性重复”&lt;/strong&gt;—— 不断重演相同的场景，与弗洛伊德的 “致死欲” 相呼应。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;倒错者的享乐结构超越快乐原则&lt;/strong&gt; —— 他们追求的不仅是快感，而是一种极限状态的享乐（Jouissance）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;倒错的自毁倾向&lt;/strong&gt; —— 在极端情况下，倒错可能演化为自残、极端施虐，甚至死亡的渴望。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;象征秩序的作用&lt;/strong&gt; —— 倒错者试图支撑秩序，但方式是通过 “玩弄规则” 或 “极端执行规则”，最终导致结构的瓦解。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;在拉康的理论框架下，&lt;strong&gt;倒错的本质是一种主体结构，而非单纯的性偏好&lt;/strong&gt;。倒错者的享乐模式实际上是 “致死欲” 的一种表现，因为它表现出超越生命本能（Eros）的毁灭性冲动。&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;你是想更深入探讨倒错的具体案例，还是希望理解致死欲如何影响个体心理结构？&lt;/p&gt;
&lt;p&gt;Q：那有可能一个人在做某件事情时既是施虐者也是受虐者吗，存在这样的辩证关系吗&lt;br&gt;
 A: 是的，一个人在做某件事情时&lt;strong&gt;既是施虐者（Sadist）也是受虐者（Masochist）&lt;/strong&gt;，这种辩证关系不仅存在，而且在精神分析、哲学、社会批判等多个领域都有体现。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;1-施虐与受虐的辩证关系&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-施虐与受虐的辩证关系&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. 施虐与受虐的辩证关系&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;施虐（Sadism）与受虐（Masochism）通常被看作相对立的两极，但精神分析认为，它们实际上可能&lt;strong&gt;共存并相互转化&lt;/strong&gt;，甚至在同一主体内部发生。这种关系可以从以下几个方面分析：&lt;/p&gt;
&lt;h3 id=&#34;1-施虐即受虐倒错结构的循环&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-施虐即受虐倒错结构的循环&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(1) 施虐即受虐：倒错结构的循环&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;在极端的施虐 - 受虐（Sado-Masochism）关系中，个体的快感不仅仅来自于对他人的控制或被控制，而是来自于&lt;strong&gt;循环性的支配与服从&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;施虐者并不仅仅是折磨他人，而是&lt;strong&gt;依赖于受虐者的存在&lt;/strong&gt;来完成自己的角色。&lt;/li&gt;
&lt;li&gt;受虐者的快感来源于痛苦，但&lt;strong&gt;这种痛苦往往是由施虐者决定的&lt;/strong&gt;，因此他们也在反向塑造施虐者的行为。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;在这个循环中，施虐者和受虐者的角色可能互相倒置，甚至共存。&lt;/strong&gt;&lt;br&gt;
例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;施虐者的控制欲实际上建立在&lt;strong&gt;受虐者的服从之上&lt;/strong&gt;，因此他的存在本身已经依赖于受虐者的配合。&lt;/li&gt;
&lt;li&gt;受虐者在忍受痛苦的同时，&lt;strong&gt;也在操控施虐者的行为&lt;/strong&gt;，因为他们通过自身的反应在 “训练” 施虐者，使其按照某种方式施加痛苦。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;拉康在精神分析中强调，&lt;strong&gt;施虐与受虐的行为模式并不是独立的，而是彼此依赖的对偶关系&lt;/strong&gt;。在极端情况下，一个人可能在心理层面同时充当两个角色。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;2-超我superego如何在个体内部制造施虐-受虐关系&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-超我superego如何在个体内部制造施虐-受虐关系&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(2) 超我（Superego）如何在个体内部制造施虐 - 受虐关系&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;弗洛伊德的精神分析理论中，&lt;strong&gt;超我（Superego）是施虐者，而自我（Ego）则是受虐者&lt;/strong&gt;。换句话说，一个人在心理上可能&lt;strong&gt;同时施虐自己，又受虐于自己&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;超我是父权象征（象征性权威），它不断&lt;strong&gt;惩罚自我，制造罪恶感&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;自我在被超我支配的同时，又&lt;strong&gt;主动寻求这种惩罚&lt;/strong&gt;，因为罪恶感本身可以成为一种享乐（Jouissance）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;工作狂（Workaholic）&lt;/strong&gt;：一个人可能不断压榨自己，追求完美的业绩，不给自己休息的时间。在这个过程中，他既是施虐者（强迫自己工作），也是受虐者（承受工作的折磨）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;自我牺牲（Self-Sacrifice）&lt;/strong&gt;：某些人在道德层面上以 “为他人奉献” 为乐，但实际上他们在这个过程中也对自己实施了某种折磨，甚至是无意识地寻找痛苦。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;拉康认为，超我本质上是一种 **“施虐性的享乐结构”&lt;strong&gt;。它让个体不断内化社会的律法，并通过自我惩罚来获得快感。这解释了为什么有些人会&lt;/strong&gt;主动沉迷于痛苦或高强度的道德要求 **。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;2-哲学上的辩证关系享乐的双重性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-哲学上的辩证关系享乐的双重性&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. 哲学上的辩证关系：享乐的双重性&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;从哲学角度来看，施虐与受虐的关系涉及&lt;strong&gt;享乐（Jouissance）的悖论&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;普通的快乐（Pleasure）受 “快乐原则” 控制，即趋向愉悦，回避痛苦。&lt;/li&gt;
&lt;li&gt;但享乐（Jouissance）超越了快乐，它可以&lt;strong&gt;包含痛苦、禁忌、甚至毁灭性的元素&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;这意味着，在某些情况下，人可能同时享受痛苦和快感，即&lt;strong&gt;在受虐的同时获得施虐的权力感&lt;/strong&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;宗教禁欲主义（Asceticism）&lt;/strong&gt;：某些宗教信仰提倡禁欲和苦行，信徒通过自我惩罚来获得某种神圣的喜悦。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;极端的革命者或殉道者&lt;/strong&gt;：某些人愿意为信仰或理想而自我牺牲，但这种 “自我毁灭” 同时也是一种对自身意志的极端控制（即施虐的一面）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;哲学家齐泽克（Slavoj Žižek）分析道，&lt;strong&gt;意识形态本身就是一种 “施虐 - 受虐关系”&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;现代社会并非简单地压迫个体，而是让个体主动内化这种压迫，并在自我剥削中找到意义（如 “996” 工作文化）。&lt;/li&gt;
&lt;li&gt;个体在接受社会规则时，实际上是在&lt;strong&gt;享受自己被规训的快感&lt;/strong&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;3-社会与政治维度制度如何制造施虐-受虐关系&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-社会与政治维度制度如何制造施虐-受虐关系&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. 社会与政治维度：制度如何制造施虐 - 受虐关系&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;施虐 - 受虐关系不仅存在于个体心理中，还&lt;strong&gt;广泛存在于社会结构&lt;/strong&gt;，尤其是权力与意识形态的运作方式：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;资本主义的自我剥削&lt;/strong&gt;：&lt;br&gt;
在资本主义社会，人们被要求 “努力工作”“自我提升”，甚至在超负荷工作时感到满足。个体在这个过程中既是施虐者（对自己施加高要求），也是受虐者（承受加班和过劳的痛苦）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;政治极端主义&lt;/strong&gt;：&lt;br&gt;
某些极端政治运动中，领导者通过残酷的纪律约束自己和追随者，形成 **“以痛苦换取纯粹性的机制”&lt;strong&gt;。&lt;br&gt;
例如，法西斯主义、极端宗教组织都利用了 “自我牺牲” 作为一种道德律法，要求成员&lt;/strong&gt;在受虐的同时成为惩罚异己的施虐者 **。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;齐泽克指出，&lt;strong&gt;当人们在意识形态中找到 “享乐” 时，他们实际上已经陷入了施虐 - 受虐的恶性循环&lt;/strong&gt;。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;4-结论施虐与受虐的辩证性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-结论施虐与受虐的辩证性&#34;&gt;#&lt;/a&gt; &lt;strong&gt;4. 结论：施虐与受虐的辩证性&lt;/strong&gt;&lt;/h2&gt;
&lt;h3 id=&#34;1-个体层面&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-个体层面&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(1) 个体层面&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;施虐与受虐并非对立，而是&lt;strong&gt;一种双向循环&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;一个个体可能在&lt;strong&gt;心理上对自己施虐，同时又享受受虐的过程&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;这种模式符合弗洛伊德的&lt;strong&gt;超我施虐结构&lt;/strong&gt;，以及拉康的&lt;strong&gt;享乐理论&lt;/strong&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2-社会与文化层面&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-社会与文化层面&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(2) 社会与文化层面&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;现代社会鼓励个体 “主动受虐”，比如过度工作、极端自律等，这其实是一种隐形的权力控制机制。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;意识形态运作的方式&lt;/strong&gt;，往往让个体在 “自我牺牲” 中找到意义，从而&lt;strong&gt;在受虐的同时成为社会规范的维护者（施虐者）&lt;/strong&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3-哲学层面&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-哲学层面&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(3) 哲学层面&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;享乐不仅仅是愉悦，它可以是&lt;strong&gt;痛苦的、禁忌的、甚至毁灭性的&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;施虐与受虐的关系本质上是一种 “极端享乐” 的表现&lt;/strong&gt;，它挑战了 “快乐原则”，并揭示了主体如何在痛苦中寻求意义。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;开放性问题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#开放性问题&#34;&gt;#&lt;/a&gt; &lt;strong&gt;开放性问题&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;这个话题可以继续深入，比如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;如何在日常生活中察觉到这种施虐 - 受虐结构？&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;现代社会如何利用这种辩证关系来操控个体？&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;是否存在某种方式可以超越这种二元结构，而不是陷入其循环？&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;你对哪个方向更感兴趣？&lt;/p&gt;
&lt;p&gt;Q：是否存在某种方式可以超越这种二元结构，而不是陷入其循环？&lt;br&gt;
A: 超越施虐 - 受虐的二元结构并非易事，因为它不仅是一个心理机制，还深植于社会、文化和意识形态的运作方式。然而，哲学、精神分析、批判理论等多个领域都提供了一些可能的出路，主要可以从&lt;strong&gt;主体性的重构、享乐结构的重新安排，以及社会关系的变革&lt;/strong&gt;等角度进行探讨。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;1-主体性的重构超越受虐者与施虐者的角色&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-主体性的重构超越受虐者与施虐者的角色&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. 主体性的重构：超越受虐者与施虐者的角色&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;（1）从 “无意识的重复” 转向 “自觉的转化”&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;弗洛伊德的 “强迫性重复” 理论认为，个体往往无意识地重复创伤模式（例如持续进入施虐 - 受虐关系）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;要超越这种循环，个体需要意识到自己的行为模式，并在自觉层面进行转化。&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;例如，一个工作狂意识到自己正在受虐于资本主义工作伦理，同时又施虐于自己或下属，他可以&lt;strong&gt;选择重新定义自己的工作方式，而非继续沉溺其中&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;这类似于拉康所说的 “去象征化”（désymbolisation）过程 ——&lt;strong&gt; 主体意识到自己被象征秩序塑造后，便可能在其中找到新的位置，而非完全屈服于它&lt;/strong&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;（2）从 “认同律法” 到 “重新书写律法”&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拉康认为，倒错者的问题在于他们总是&lt;strong&gt;试图维护象征秩序，但以极端方式执行它&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;真正的超越不是简单地服从或反抗律法，而是重新定义自己与律法的关系。&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;例如，在极权社会中，有些人选择极端服从（受虐），有些人选择暴力反抗（施虐），但超越这两者的方式可能是&lt;strong&gt;创造新的社会实践和规则&lt;/strong&gt;，以不同的方式抵抗权力。&lt;/li&gt;
&lt;li&gt;在个人层面，一个人可以在自我要求和自由之间找到新的平衡，而不是陷入 “自虐式完美主义” 或 “放纵式逃避” 之间的摇摆。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;2-重新安排享乐jouissance从破坏性享乐到创造性享乐&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-重新安排享乐jouissance从破坏性享乐到创造性享乐&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. 重新安排享乐（Jouissance）：从破坏性享乐到创造性享乐&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;拉康的 “享乐”（Jouissance）概念表明，主体的欲望往往指向痛苦和过度的快感。要超越施虐 - 受虐的循环，关键是&lt;strong&gt;重新安排享乐的方式&lt;/strong&gt;，让它从破坏性的、压抑性的模式转变为创造性的、开放性的模式。&lt;/p&gt;
&lt;h3 id=&#34;1享乐的解构破除禁忌减少压抑&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1享乐的解构破除禁忌减少压抑&#34;&gt;#&lt;/a&gt; &lt;strong&gt;（1）享乐的解构：破除禁忌，减少压抑&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;享乐的悖论在于：越是被禁止的东西，越能激发快感。&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;受虐者的快感往往源于 “被支配”，但如果这种支配不再具有 “禁忌性”，它可能就不再那么诱人。&lt;/li&gt;
&lt;li&gt;例如，如果社会不再对 “懒惰” 施加过度的道德压力，某些人可能会发现，他们原本以 “过度工作” 作为自虐方式的快感已经消失。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;通过&lt;strong&gt;减少外部的压抑机制，主体可以更自由地选择享乐，而不是在痛苦中寻找享乐。&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2创造性的享乐转向非破坏性的激情&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2创造性的享乐转向非破坏性的激情&#34;&gt;#&lt;/a&gt; &lt;strong&gt;（2）创造性的享乐：转向非破坏性的激情&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;施虐 - 受虐结构的问题在于，它总是依赖 “他者的痛苦” 或 “自我的痛苦” 来获取快感。&lt;/li&gt;
&lt;li&gt;然而，享乐可以&lt;strong&gt;转向非破坏性的方向&lt;/strong&gt;，比如：
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;艺术、创造、游戏&lt;/strong&gt;：很多艺术家通过创作将破坏性的冲动转化为创造性的能量，从而避免直接伤害自己或他人。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;幽默、讽刺&lt;/strong&gt;：齐泽克认为，幽默是一种打破意识形态循环的方式，因为它能让人意识到自己深陷其中，同时又能保持一定的距离。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;自我探索&lt;/strong&gt;：如禅宗冥想、身体实践（舞蹈、瑜伽）等，它们提供了一种&lt;strong&gt;非施虐 - 受虐模式的快感&lt;/strong&gt;，让个体在不受外部律法规训的情况下体验自身的存在。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;3-社会关系的变革去中心化的权力结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-社会关系的变革去中心化的权力结构&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. 社会关系的变革：去中心化的权力结构&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;精神分析的施虐 - 受虐关系不仅发生在个人层面，也深植于社会制度之中。因此，个人的解放往往与社会变革相伴。&lt;/p&gt;
&lt;h3 id=&#34;1摆脱支配-服从结构转向合作性关系&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1摆脱支配-服从结构转向合作性关系&#34;&gt;#&lt;/a&gt; &lt;strong&gt;（1）摆脱支配 - 服从结构，转向合作性关系&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;传统权力结构（如父权制、威权主义）往往依赖于 “支配者 vs. 服从者” 的模式。&lt;/li&gt;
&lt;li&gt;然而，去中心化的社会结构（如合作社、自治组织、民主协商）可以减少这种极端二分。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;举例：&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;企业组织可以采用&lt;strong&gt;扁平化管理&lt;/strong&gt;，让员工不再陷入 “自我剥削” 或 “被剥削” 的循环。&lt;/li&gt;
&lt;li&gt;教育方式可以从 “惩罚 - 服从” 模式转向 “自主探索”，减少 “被动学习 vs. 强制管控” 的施虐 - 受虐关系。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2改变意识形态让个体拥有自主的欲望&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2改变意识形态让个体拥有自主的欲望&#34;&gt;#&lt;/a&gt; &lt;strong&gt;（2）改变意识形态，让个体拥有自主的欲望&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;施虐 - 受虐关系在社会层面上往往由意识形态强化，例如：
&lt;ul&gt;
&lt;li&gt;“成功人士必须加班”“真正努力的人不会抱怨” 等观念，让个体主动认同 “自虐式奋斗”。&lt;/li&gt;
&lt;li&gt;“道德高尚的人必须自我牺牲”，让人们陷入 “受虐式奉献” 的循环。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;超越这种意识形态的方式在于：
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;建立新的价值体系&lt;/strong&gt;，强调平衡、合作，而非极端的竞争与支配。&lt;/li&gt;
&lt;li&gt;让个体认识到&lt;strong&gt;他们的欲望并不一定是被社会塑造的那种 “应该想要的东西”&lt;/strong&gt;，从而发展更自主的选择。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;4-结论如何逃出循环&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-结论如何逃出循环&#34;&gt;#&lt;/a&gt; &lt;strong&gt;4. 结论：如何逃出循环？&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;超越施虐 - 受虐的方式并不是简单地拒绝痛苦或权力，而是重新定义主体如何体验享乐、如何与社会规则互动。&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;可能的路径包括：&lt;/strong&gt;&lt;br&gt;
✅ &lt;strong&gt;个体层面&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;觉察自己的 “无意识重复”，并尝试转化欲望结构。&lt;/li&gt;
&lt;li&gt;重新书写自己的律法，而不是被动服从或极端反抗。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;✅ &lt;strong&gt;享乐层面&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;破除禁忌，减少对压抑性享乐的依赖。&lt;/li&gt;
&lt;li&gt;将享乐从破坏性模式转向创造性模式，如艺术、幽默、身体实践等。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;✅ &lt;strong&gt;社会层面&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;变革社会结构，减少支配 - 服从的二元关系。&lt;/li&gt;
&lt;li&gt;改变意识形态，让个体更自由地选择自己的生活方式。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;最终，关键在于让个体&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;不再依赖痛苦来定义自我&lt;/strong&gt;，而是找到不需要施虐或受虐的方式来体验世界。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;不再只是顺从或反抗权力，而是创造新的社会实践&lt;/strong&gt;，让人们可以在合作和自由中建立新的关系模式。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;你怎么看你认为现实生活中有哪些领域可能最需要这样的超越&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#你怎么看你认为现实生活中有哪些领域可能最需要这样的超越&#34;&gt;#&lt;/a&gt; &lt;strong&gt;你怎么看？你认为现实生活中有哪些领域可能最需要这样的超越？&lt;/strong&gt;&lt;/h3&gt;

 &lt;p&gt;总结一下以往看过的文章对于 background，尤其是对于 spatial domain 相关知识的介绍&lt;/p&gt;
&lt;h1 id=&#34;benchmarking-spatial-clustering-methods-with-spatially-resolved-transcriptomics-data&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#benchmarking-spatial-clustering-methods-with-spatially-resolved-transcriptomics-data&#34;&gt;#&lt;/a&gt; Benchmarking spatial clustering methods with spatially resolved transcriptomics data&lt;/h1&gt;
&lt;p&gt;Spatial clustering, which shares an analogy with single-cell clustering, has expanded the scope of tissue physiology from cell-centriod to structure-centroid with spatially resolved transcriptomics(SRT) data.&lt;/p&gt;
&lt;p&gt;advancements in spatially resolved transcriptomics(SRT) enable the multiplexed spatial mapping of gene expression, allowing researchers to move beyond cell clustering to identify higher-order tissue structures, or spatial domains, through the provisdion of additional spatial information.&lt;/p&gt;
&lt;p&gt;Identifying spatial domains by spatial clustering has become a standard initial step in constructing spatial atlas and has proven to be a crucial in visualizing tissue anatomy, inferring tissue spatial signatures of development and disease, and identifying domain-dependent molecular regulatory networks.&lt;/p&gt;
&lt;h2 id=&#34;supplymentary-note&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#supplymentary-note&#34;&gt;#&lt;/a&gt; Supplymentary Note&lt;/h2&gt;
&lt;p&gt;Spatial clustering, also known as spatial domain identification, aims to utilize both gene expression profiles and spatial information to identify tissue regions with spatially coherent gene expression patterns.&lt;/p&gt;
&lt;p&gt;The primary applied spatial data types are spot-like non-single-cell resolution technologies, such as 10X Visium and ST. With the development of advanced technologies that have improved spatial resolution, the applied data type has been extended to single-cell level datasets, such as Slide-seq, Slide-seqV2, Stereo-seq, STARmap, MERFISH, and seqFISH1, among others.&lt;/p&gt;
&lt;p&gt;These methods are useful in the following aspects:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;The identification of tissue structures. Traditionally, histological experts annotate tissue structures, which is a highly labor-demanding and subjective approach. However, spatial clustering provides an unbiased and efficient way to segregate tissue structures without human supervision, saving a lot of time and effort. For example, the classical dorsolateral prefrontal cortex (DLPFC) dataset was originally annotated by experts, but current advances in spatial clustering methods have been able to automatically annotate the tissue with very similar performance to human labels. Other brain regions were also annotated computationally, such as the hypothalamic preoptic region, primary visual area, hippocampus, and cerebellum. In the future, other brain regions, the whole brain, and more complex tissues and organs will hopefully be annotated in an unbiased and effective manner by advancements in computational methods.&lt;/li&gt;
&lt;li&gt;Some tissue structures cannot be trivially identified by referring to H&amp;amp;E images. An important example is the liver. In a liver lobule, the tissue spatially is classically divided into different zones (termed liver zonation), and each zone contains major portions of hepatocytes having different metabolic functions while displaying similar morphological features. In such tissue, manual annotation is especially challenging, given the large amount of liver lobules with complex shapes. Computational methods are very important in such cases.&lt;/li&gt;
&lt;li&gt;The identification of tissue spatial continuity. Some tissues display continuous spatial patterns instead of having sharp tissue interfaces. For example, the brain cortex, although partitioned into several discrete layers, may not have strictly defined boundaries. Many genes exhibited strong continuity along the cortical axis, and some higher-level cellular organizations also showed continuity, such as cell type complexity and spatial heterogeneity, which were reported to have strong correlations with cortical depth. The continuity sometimes has clinical significance in disease and cancer. Investigations have been made in studying the gradual structural changes from adjacent normal tissue to cancerous tissue to understand the molecular and tissue biology of cancer.&lt;/li&gt;
&lt;li&gt;The identification of domain-specific marker genes. Different from cell-type-specific marker genes, domain-specific marker genes show stronger spatial autocorrelations.Their functions are more likely to be spatially related or display specificity to certain proximities to certain microenvironments. Traditionally, gene markers that define specific brain regions are identified by traditional assays (such as bulk or scRNA-seq) from selected brain domains. Such practice is labor-demanding and has limited domain specificity. Some genes within certain domains or tissue microenvironments are strongly related to their localizations. For example, in disease, molecular polarizations have been found in liver fibrosis, where metabolites related to glycolysis within the hepatic domains showed polarization patterns towards the fibrosis domain boundary. In another example in cancer, some immune-related proteins showed polarization patterns within the immune regions towards tumor domain boundaries, which is reported to be associated with tumor-immune interactions.&lt;/li&gt;
&lt;li&gt;Mining spatial signatures of development and disease. In the single-cell era, cell type proportions were typically used to differentiate different patient groups for better diagnosis. However, many diseases and cancers do not show significant differences in cell type proportions but only have differences in terms of the spatial organizations of cells30,31. Such cases have been reported in different cancers (e.g., breast cancer12 and colorectal cancer30) and COVID-19 diseases31. Pioneer computational methods have already illustrated the diagnostic significance of such cases.&lt;/li&gt;
&lt;li&gt;Identifying domain-dependent molecular regulatory networks. Such studies are mainly concentrated on investigating the distribution of disease-related molecules (e.g., proteins) across spatial domains. A recent study developed STARmapPlus to simultaneously spatially profile targeted proteins and gene expressions. They used the new technology to study the different distributions of Alzheimer&#39;s disease-related proteins within domains. Another study utilized computational methods to predict the abundance of such proteins by incorporating spatial microenvironment information.&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;spagcn&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#spagcn&#34;&gt;#&lt;/a&gt; SpaGCN&lt;/h1&gt;
&lt;p&gt;Recent technological advances in SRT have enabled gene expression profilingh with spatial information in tissue.&lt;/p&gt;
&lt;p&gt;Knoledge of the relative locations of different cells in a tissue is critical for understanding disease pathology because spatial information helps in understanding how the gene expression of a cell is influenced by its surrounding environment.&lt;/p&gt;
&lt;p&gt;methods for SRT:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;in situ hybridization or sequencing-based technologies with single-cell resolution
&lt;ul&gt;
&lt;li&gt;e.g. seqFISH, seqFISH+, MERFISH, STARmap and FISSEQ that measure the expression level for hundred to thousands of genes in cells within their tissue context.&lt;/li&gt;
&lt;li&gt;因为能达到单细胞分辨率，这些技术适合于高精度分析，用于深入理解细胞在组织结构中的分布以及细胞间的相互作用。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;in situ capturing-based technologies with spatial barcoding followed by sequencing
&lt;ul&gt;
&lt;li&gt;e.g. spatial transcriptomics(ST), SLIDE-seq, SLIDE-seqV2, HDST and 10x Visium that measure the expression level for thousands of genes in captured locations, referred to as spots.&lt;/li&gt;
&lt;li&gt;由于通常只能定位到捕获区域的水平，这类技术的空间分辨率低于单细胞分辨率，但它们适合于大规模研究，因为能够同时检测数千个基因。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;To link spatial domains with biological functions, it is crucial to identify genes that show enriched expression in the identified domains. Methods such as Trendsceek, SpatialDE and SPARK have been developed to detect spatially variable genes(SVGs).&lt;/p&gt;
&lt;h1 id=&#34;bayesspace&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#bayesspace&#34;&gt;#&lt;/a&gt; BayesSpace&lt;/h1&gt;
&lt;p&gt;Knowledge of the spatial location of transript expression can provide vital insights into biological function and pathology.&lt;/p&gt;
&lt;p&gt;Single-cell RNA sequencing(scRNA-seq) achieves high-throughput and high-resolution profiling of gene expression, but because tissue is dissociated for sample preparation, spatial information is not retained.&lt;/p&gt;
&lt;p&gt;Recent methods for high-throughput profiling of gene expression while retaining spatial information allow analyses to be made within the context of the biological tissue.Studies performed with the Spatial Transcriptomics(ST) platform and the improved Visium platform have already generated insights into diverse areas such as tumor heterogeneity, brain function and the pathophysiology of sepsis. The primary technological limitation of these spatial gene expression platforms is resolution, with the unit of observation being spots that are 100 μm in diameter on the ST platform and 55 μm in diameter on the Visium platform.  As such, the number of cells within a spot may range from one to 30 on the Visium platform and up to 200 on the older ST platform, depending on the biological tissue. Alternative approaches include fluorescence in situ hybridization (FISH) technologies, such as seqFISH and multiplexed error-robust FISH, and other recently developed spatial sequencing methods, such as Slide-seq and ZipSeq. While these methods provide increased resolution, most are lower throughput, less sensitive, rely on custom protocols or are not widely available.&lt;/p&gt;
&lt;p&gt;+++ 解释&lt;br&gt;
这段话主要讨论了不同 ** 空间转录组技术（spatial transcriptomics, ST）&lt;strong&gt;在&lt;/strong&gt;分辨率（resolution）、通量（throughput）、灵敏度（sensitivity）和可用性（availability）** 方面的差异。可以从以下几个方面理解：&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;1-visium-与-st-平台的细胞数差异&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-visium-与-st-平台的细胞数差异&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. Visium 与 ST 平台的细胞数差异&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;在 &lt;strong&gt;10X Genomics Visium&lt;/strong&gt; 平台上，每个检测点（spot）可能包含 &lt;strong&gt;1 到 30 个细胞&lt;/strong&gt;，具体取决于生物组织的密度。&lt;/li&gt;
&lt;li&gt;在 &lt;strong&gt;较早的 ST（Spatial Transcriptomics）平台&lt;/strong&gt; 上，每个检测点可能包含&lt;strong&gt;多达 200 个细胞&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;这表明 &lt;strong&gt;Visium 提供了更高的分辨率&lt;/strong&gt;，因为每个 spot 覆盖的细胞数量更少，可以更精细地解析基因表达的空间分布。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;2-其他高分辨率技术fish-和新型空间测序方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-其他高分辨率技术fish-和新型空间测序方法&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. 其他高分辨率技术：FISH 和新型空间测序方法&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;荧光原位杂交（FISH）技术&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;seqFISH（sequential FISH）&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;MERFISH（multiplexed error-robust FISH）&lt;/strong&gt;&lt;br&gt;
这些技术通过荧光探针直接检测 RNA 分子，可以达到单细胞甚至亚细胞（subcellular）级别的分辨率。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;其他新型空间测序方法&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Slide-seq&lt;/strong&gt;：将 RNA 分子定位到微珠阵列（bead array）上，实现高分辨率空间测序。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;ZipSeq&lt;/strong&gt;：结合光学方法和条形码标记（barcoding）来进行空间解析。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;3-这些方法的局限性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-这些方法的局限性&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. 这些方法的局限性&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;尽管 &lt;strong&gt;seqFISH、MERFISH、Slide-seq 和 ZipSeq&lt;/strong&gt; 在分辨率方面优于 Visium 和 ST 平台，但它们存在以下不足：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;通量较低（lower throughput）&lt;/strong&gt;：一次实验可以检测的 RNA 分子或细胞数量有限，难以大规模应用。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;灵敏度较低（less sensitive）&lt;/strong&gt;：相比于 Visium 这样的商业化平台，FISH 技术可能在检测低丰度基因表达时存在问题。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;依赖定制实验流程（custom protocols）&lt;/strong&gt;：这些方法往往需要特殊的实验设置，不如 Visium 这样的平台易于使用。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;尚未广泛可用（not widely available）&lt;/strong&gt;：这些技术可能仍处于实验室研发阶段，尚未大规模商业化，难以在各类实验室推广。&lt;/li&gt;
&lt;/ol&gt;
&lt;hr&gt;
&lt;h3 id=&#34;总结&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结&#34;&gt;#&lt;/a&gt; &lt;strong&gt;总结&lt;/strong&gt;&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;技术&lt;/th&gt;
&lt;th&gt;细胞覆盖范围&lt;/th&gt;
&lt;th&gt;分辨率&lt;/th&gt;
&lt;th&gt;通量&lt;/th&gt;
&lt;th&gt;灵敏度&lt;/th&gt;
&lt;th&gt;可用性&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;Visium&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;1-30 细胞 /spot&lt;/td&gt;
&lt;td&gt;中等&lt;/td&gt;
&lt;td&gt;高&lt;/td&gt;
&lt;td&gt;高&lt;/td&gt;
&lt;td&gt;商业化，易获取&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;ST（老版）&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;高达 200 细胞 /spot&lt;/td&gt;
&lt;td&gt;低&lt;/td&gt;
&lt;td&gt;高&lt;/td&gt;
&lt;td&gt;高&lt;/td&gt;
&lt;td&gt;商业化，易获取&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;seqFISH / MERFISH&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;单细胞甚至亚细胞级&lt;/td&gt;
&lt;td&gt;高&lt;/td&gt;
&lt;td&gt;低&lt;/td&gt;
&lt;td&gt;低&lt;/td&gt;
&lt;td&gt;需要特殊设备和协议&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;Slide-seq / ZipSeq&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;取决于条形码技术&lt;/td&gt;
&lt;td&gt;高&lt;/td&gt;
&lt;td&gt;低&lt;/td&gt;
&lt;td&gt;低&lt;/td&gt;
&lt;td&gt;仍在研究中，尚未大规模应用&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;strong&gt;核心理解&lt;/strong&gt;：Visium 和 ST 平台虽然分辨率不如 seqFISH 或 Slide-seq，但它们的&lt;strong&gt;通量高、灵敏度强、实验流程标准化，适用于大规模应用&lt;/strong&gt;。而 FISH 和新型空间测序方法提供了更高分辨率，但&lt;strong&gt;实验复杂度高，难以大规模推广&lt;/strong&gt;。&lt;br&gt;
+++&lt;/p&gt;
&lt;h1 id=&#34;stagate&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#stagate&#34;&gt;#&lt;/a&gt; STAGATE&lt;/h1&gt;
&lt;p&gt;Deciphering spatial domains (i.e., regions with similar spatial expression patterns) is one of the great challenges from STs.For example, the laminar organization of the human cerebral cortex is especially related to its biological functions, in which cells residing within different cortical layers often differ in expressions, morphology and physiology.&lt;/p&gt;
&lt;p&gt;These non-spatial methods can be roughly divided into two categories. The first category uses traditional clustering methods such as k-means and Louvain algorithm. These methods are limited to the small number of spots or the sparsity according to the different resolutions of ST technologies, and clustering results may be discontinuous in the tissue section. The second category utilizes the cell type signatures defined by single-cell RNA-seq to deconvolute the spots. They are not applicable to ST data at a resolution of cellular or subcellular levels.&lt;/p&gt;
&lt;p&gt;Some recent algorithms adapt the clustering methods by considering the similarity between adjacent spots to better account for the spatial dependency of gene expressions. These methods show significant improvements in identifying spatial domains of sections from brain and cancer tissues. For example, BayesSpace is a Bayesian statistical method that encourages neighboring spots to belong to the same cluster by introducing spatial neighbor structure into the prior. Giotto identifies spatial domains by implementing a hidden Markov random field (HMRF) model with the spatial neighbor prior. stLearn defines the morphological distance based on features extracted from a histology image and utilizes such distances as well as spatial neighbor structure to smooth gene expressions. SEDR employs a deep auto-encoder network for learning gene representations and uses a variational graph auto-encoder to simultaneously embed spatial information. SpaGCN also applies the graph convolutional network to integrate gene expression and spatial location, and further coupled with a self-supervised module to identify domains. Besides, a recent developed method named RESEPT leverages the supervised image segmentation method to perform tissue structure identification. Although these methods consider the spatial structure of STs, the similarity of neighboring spots defined by them is pre-defined before training and cannot be learned adaptively. Moreover, these methods do not consider the spatial similarity of spots at the boundary of spatial domains in more detail and do not well integrate spatial information to impute and denoise gene expressions. More importantly, these approaches cannot be applied to multiple consecutive sections to reconstruct a three-dimensional (3D) ST model and extract 3D expression domains.&lt;/p&gt;
&lt;p&gt;全是英文看的想吐，这里补充一下中文的版本：&lt;/p&gt;
&lt;h1 id=&#34;benchmarking&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#benchmarking&#34;&gt;#&lt;/a&gt; Benchmarking&lt;/h1&gt;
&lt;p&gt;空间转录组学（SRT）的进步实现了基因表达的多重空间定位，使研究人员能够突破传统的细胞聚类，借助额外的空间信息识别更高层级的组织结构，即空间域（spatial domains）[&lt;sup&gt;1,&lt;/sup&gt;2,^3]。通过空间聚类识别空间域已成为构建空间图谱（spatial atlas）的标准初始步骤 [&lt;sup&gt;4–&lt;/sup&gt;8]，并在可视化组织解剖结构 [&lt;sup&gt;9]、推断组织空间连续性 [&lt;/sup&gt;10,&lt;sup&gt;11]、检测空间域特异性标志基因 [&lt;/sup&gt;12,&lt;sup&gt;13]、挖掘发育与疾病的空间特征 [&lt;/sup&gt;14,&lt;sup&gt;15]、识别空间域依赖的分子调控网络 [&lt;/sup&gt;16,^17] 等方面发挥了关键作用（见补充说明 1）。&lt;/p&gt;
&lt;p&gt;尽管近年来已经提出了基于概率图模型和图神经网络（GNNs）等多种识别空间域的计算方法 [&lt;sup&gt;18,&lt;/sup&gt;19]，但由于所用数据集和评估指标缺乏一致性与全面性，仍面临较大挑战。这些问题的产生原因包括：空间技术快速迭代、部分应用中评估指标过于有限，以及数据往往来自特定实验室基于特定组织和技术生成的数据集（见补充说明 2）。&lt;/p&gt;
&lt;p&gt;尽管已有一些空间转录组数据的基准评估工作，尤其聚焦于细胞类型识别 [^20]，但针对空间聚类方法用于空间域识别的系统性基准研究仍然缺失（见扩展图 1）。在本项研究中，我们从四个维度 —— 预测准确性、空间域连续性、空间标志基因识别能力以及方法的可扩展性（详见方法部分）—— 设定了十项评估指标。需要说明的是，本文中 “准确性” 一词的含义较传统统计学术语更广，而 “数据”（data）指的是来自同一切片的空间转录组数据，“数据集”（dataset）则表示来源于同一篇文献、基于相同技术生成的一组数据。&lt;/p&gt;
&lt;h1 id=&#34;spagcn-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#spagcn-2&#34;&gt;#&lt;/a&gt; SpaGCN&lt;/h1&gt;
&lt;p&gt;近年来空间转录组技术（SRT）的快速发展，使得我们能够在组织中获取带有空间信息的基因表达谱 [^1]。在理解疾病病理过程中，不同细胞在组织中的相对位置尤为关键，因为空间信息有助于揭示细胞基因表达如何受到其周围微环境的影响。&lt;/p&gt;
&lt;p&gt;目前常用的空间转录组实验方法大致可分为两类：&lt;br&gt;
第一类是基于原位杂交或测序的技术，具有单细胞分辨率，代表性方法包括 seqFISH [&lt;sup&gt;2,&lt;/sup&gt;3]、seqFISH+[&lt;sup&gt;4]、MERFISH[&lt;/sup&gt;5,&lt;sup&gt;6]、STARmap[&lt;/sup&gt;7] 和 FISSEQ [^8]，它们可在保持组织结构的同时测量数百到上千个基因的表达水平。&lt;br&gt;
第二类是基于原位捕获的技术，通过空间条形码标记并后续进行测序，代表性方法包括 Spatial Transcriptomics（ST）[&lt;sup&gt;9]、SLIDE-seq[&lt;/sup&gt;10]、SLIDE-seqV2[&lt;sup&gt;11]、HDST[&lt;/sup&gt;12] 以及 10x Visium。这类技术可以在被称为 “spot” 的捕获位置上检测数千个基因的表达。&lt;/p&gt;
&lt;p&gt;这些多样化的 SRT 技术使得揭示异质性组织中复杂的转录组结构成为可能，也极大地拓展了我们对疾病相关细胞机制的理解 [&lt;sup&gt;13,&lt;/sup&gt;14]。&lt;/p&gt;
&lt;p&gt;在空间转录组研究中，识别 “空间域” 是一个重要步骤 —— 空间域是指在基因表达和组织形态上都具有空间连续性的区域。传统聚类方法如 K-means 和 Louvain 算法 [^15] 仅依赖基因表达数据，忽略了空间和组织结构信息，往往会得到不连续或生物学解释性较差的聚类结果。&lt;/p&gt;
&lt;p&gt;为了解决这一问题，近年来发展了多种考虑空间依赖性的聚类方法。例如，Zhu 等人 [&lt;sup&gt;16] 提出了基于隐马尔可夫随机场（HMRF）的模型来捕捉基因表达的空间依赖关系；stLearn [&lt;/sup&gt;17] 在聚类前融合了组织学图像特征以及邻近 spot 的表达信息以归一化数据；BayesSpace [^18] 则通过贝叶斯方法引入物理邻近性作为先验来优化聚类效果。这些方法虽能有效将 spot 或细胞划分为不同组，但由于在处理不同数据类型（模态）上的灵活性不足，限制了其广泛适用性。随着新一代空间转录组技术不断涌现 [&lt;sup&gt;19–&lt;/sup&gt;22]，亟需开发更具通用性的方法来适配多种平台。&lt;/p&gt;
&lt;p&gt;为了进一步探究空间域的生物学功能，识别在特定空间区域中高表达的基因是至关重要的一步。为此，研究者已开发出多种方法来检测具有空间差异表达的基因（spatially variable genes, SVGs），如 Trendsceek [&lt;sup&gt;23]、SpatialDE[&lt;/sup&gt;24] 和 SPARK [^25]。这些方法通常逐个基因独立评估其空间变异性，并通过 P 值反映其空间表达的显著性。然而，由于这些方法未考虑空间域的整体结构，所筛选出的基因可能缺乏明确的空间表达模式，从而限制了其在后续生物学研究中的应用潜力。&lt;/p&gt;
&lt;h1 id=&#34;stagate-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#stagate-2&#34;&gt;#&lt;/a&gt; STAGATE&lt;/h1&gt;
&lt;p&gt;复杂组织的功能在根本上与不同细胞类型的空间环境密切相关 [&lt;sup&gt;1]。组织中转录表达的相对位置对于理解其生物学功能、描述细胞间的交互网络具有重要意义 [&lt;/sup&gt;2]。近年来，空间转录组（Spatial Transcriptomics, ST）技术取得了突破性进展，如 10x Visium [&lt;sup&gt;3]、Slide-seq[&lt;/sup&gt;4,&lt;sup&gt;5]、Stereo-seq[&lt;/sup&gt;6] 和 PIXEL-seq [^7] 等，使得我们能够在被称为 “spot” 的捕获位置上，以数个细胞甚至亚细胞级别的分辨率进行全基因组水平的表达谱分析。&lt;/p&gt;
&lt;p&gt;解析空间域（即表达模式相似的区域）是空间转录组研究面临的重要挑战之一。例如，人类大脑皮层的层状结构与其生物学功能密切相关，其中不同皮层层级中的细胞在基因表达、形态结构和生理功能上往往存在显著差异 [^8]。然而，多数现有聚类方法未能有效利用空间信息。这些非空间方法大致可分为两类：&lt;br&gt;
第一类是传统聚类算法，如 K-means 和 Louvain 算法 [^9]，它们在 spot 数量较少或数据稀疏时（因 ST 技术分辨率不同）效果有限，且常导致聚类结果在组织切片中不连续；&lt;br&gt;
第二类方法基于单细胞 RNA 测序定义的细胞类型特征对 spot 进行解卷积 [&lt;sup&gt;10,&lt;/sup&gt;11]，但该类方法并不适用于细胞或亚细胞分辨率的 ST 数据。&lt;/p&gt;
&lt;p&gt;为更好地建模基因表达的空间依赖性，部分近期算法在聚类时引入了邻近 spot 之间的相似性考虑，从而在脑组织和癌症组织的空间域识别方面取得了显著进展 [&lt;sup&gt;12,&lt;/sup&gt;13,^14]。&lt;br&gt;
例如，BayesSpace 是一种贝叶斯统计方法，通过在先验中引入空间邻近结构，鼓励相邻 spot 属于同一聚类 [^12]；Giotto 采用隐马尔可夫随机场（HMRF）模型，结合空间邻接信息以识别空间域 [^15]；stLearn 利用组织切片图像中提取的形态特征定义 “形态距离”，并结合空间邻接结构对基因表达进行平滑处理 [^13]；SEDR 则通过深度自动编码器学习基因表达表示，并利用变分图自编码器嵌入空间信息 [^14]；SpaGCN 应用了图卷积网络来整合基因表达与空间位置，并通过自监督模块提升空间域识别效果 [^16]；此外，新近提出的 RESEPT 方法则借助有监督图像分割方法进行组织结构识别 [^17]。&lt;/p&gt;
&lt;p&gt;虽然这些方法均考虑了 ST 的空间结构，但它们所定义的邻近 spot 间相似性在训练前是固定的，无法自适应学习；同时，这些方法在处理空间域边界处 spot 之间的空间相似性上考虑不足，亦未能充分整合空间信息对基因表达进行插补与去噪。更重要的是，这些方法无法应用于多张连续切片，进而无法构建三维（3D）ST 模型，也无法识别三维空间表达域（详见补充表 S1）。&lt;/p&gt;
&lt;h1 id=&#34;bayesspace-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#bayesspace-2&#34;&gt;#&lt;/a&gt; BayesSpace&lt;/h1&gt;
&lt;p&gt;了解转录表达的空间位置可以为生物功能和病理过程提供重要的洞见。单细胞 RNA 测序（scRNA-seq）虽然可以实现高通量和高分辨率的基因表达谱分析，但由于组织在样本制备过程中被解离，空间信息无法保留。近年来，一些新方法能够在保留空间信息的同时进行高通量的基因表达分析，使得研究可以在生物组织的上下文中进行 [^1]。&lt;/p&gt;
&lt;p&gt;基于 Spatial Transcriptomics（ST）平台及其改进版 Visium 平台的研究，已经在多个领域产生了新的见解，如肿瘤异质性 [&lt;sup&gt;2,&lt;/sup&gt;3]、脑功能 [&lt;sup&gt;4] 以及败血症的病理生理机制 [&lt;/sup&gt;5]。这些空间基因表达平台的主要技术限制在于分辨率：在 ST 平台上，观察单位是直径为 100 μm 的 spot，而在 Visium 平台上为 55 μm。因此，在 Visium 平台的一个 spot 中，可能包含 1 至 30 个细胞，而在老一代 ST 平台中，这一数量可达 200 个，具体取决于所研究的组织类型 [^6]。&lt;/p&gt;
&lt;p&gt;其他替代方法包括荧光原位杂交（FISH）技术，如 seqFISH 和多重误差稳健 FISH（MERFISH），以及最近发展的一些空间测序方法，如 Slide-seq 和 ZipSeq [&lt;sup&gt;7,&lt;/sup&gt;8,&lt;sup&gt;9,&lt;/sup&gt;10]。尽管这些方法在空间分辨率上有所提高，但它们多数通量较低、灵敏度较差、依赖定制实验方案，或尚未广泛普及。&lt;/p&gt;
&lt;h1 id=&#34;mender&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#mender&#34;&gt;#&lt;/a&gt; MENDER&lt;/h1&gt;
&lt;p&gt;空间分辨单细胞（SRSC, Spatially Resolved Single-Cell）技术的最新进展，使得在组织环境中对细胞基因表达进行高精度分析成为可能，从而可以全面地刻画各种生物系统的空间特征 [&lt;sup&gt;1,&lt;/sup&gt;2,&lt;sup&gt;3,&lt;/sup&gt;4,&lt;sup&gt;5,&lt;/sup&gt;6,&lt;sup&gt;7]。在不同基因表达状态的细胞协同作用下，空间域作为更高阶的功能单元，在组织空间中呈现出规律性的分布，并与组织生理功能密切相关 [&lt;/sup&gt;8,&lt;sup&gt;9]。在癌症等复杂疾病中，越来越多的证据表明，特定空间域在疾病的诊断与监测中发挥着关键作用 [&lt;/sup&gt;10,&lt;sup&gt;11,&lt;/sup&gt;12]。&lt;/p&gt;
&lt;p&gt;随着 SRSC 数据的不断积累 [&lt;sup&gt;13,&lt;/sup&gt;14]，众多计算方法被提出以识别这些空间域 [&lt;sup&gt;15,&lt;/sup&gt;16,^17]。&lt;/p&gt;
&lt;p&gt;在典型的 SRSC 数据集中，每个细胞都被测量了其空间坐标和基因表达谱。这种数据结构天然地构成了一个空间图，其中细胞作为图的节点，基因表达作为节点属性。这一结构促生了该领域的两大主流建模范式：图神经网络（GNN, Graph Neural Network）[&lt;sup&gt;18,&lt;/sup&gt;19,^20] 和 贝叶斯网络（BN, Bayesian Network）[&lt;sup&gt;21,&lt;/sup&gt;22,^23]。&lt;/p&gt;
&lt;p&gt;这两种建模路线的发展，大多数方法都是通过增加模型复杂度来提升性能。GNN 方法通常引入了专门的神经模块、损失函数和网络结构；而 BN 方法则扩展了隐变量、变量之间的依赖关系及先验知识。虽然模型复杂度的提升往往带来性能的增强，但近年来的一些研究显示，这种提升正呈现出边际收益递减的趋势 [^24]。&lt;/p&gt;
&lt;p&gt;此外，模型的复杂性还可能带来如下问题：参数调整困难、时间效率低、泛化能力下降。因此，这些挑战共同呼唤一种新的建模范式，以突破当前领域的发展瓶颈。&lt;/p&gt;
&lt;p&gt;我们首先解释为何在已有众多方法的前提下，仍然需要一种新的空间域识别方法。我们选取了近两年发表的 8 种现有方法，并从 6 个评估维度进行比较，包括：是否支持多切片分析、稳定性、可解释性、可扩展性、运行速度，以及是否能输出细胞上下文表示（见补充图 1A）。每个评估维度的简要定义见补充图 1A，详细说明见 “方法” 部分中 “从六个方面评估现有方法” 章节。&lt;/p&gt;
&lt;p&gt;这 8 种方法包括 4 种基于图神经网络（GNN）的模型（SpaGCN [&lt;sup&gt;18]、STAGATE[&lt;/sup&gt;19]、CCST [^25] 和 SpaceFlow [&lt;sup&gt;20]），以及 4 种基于贝叶斯网络（BN）的模型（BayesSpace [&lt;/sup&gt;21]、BASS[&lt;sup&gt;23]、SpatialPCA[&lt;/sup&gt;26] 和 SOTIP [^27]）。&lt;/p&gt;
&lt;p&gt;从结果中可以看到，多数评估指标与方法的基本原理密切相关（见补充图 1A）。所有 GNN 类方法在可扩展性和运行速度（在使用 GPU 的前提下）方面表现更好，并且能够输出细胞的上下文表示。但这类方法也继承了深度学习模型普遍存在的缺陷：稳定性差、可解释性不足。相较之下，BN 类方法在输出结果的稳定性和可解释性上更具优势，因为它们通常构建在明确的概率变量依赖关系上。然而，这类方法往往无法很好地适配大规模数据集，运行时间较长，且通常不能输出细胞上下文表示（SpatialPCA [^26] 是个例外）。&lt;/p&gt;
&lt;p&gt;这些评估结果不仅被我们在本文中的基准测试所验证，也得到了近期相关研究 [&lt;sup&gt;20,&lt;/sup&gt;23] 的支持。&lt;/p&gt;
&lt;p&gt;特别地，在空间组学迈入 “大数据时代” 的背景下，上述某些指标变得尤为关键。目前，许多大型科研合作项目已生成了包含上百万个细胞、跨多个切片的大规模空间组学数据集 [&lt;sup&gt;28,&lt;/sup&gt;29,^30]。在这种情境下，方法的可扩展性、运行效率和对多切片分析的支持变得格外重要。&lt;/p&gt;
&lt;p&gt;因此，尽管现有空间域识别方法种类繁多，仍然需要新的创新方法，以尽可能满足上述关键评估标准。&lt;/p&gt;
&lt;p&gt;组织内多种细胞类型复杂的空间组织结构，对于理解其生物学功能和病理状态至关重要。近年来，空间转录组学（Spatially Resolved Transcriptomics, SRT）技术取得了显著进展，如 10x Visium 等平台，通过原位测序大幅提升了我们在转录组水平上绘制组织结构和细胞间相互作用图谱的能力 [^1–4]。在分析空间转录组数据时，一个关键任务是将测点（spot）准确划分到空间域（spatial domain）中，这些空间域通常在基因表达模式和组织学结构上具有一致性。对复杂组织区域的准确划分对后续分析具有重要意义，例如识别空间变异基因（Spatially Variable Genes, SVGs）[&lt;sup&gt;5]、解析组织异质性 [&lt;/sup&gt;6]，以及 ** 探索细胞 - 细胞间相互作用 [^7]** 等。&lt;/p&gt;
&lt;h1 id=&#34;ensdd&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ensdd&#34;&gt;#&lt;/a&gt; EnSDD&lt;/h1&gt;
&lt;p&gt;当前的空间域检测（Spatial Domain Detection, SDD）方法大致可分为非空间聚类方法与空间聚类方法。传统的非空间聚类方法，如 K-means 和 Louvain 算法 [^8]，仅利用基因表达数据，常常导致聚类结果在空间上不连贯。相比之下，空间聚类方法（如 BayesSpace [&lt;sup&gt;9]、DR-SC[&lt;/sup&gt;10]、GraphST [^11] 和 STAGATE [^12]）在分析中引入了 SRT 数据的空间坐标，从而考虑基因表达的空间依赖性。这些方法通常会根据基因表达和空间位置对相邻 spot 进行联合聚类，通过不同的空间邻域建模策略来捕捉空间关系。虽然这些方法在脑组织和癌症组织中表现出显著优势 [&lt;sup&gt;12]，但它们往往忽略了组织学图像中蕴含的形态学信息，这可能导致划分出的空间域与真实组织结构不一致 [&lt;/sup&gt;13]。&lt;/p&gt;
&lt;p&gt;为了解决这一问题，出现了一类融合多模态信息的方法，如 SpaGCN [&lt;sup&gt;13]、stLearn[&lt;/sup&gt;14]、SiGra [^15] 和 spaVAE [^16]，它们将基因表达、空间坐标和组织学图像等多种信息结合，通过学习相邻 spot 间的空间依赖关系，从而在表达和形态学两方面都实现连续一致的空间域检测。&lt;/p&gt;
&lt;p&gt;由于各类空间聚类方法在假设和数据依赖方面存在差异，它们在划分空间域时产生的结果也存在差异 [&lt;sup&gt;17]。具体方法的效果还会受到组织复杂程度的影响 [&lt;/sup&gt;18]，这也增加了在新数据集中选择合适方法的难度。一个应对策略是开发集成方法（ensemble methods），通过整合多个基础方法的结果提高稳健性 [^19]。然而，集成方法也面临两个主要挑战：（i）不同基础方法可能生成不同数量和类型的空间域，使得结果整合变得复杂；（ii）方法性能在不同数据集间表现不一致，难以自动评估并融合各方法的效果。&lt;/p&gt;

 &lt;p&gt;在 C 调中，常见的和弦及其构成音（按照音阶度数）如下：&lt;/p&gt;
&lt;h3 id=&#34;三和弦triads&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三和弦triads&#34;&gt;#&lt;/a&gt; &lt;strong&gt;三和弦（Triads）&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;C（C 大三和弦）&lt;/strong&gt;：1, 3, 5 → C, E, G&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cm（C 小三和弦）&lt;/strong&gt;：1, ♭3, 5 → C, E♭, G&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cdim（C 减三和弦）&lt;/strong&gt;：1, ♭3, ♭5 → C, E♭, G♭&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Caug（C 增三和弦）&lt;/strong&gt;：1, 3, 5# → C, E, G#&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;七和弦seventh-chords&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#七和弦seventh-chords&#34;&gt;#&lt;/a&gt; &lt;strong&gt;七和弦（Seventh Chords）&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Cmaj7（C 大七和弦）&lt;/strong&gt;：1, 3, 5, 7 → C, E, G, B&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;C7（C 属七和弦）&lt;/strong&gt;：1, 3, 5, ♭7 → C, E, G, B♭&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cm7（C 小七和弦）&lt;/strong&gt;：1, ♭3, 5, ♭7 → C, E♭, G, B♭&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cm (maj7)（C 小大七和弦）&lt;/strong&gt;：1, ♭3, 5, 7 → C, E♭, G, B&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cdim7（C 减七和弦）&lt;/strong&gt;：1, ♭3, ♭5, ♭♭7（重降七）→ C, E♭, G♭, A&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cm7♭5（C 半减七和弦）&lt;/strong&gt;：1, ♭3, ♭5, ♭7 → C, E♭, G♭, B♭&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;扩展和弦extended-chords&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#扩展和弦extended-chords&#34;&gt;#&lt;/a&gt; &lt;strong&gt;扩展和弦（Extended Chords）&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;C9（C 属九和弦）&lt;/strong&gt;：1, 3, 5, ♭7, 9 → C, E, G, B♭, D&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cmaj9（C 大九和弦）&lt;/strong&gt;：1, 3, 5, 7, 9 → C, E, G, B, D&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cm9（C 小九和弦）&lt;/strong&gt;：1, ♭3, 5, ♭7, 9 → C, E♭, G, B♭, D&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;C11（C 属十一和弦）&lt;/strong&gt;：1, 3, 5, ♭7, 9, 11 → C, E, G, B♭, D, F&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cmaj11（C 大十一和弦）&lt;/strong&gt;：1, 3, 5, 7, 9, 11 → C, E, G, B, D, F&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cm11（C 小十一和弦）&lt;/strong&gt;：1, ♭3, 5, ♭7, 9, 11 → C, E♭, G, B♭, D, F&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;C13（C 属十三和弦）&lt;/strong&gt;：1, 3, 5, ♭7, 9, 11, 13 → C, E, G, B♭, D, F, A&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cmaj13（C 大十三和弦）&lt;/strong&gt;：1, 3, 5, 7, 9, 11, 13 → C, E, G, B, D, F, A&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Cm13（C 小十三和弦）&lt;/strong&gt;：1, ♭3, 5, ♭7, 9, 11, 13 → C, E♭, G, B♭, D, F, A&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;挂留和弦suspended-chords&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#挂留和弦suspended-chords&#34;&gt;#&lt;/a&gt; &lt;strong&gt;挂留和弦（Suspended Chords）&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Csus2（C 挂二和弦）&lt;/strong&gt;：1, 2, 5 → C, D, G&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Csus4（C 挂四和弦）&lt;/strong&gt;：1, 4, 5 → C, F, G&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;C7sus4（C 属七挂四和弦）&lt;/strong&gt;：1, 4, 5, ♭7 → C, F, G, B♭&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;如果你有特定的和弦想要补充或分析，欢迎告诉我！&lt;/p&gt;
&lt;p&gt;在 C 调的歌曲中提到 &lt;strong&gt;E minor Blues 音阶&lt;/strong&gt; 时，我们可以根据蓝调（Blues）音阶的定义来确定其具体的组成音。&lt;/p&gt;
&lt;h3 id=&#34;小调蓝调音阶minor-blues-scale的构成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#小调蓝调音阶minor-blues-scale的构成&#34;&gt;#&lt;/a&gt; 小调蓝调音阶（Minor Blues Scale）的构成&lt;/h3&gt;
&lt;p&gt;小调蓝调音阶由 6 个音组成，其公式为：&lt;br&gt;
&lt;strong&gt;1 - ♭3 - 4 - ♯4/♭5 - 5 - ♭7&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;具体到 &lt;strong&gt;E minor Blues 音阶&lt;/strong&gt;，我们以 E 为根音（1），按照上述公式计算每个音的位置：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;1&lt;/strong&gt;：E&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;♭3&lt;/strong&gt;：G&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;4&lt;/strong&gt;：A&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;♯4/♭5&lt;/strong&gt;：A# / Bb （称为 “蓝音”，Blue Note）&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;5&lt;/strong&gt;：B&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;♭7&lt;/strong&gt;：D&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;因此，&lt;strong&gt;E minor Blues 音阶&lt;/strong&gt;的组成音为：&lt;br&gt;
&lt;strong&gt;E - G - A - A# - B - D&lt;/strong&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;在c调中的应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#在c调中的应用&#34;&gt;#&lt;/a&gt; 在 C 调中的应用&lt;/h3&gt;
&lt;p&gt;虽然 C 调是以 C 为基准的大调，但在即兴演奏或编曲时，可以引入其他调性的音阶（如 E minor Blues）来增加色彩。例如，在 C 调的歌曲中，如果某个段落强调 E 和弦或 E 相关的音，就可以使用 E minor Blues 音阶进行即兴演奏。&lt;/p&gt;
&lt;p&gt;这种做法常用于布鲁斯、摇滚或流行音乐中，通过加入蓝音（如 A#）来营造独特的情感表达。&lt;/p&gt;
&lt;p&gt;在音乐中，&lt;strong&gt;E major Blues 音阶&lt;/strong&gt;（E 大调蓝调音阶）也是一种常见的音阶，它结合了大调的明亮感和蓝调音乐的独特色彩。下面我们来详细分析它的构成。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;大调蓝调音阶major-blues-scale的构成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#大调蓝调音阶major-blues-scale的构成&#34;&gt;#&lt;/a&gt; 大调蓝调音阶（Major Blues Scale）的构成&lt;/h3&gt;
&lt;p&gt;大调蓝调音阶由 6 个音组成，其公式为：&lt;br&gt;
&lt;strong&gt;1 - 2 - ♭3 - 3 - 5 - 6&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;具体到 &lt;strong&gt;E major Blues 音阶&lt;/strong&gt;，我们以 E 为根音（1），按照上述公式计算每个音的位置：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;1&lt;/strong&gt;：E&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;2&lt;/strong&gt;：F#&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;♭3&lt;/strong&gt;：G （蓝音，Blue Note）&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;3&lt;/strong&gt;：G#&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;5&lt;/strong&gt;：B&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;6&lt;/strong&gt;：C#&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;因此，&lt;strong&gt;E major Blues 音阶&lt;/strong&gt;的组成音为：&lt;br&gt;
&lt;strong&gt;E - F# - G - G# - B - C#&lt;/strong&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;在c调中的应用-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#在c调中的应用-2&#34;&gt;#&lt;/a&gt; 在 C 调中的应用&lt;/h3&gt;
&lt;p&gt;虽然 C 调是以 C 为基准的大调，但在某些情况下可以引入 E major Blues 音阶，尤其是在歌曲中有 E 和弦或与 E 相关的旋律时。这种音阶的使用能够为音乐增添一种活泼、轻松甚至带点 “蓝调” 风味的感觉。&lt;/p&gt;
&lt;p&gt;例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在 C 调的即兴演奏中，如果当前和弦是 E 或 E7，可以使用 E major Blues 音阶。&lt;/li&gt;
&lt;li&gt;蓝音（G）的加入会带来一种轻微的不和谐感，但正是这种不和谐感让蓝调音乐充满魅力。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;总结&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结&#34;&gt;#&lt;/a&gt; 总结&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;E major Blues 音阶&lt;/strong&gt;的组成音是：&lt;br&gt;
&lt;strong&gt;E - F# - G - G# - B - C#&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;这个音阶常用于布鲁斯、摇滚、爵士以及流行音乐中，通过加入蓝音（G）增强了情感表达和音乐张力。&lt;/p&gt;
&lt;p&gt;Dorian 音阶是一种中古调式（教会调式），具有独特的音程结构，常用于爵士、摇滚和民间音乐中。以下是其组成方式的详细说明：&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;1-音程结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-音程结构&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. 音程结构&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;Dorian 音阶的音程排列为（以根音为基准）：&lt;br&gt;
&lt;strong&gt;全音 - 半音 - 全音 - 全音 - 全音 - 半音 - 全音&lt;/strong&gt;&lt;br&gt;
或简化为音级公式：&lt;br&gt;
&lt;strong&gt;1 2 ♭3 4 5 6 ♭7&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;特点&lt;/strong&gt;：
&lt;ul&gt;
&lt;li&gt;小三度（♭3）和大六度（6），使其介于自然小调与混合利底亚调式之间。&lt;/li&gt;
&lt;li&gt;与自然小调（1 2 ♭3 4 5 ♭6 ♭7）相比，第六音升高半音；与自然大调相比，第三音和第七音降低半音。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;2-构建方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-构建方法&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. 构建方法&lt;/strong&gt;&lt;/h3&gt;
&lt;h4 id=&#34;方法一从自然大调推导&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方法一从自然大调推导&#34;&gt;#&lt;/a&gt; &lt;strong&gt;方法一：从自然大调推导&lt;/strong&gt;&lt;/h4&gt;
&lt;p&gt;Dorian 调式是自然大调的第二调式。例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;C 大调音阶&lt;/strong&gt;：C D E F G A B C&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;D Dorian 音阶&lt;/strong&gt;：以 D 为根音，沿用 C 大调音阶的音符 → D E F G A B C D&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;方法二调整自然小调&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方法二调整自然小调&#34;&gt;#&lt;/a&gt; &lt;strong&gt;方法二：调整自然小调&lt;/strong&gt;&lt;/h4&gt;
&lt;p&gt;将自然小调的第六音升高半音：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;D 自然小调&lt;/strong&gt;：D E F G A B♭ C D&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;D Dorian&lt;/strong&gt;：将 B♭变为 B → D E F G A B C D&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;3-实例演示&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-实例演示&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. 实例演示&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;D Dorian 音阶&lt;/strong&gt;：D (1) - E (2) - F (♭3) - G (4) - A (5) - B (6) - C (♭7) - D&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;A Dorian 音阶&lt;/strong&gt;：A - B - C - D - E - F♯ - G - A（对应 G 大调的第二调式）&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;4-应用场景&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-应用场景&#34;&gt;#&lt;/a&gt; &lt;strong&gt;4. 应用场景&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;Dorian 音阶常用于营造神秘、忧郁或爵士色彩的和声环境，例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;爵士乐中的即兴演奏（如《So What》- Miles Davis）。&lt;/li&gt;
&lt;li&gt;摇滚和流行音乐中的小调和声进行（如《Scarborough Fair》）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;通过掌握其结构，你可以在作曲或即兴中灵活运用这一富有表现力的音阶。&lt;/p&gt;
&lt;p&gt;和声小调音阶（Harmonic Minor Scale）是&lt;strong&gt;自然小调音阶的第七级升高半音&lt;/strong&gt;得到的音阶。它的构成方式如下：&lt;/p&gt;
&lt;h3 id=&#34;一-和声小调音阶的结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#一-和声小调音阶的结构&#34;&gt;#&lt;/a&gt; 一、和声小调音阶的结构：&lt;/h3&gt;
&lt;p&gt;从音程上看，&lt;strong&gt;和声小调音阶的音程结构为：&lt;/strong&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;全音 - 半音 - 全音 - 全音 - 半音 - &lt;strong&gt;增二度&lt;/strong&gt; - 半音&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;也就是：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;1 - 2 - b3 - 4 - 5 - b6 - &lt;strong&gt;7&lt;/strong&gt; - 1（高八度）&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;相比自然小调：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;自然小调的第七音是 b7&lt;br&gt;
 和声小调将 b7 升高为 7（大七）&lt;/p&gt;
&lt;/blockquote&gt;
&lt;hr&gt;
&lt;h3 id=&#34;二-举个例子a-和声小调音阶&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#二-举个例子a-和声小调音阶&#34;&gt;#&lt;/a&gt; 二、举个例子：A 和声小调音阶&lt;/h3&gt;
&lt;p&gt;A 自然小调：&lt;br&gt;
A - B - C - D - E - F - G - A（全、半、全、全、半、全、全）&lt;/p&gt;
&lt;p&gt;A 和声小调：&lt;br&gt;
A - B - C - D - E - F - G# - A&lt;br&gt;
（其中 G 升高为 G#）&lt;/p&gt;
&lt;p&gt;音程结构是：&lt;br&gt;
A–B（全）&lt;br&gt;
B–C（半）&lt;br&gt;
C–D（全）&lt;br&gt;
D–E（全）&lt;br&gt;
E–F（半）&lt;br&gt;
F–G#（增二度）&lt;br&gt;
G#–A（半）&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;三-和声小调的作用与特点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三-和声小调的作用与特点&#34;&gt;#&lt;/a&gt; 三、和声小调的作用与特点&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;** 增二度（例如 F 到 G#）** 带来了很强的异国风格（东方或中东风情）&lt;/li&gt;
&lt;li&gt;升高第七音（G#）使主音（A）和属音（E）之间构成一个&lt;strong&gt;真正的属七和弦&lt;/strong&gt;（E7），这对于形成 ** 强烈的回主音感觉（正格终止）** 很有用。&lt;/li&gt;
&lt;li&gt;广泛用于古典音乐、爵士、金属以及中东音乐中。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;p&gt;如果你想我帮你画一个和声小调的音阶图、吉他指板图，或钢琴键盘图，也可以告诉我！&lt;/p&gt;

 &lt;p&gt;Enhancing spatial domain detection in spatial transcriptomics with EnSDD&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;
&lt;details class=&#34;danger&#34;&gt;&lt;summary&gt;先用chatgpt提炼一下要点：&lt;/summary&gt;&lt;div&gt;
&lt;h3 id=&#34;论文要点提炼enhancing-spatial-domain-detection-in-spatial-transcriptomics-with-ensdd&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#论文要点提炼enhancing-spatial-domain-detection-in-spatial-transcriptomics-with-ensdd&#34;&gt;#&lt;/a&gt; 论文要点提炼：《Enhancing Spatial Domain Detection in Spatial Transcriptomics with EnSDD》&lt;/h3&gt;
&lt;h4 id=&#34;1-研究背景&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-研究背景&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. 研究背景&lt;/strong&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;空间转录组学（Spatial Transcriptomics, SRT）帮助理解器官功能和组织微环境，但空间域（spatial domains）的准确识别仍是挑战。&lt;/li&gt;
&lt;li&gt;现有的空间域检测方法（如 BayesSpace、GraphST、STAGATE 等）存在局限，如忽略组织形态信息，或受数据复杂性影响效果不稳定。&lt;/li&gt;
&lt;li&gt;传统方法难以选择最佳的检测方法，因此需要集成学习（ensemble learning）策略来整合多种方法的结果。&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;2-研究目标&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-研究目标&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. 研究目标&lt;/strong&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;提出 &lt;strong&gt;EnSDD (Ensemble-learning for Spatial Domain Detection)&lt;/strong&gt;，整合 8 种先进的空间域检测方法，并使用 &lt;strong&gt;动态加权机制&lt;/strong&gt; 来优化每种方法的贡献。&lt;/li&gt;
&lt;li&gt;该方法可 &lt;strong&gt;自动评估各方法的性能&lt;/strong&gt;，无需依赖人工标注（ground truth）。&lt;/li&gt;
&lt;li&gt;EnSDD 还能够识别 &lt;strong&gt;特定空间域的差异表达基因（SVGs）&lt;/strong&gt; 和 &lt;strong&gt;细胞类型空间分布&lt;/strong&gt;，提供更深层次的组织异质性见解。&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;3-方法创新&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-方法创新&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. 方法创新&lt;/strong&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;动态加权机制&lt;/strong&gt;：EnSDD 通过优化模型自适应地分配各基方法的权重，并生成一个 &lt;strong&gt;共识相似度矩阵（consensus similarity matrix）&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;自动调整聚类参数&lt;/strong&gt;：采用 Louvain 算法的自适应分辨率调整策略，确保聚类结果的优化。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;集成 8 种方法&lt;/strong&gt;：包括 &lt;strong&gt;BayesSpace、DR-SC、GraphST、STAGATE、SpaGCN、stLearn、SiGra 和 spaVAE&lt;/strong&gt;，结合空间坐标、基因表达数据和组织形态图像进行聚类分析。&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;4-主要实验与结果&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-主要实验与结果&#34;&gt;#&lt;/a&gt; &lt;strong&gt;4. 主要实验与结果&lt;/strong&gt;&lt;/h4&gt;
&lt;h5 id=&#34;1-在人类大脑-dlpfc-数据集上的表现&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-在人类大脑-dlpfc-数据集上的表现&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(1) 在人类大脑 DLPFC 数据集上的表现&lt;/strong&gt;&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;EnSDD 在 12 个人类 DLPFC（前额叶皮层）切片上进行测试，结果显示：
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;在大多数切片上表现最佳&lt;/strong&gt;，准确划分了不同皮层层次。&lt;/li&gt;
&lt;li&gt;以 &lt;strong&gt;调整兰德指数（ARI）= 0.637&lt;/strong&gt; 和 &lt;strong&gt;纯度（Purity）= 0.753&lt;/strong&gt; 在部分切片中取得最高聚类准确度。&lt;/li&gt;
&lt;li&gt;与人工标注相比，部分区域的划分更细（如 Layer 3 进一步被细分），表明 EnSDD 具有较强的发现新结构的能力。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;2-在小鼠大脑数据集上的验证&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-在小鼠大脑数据集上的验证&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(2) 在小鼠大脑数据集上的验证&lt;/strong&gt;&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;采用 &lt;strong&gt;Allen Brain Atlas&lt;/strong&gt; 作为参考标准，EnSDD 成功识别出 &lt;strong&gt;大脑皮层 6 层结构、海马 CA1 结构、齿状回（DG）&lt;/strong&gt; 等重要区域。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;相比其他方法更稳定&lt;/strong&gt;，即使调整聚类数量，EnSDD 仍能保持空间域的连贯性，而其他方法如 BayesSpace、stLearn 在某些情况下生成不连续的区域。&lt;/li&gt;
&lt;/ul&gt;
&lt;h5 id=&#34;3-在癌症组织乳腺癌-前列腺癌和卵巢癌上的应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-在癌症组织乳腺癌-前列腺癌和卵巢癌上的应用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(3) 在癌症组织（乳腺癌、前列腺癌和卵巢癌）上的应用&lt;/strong&gt;&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;乳腺癌&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;EnSDD 识别出不同的 &lt;strong&gt;肿瘤区域（IDC、DCIS/LCIS）&lt;/strong&gt; 及肿瘤边缘的细微异质性。&lt;/li&gt;
&lt;li&gt;通过差异基因分析，发现了 &lt;strong&gt;IDC_5 区域的关键基因（如 CSTA、FAM234B、HEBP1）&lt;/strong&gt;，揭示了潜在的肿瘤进展机制。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;肿瘤微环境分析&lt;/strong&gt; 显示，IDC 5 区域的 &lt;strong&gt;巨噬细胞和树突状细胞&lt;/strong&gt; 含量较高，可能与肿瘤免疫逃逸相关。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;前列腺癌&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;成功识别 &lt;strong&gt;肿瘤区域&lt;/strong&gt; 和 &lt;strong&gt;肿瘤边界（ecotone）&lt;/strong&gt;，相比其他方法，EnSDD 更精确地区分了肿瘤与周围组织的异质性。&lt;/li&gt;
&lt;li&gt;发现 &lt;strong&gt;KLK3、TP63、ATG9B&lt;/strong&gt; 等基因在肿瘤边缘具有显著表达变化，可能影响前列腺癌的进展。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;卵巢癌&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;EnSDD 成功检测到 &lt;strong&gt;肿瘤 - 基质交界区（tumor-stroma interface）&lt;/strong&gt;，揭示了肿瘤微环境的复杂性。&lt;/li&gt;
&lt;li&gt;识别的关键基因 &lt;strong&gt;SFRP4、IGKN、THBS1&lt;/strong&gt; 可能与肿瘤侵袭能力相关，提示 EnSDD 可用于肿瘤生物标志物的发现。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;5-贡献与未来展望&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-贡献与未来展望&#34;&gt;#&lt;/a&gt; &lt;strong&gt;5. 贡献与未来展望&lt;/strong&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;EnSDD &lt;strong&gt;比单一方法更稳定&lt;/strong&gt;，可自动评估不同方法的贡献，适用于 &lt;strong&gt;不同类型的组织结构&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;未来可扩展至 &lt;strong&gt;多切片分析（multi-slice analysis）&lt;/strong&gt;，探索组织在多个切片间的连续性。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;结合外部参考数据&lt;/strong&gt; 可能进一步提升 EnSDD 在未知数据集上的适用性。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;总结&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结&#34;&gt;#&lt;/a&gt; &lt;strong&gt;总结&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;这篇论文提出了一种 &lt;strong&gt;基于集成学习的空间域检测方法 EnSDD&lt;/strong&gt;，在多个数据集上表现优异，能更准确地识别 &lt;strong&gt;空间域结构、差异基因和细胞类型分布&lt;/strong&gt;，并适用于 &lt;strong&gt;复杂组织结构及肿瘤微环境研究&lt;/strong&gt;，为空间转录组学分析提供了新的工具。&lt;/p&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;h2 id=&#34;two-main-challenges&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#two-main-challenges&#34;&gt;#&lt;/a&gt; two main challenges:&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;differing base methods may produce varying numbers and types of spatial doamins, complicating the integration of their results&lt;/li&gt;
&lt;li&gt;the performance of methods can vary across datasets, making it difficult to automatically assess and incorporate method performance into the ensemble process.&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;ensddensemble-learning-for-spatial-domain-detection-offers-several-advantages&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ensddensemble-learning-for-spatial-domain-detection-offers-several-advantages&#34;&gt;#&lt;/a&gt; EnSDD(Ensemble-learning for Spatial Domain Detection) offers several advantages:&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;EnSDD adaptively assigns weights to similarity matrices generated by base methods, learning the complete similarity between spots&lt;/li&gt;
&lt;li&gt;the weights assigned by EnSDD provide a reliable metric for evaluating the performance of base SDD methods without requiring ground truth.&lt;/li&gt;
&lt;li&gt;EnSDD offers a comprehensive framework for exploring tissue spatial organization, including the identification of spatial domains, determination of domain-specific SVGs, and inference of cell type distribution&lt;/li&gt;
&lt;li&gt;it includes well-documented tutorials and an interative platform to facilitate implementation and visualization.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/EnSDD1.png&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;大概概括一下整个流程：&lt;br&gt;
首先将各种各样的数据输入进模型，这个模型下的 8 个 base methods 会生成结果，然后右图的那个代表 0，1 的矩阵的意思是两个 spot 之间是否属于一个 cluster，通过使用这些矩阵，EnSDD 会运用一个优化模型去决定最终的 similarity matrix，并且把可自适应的权重分给 base method，然后这些权重便成为了衡量 base method 的方式。最终 EnSDD 运用 Louvain 算法去最终决定 spatial domains。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/EnSDD2.png&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;EnSDD offers two approaches for identifying SVGs:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;one involves detecting domain-specific differentially expressed genes(DEGs)&lt;/li&gt;
&lt;li&gt;other identifies gene with expression patterns with expression patterns correlated to spatial locations&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/EnSDD3.png&#34; alt&gt;&lt;br&gt;
&lt;img data-src=&#34;https://amentirazblogpic.oss-cn-hangzhou.aliyuncs.com/blogpic/EnSDD4.png&#34; alt&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;在科研中，gold standard 指的是被广泛接受、被认为是最准确和权威的 “真值” 或参考数据，通常由专家通过严格的人工注释获得。例如，在前列腺癌数据中，病理学家提供的肿瘤和肿瘤边缘区域标注就被视为 gold standard，用来评估算法的准确性。而 silver standard 则是指在没有绝对完美的 gold standard 时使用的参考数据，这类数据虽然不是最完美的，但仍能作为一个有用的基准来评价方法的表现。例如，在某些小鼠大脑数据中，Allen Brain Atlas 被用作 silver standard。总体来说，gold standard 是最理想的标准，而 silver standard 则是在实际条件下的一个次优但可接受的替代。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;针对乳腺癌数据板块的对于 cell proportion 的分析可以借鉴一下&lt;/p&gt;
&lt;details class=&#34;danger&#34;&gt;&lt;summary&gt;其它的集成学习方法&lt;/summary&gt;&lt;div&gt;
&lt;p&gt;STAMarker 和 SC3 都是利用集成学习思想的聚类方法，但它们应用的场景和侧重点有所不同：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;SC3&lt;/strong&gt; 是一种用于单细胞 RNA 测序（scRNA-seq）数据聚类的方法。它通过整合多个聚类结果得到多个二元相似度矩阵，然后利用层次聚类生成最终的细胞分类结果。这种方法能够整合不同算法的信息，从而获得更稳健的聚类结果。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;STAMarker&lt;/strong&gt; 则主要用于空间转录组学数据中的空间域检测。它计算不同聚类结果中任意两个空间点共同归入同一空间域的比例，形成一个连接矩阵，再利用层次聚类或 Louvain 算法来进行标签分配，从而识别出具有生物学意义的空间域。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这两种方法都是通过集成多种聚类结果来提高整体的准确性和稳健性，但 SC3 更侧重于单细胞数据的细胞分类，而 STAMarker 则专注于空间域的划分。&lt;/p&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;h2 id=&#34;methods部分&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#methods部分&#34;&gt;#&lt;/a&gt; Methods 部分&lt;/h2&gt;
&lt;p&gt;在 Methods 部分，作者主要介绍了 EnSDD 模型的构建和求解方法，其中核心在于如何将来自多个基础空间域检测方法（如 BayesSpace、DR-SC、GraphST、STAGATE、SpaGCN、stLearn、SiGra 和 spaVAE）得到的二值相似矩阵进行加权融合，进而生成一个共识相似矩阵 S，从而指导后续的空间域划分。下面详细说明公式部分的主要内容：&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;1-二值相似矩阵构造&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-二值相似矩阵构造&#34;&gt;#&lt;/a&gt; 1. 二值相似矩阵构造&lt;/h3&gt;
&lt;p&gt;对于每个基础方法 m（m = 1, …, M，默认 M = 8），根据其聚类结果构造一个二值相似矩阵 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S^{(m)}&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8879999999999999em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8879999999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mopen mtight&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mclose mtight&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;。具体来说，对于任意两个点 i 和 j，如果它们在方法 m 中被划分到同一聚类，则 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S^{(m)}(i, j) = 1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.138em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8879999999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mopen mtight&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mclose mtight&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;；否则为 0。这一步的目的在于将各方法的聚类结果以矩阵的形式表达出来。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;2-优化模型与加权融合公式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-优化模型与加权融合公式&#34;&gt;#&lt;/a&gt; 2. 优化模型与加权融合公式&lt;/h3&gt;
&lt;p&gt;为了整合这些基础方法得到的相似矩阵，作者提出了如下优化问题：&lt;/p&gt;
\begin{align}
\min_{S, \{\omega_m\}} \quad \sum_{m=1}^{M} \omega_m \|S - S^{(m)}\|_F^2 + \lambda \sum_{m=1}^{M} \omega_m \log \omega_m
\end{align}
\begin{align}
\text{subject to} \quad \sum_{m=1}^{M} \omega_m = 1, \quad \omega_m \geq 0 \quad (m=1,\ldots,M)
\end{align}
&lt;p&gt;其中：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;S&lt;/strong&gt; 是待学习的共识相似矩阵。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;S^(m)&lt;/strong&gt; 是第 m 个基础方法构造的二值相似矩阵。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mo&gt;⋅&lt;/mo&gt;&lt;msubsup&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mi&gt;F&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msubsup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\|\cdot\|_F^2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;⋅&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.089439em;vertical-align:-0.275331em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8141079999999999em;&#34;&gt;&lt;span style=&#34;top:-2.424669em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.13889em;&#34;&gt;F&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.275331em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 表示矩阵的 Frobenius 范数的平方，即衡量两个矩阵之间的欧氏距离。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 是分配给第 m 个基础方法的权重，这些权重反映了每个方法在当前数据集上的表现好坏。直观上，表现较好的方法会获得较大的权重，使得共识矩阵 S 与该方法的 S^(m) 更加接近。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;λ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\lambda&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;λ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 是调节负熵正则化项的参数。正则化项 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;λ&lt;/mi&gt;&lt;msubsup&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;mrow&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;/msubsup&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;log&lt;/mi&gt;&lt;mo&gt;⁡&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\lambda \sum_{m=1}^{M} \omega_m \log \omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.2809409999999999em;vertical-align:-0.29971000000000003em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;λ&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.981231em;&#34;&gt;&lt;span style=&#34;top:-2.40029em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mrel mtight&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.2029em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.29971000000000003em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;lo&lt;span style=&#34;margin-right:0.01389em;&#34;&gt;g&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的引入能够防止权重过于集中在某一个方法上，从而避免过拟合。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;公式解析：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;第一项：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msubsup&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;mrow&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;/msubsup&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;msubsup&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mi&gt;F&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msubsup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sum_{m=1}^{M} \omega_m \|S - S^{(m)}\|_F^2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.2809409999999999em;vertical-align:-0.29971000000000003em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.981231em;&#34;&gt;&lt;span style=&#34;top:-2.40029em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mrel mtight&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.2029em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.29971000000000003em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.163331em;vertical-align:-0.275331em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8879999999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mopen mtight&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mclose mtight&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8141079999999999em;&#34;&gt;&lt;span style=&#34;top:-2.424669em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.13889em;&#34;&gt;F&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.275331em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;br&gt;
 这部分计算了共识矩阵 S 与每个基础方法的相似矩阵之间的加权差异。对每个方法 m，距离越小表明 S 更接近于该方法的结果，且这个距离由相应的权重 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 加权求和。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;第二项：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;λ&lt;/mi&gt;&lt;msubsup&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;mrow&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;/msubsup&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;log&lt;/mi&gt;&lt;mo&gt;⁡&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\lambda \sum_{m=1}^{M} \omega_m \log \omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.2809409999999999em;vertical-align:-0.29971000000000003em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;λ&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.981231em;&#34;&gt;&lt;span style=&#34;top:-2.40029em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mrel mtight&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.2029em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.29971000000000003em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;lo&lt;span style=&#34;margin-right:0.01389em;&#34;&gt;g&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;br&gt;
 这是一个负熵正则化项，它在优化过程中会鼓励权重分布更加平滑，防止某个方法的权重过大。这里的 λ 控制了正则化的强度，当 λ 较大时，权重分布会更加均衡；当 λ 较小时，可能会倾向于将大部分权重赋予表现最好的方法。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;约束条件：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msubsup&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;mrow&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;/msubsup&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sum_{m=1}^{M} \omega_m = 1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.2809409999999999em;vertical-align:-0.29971000000000003em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.981231em;&#34;&gt;&lt;span style=&#34;top:-2.40029em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mrel mtight&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.2029em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.29971000000000003em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 且 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;≥&lt;/mo&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m \geq 0&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.7859700000000001em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;≥&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;br&gt;
 这保证了所有权重构成一个概率分布，即所有权重之和为 1，并且每个权重都是非负的。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;作者采用坐标下降算法来求解这个优化问题，即交替优化 S 与 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的值。最终得到的共识相似矩阵 S 能够更准确地反映各基础方法综合后的空间点相似性，同时各 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 也可作为评估各基础方法在特定数据集上表现的指标。&lt;/p&gt;
&lt;hr&gt;
&lt;details class=&#34;danger&#34;&gt;&lt;summary&gt;第一项偏导&lt;/summary&gt;&lt;div&gt;
&lt;p&gt;这是一个经典的&lt;strong&gt;带权 Frobenius 距离最小化问题&lt;/strong&gt;，常出现在集成学习、矩阵逼近或多视图聚类中。你问的是下面这个优化目标：&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;优化问题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#优化问题&#34;&gt;#&lt;/a&gt; 📌 优化问题&lt;/h3&gt;
\begin{equation}
\min_{S, \{\omega_m\}} \quad \sum_{m=1}^{M} \omega_m \|S - S^{(m)}\|_F^2
\end{equation}
&lt;p&gt;其中：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是你要求解的&lt;strong&gt;集成矩阵&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是每个 base 矩阵的权重（你暂时是常数或已知的情况下求偏导）&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;mo&gt;∈&lt;/mo&gt;&lt;msup&gt;&lt;mi mathvariant=&#34;double-struck&#34;&gt;R&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S^{(m)} \in \mathbb{R}^{n \times n}&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.9270999999999999em;vertical-align:-0.0391em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8879999999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mopen mtight&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mclose mtight&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;∈&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.771331em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathbb&#34;&gt;R&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.771331em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mbin mtight&#34;&gt;×&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;n&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是第 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个给定的相似度矩阵&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mo&gt;⋅&lt;/mo&gt;&lt;msub&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mi&gt;F&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\| \cdot \|_F&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;⋅&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.13889em;&#34;&gt;F&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 表示 Frobenius 范数&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;要求&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#要求&#34;&gt;#&lt;/a&gt; 🎯 要求：&lt;/h3&gt;
&lt;p&gt;你现在是想&lt;strong&gt;对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 求偏导数&lt;/strong&gt;，也就是：&lt;/p&gt;
\begin{equation}
\frac{\partial}{\partial S} \left( \sum_{m=1}^{M} \omega_m \|S - S^{(m)}\|_F^2 \right)
\end{equation}
&lt;hr&gt;
&lt;h3 id=&#34;计算步骤&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计算步骤&#34;&gt;#&lt;/a&gt; 🧮 计算步骤&lt;/h3&gt;
&lt;p&gt;我们知道：&lt;/p&gt;
\begin{equation}
\|A\|_F^2 = \sum_{i,j} A_{ij}^2 = \operatorname{Tr}(A^\top A)
\end{equation}
&lt;p&gt;所以每一项：&lt;/p&gt;
\begin{equation}
\|S - S^{(m)}\|_F^2 = \operatorname{Tr}\left((S - S^{(m)})^\top (S - S^{(m)})\right)
\end{equation}
&lt;p&gt;对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 求导的标准结果是：&lt;/p&gt;
\begin{equation}
\frac{\partial}{\partial S} \|S - S^{(m)}\|_F^2 = 2(S - S^{(m)})
\end{equation}
&lt;hr&gt;
&lt;h3 id=&#34;于是整体偏导为&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#于是整体偏导为&#34;&gt;#&lt;/a&gt; 🧾 于是整体偏导为：&lt;/h3&gt;
\begin{equation}
\frac{\partial}{\partial S} \sum_{m=1}^{M} \omega_m \|S - S^{(m)}\|_F^2 = \sum_{m=1}^{M} \omega_m \cdot 2(S - S^{(m)})
= 2 \sum_{m=1}^{M} \omega_m (S - S^{(m)})
\end{equation}
&lt;hr&gt;
&lt;h3 id=&#34;最终结果&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最终结果&#34;&gt;#&lt;/a&gt; ✅ 最终结果：&lt;/h3&gt;
\begin{equation}
\frac{\partial}{\partial S} \left( \sum_{m=1}^{M} \omega_m \|S - S^{(m)}\|_F^2 \right)
= 2 \sum_{m=1}^{M} \omega_m (S - S^{(m)})
\end{equation}
&lt;hr&gt;
&lt;h3 id=&#34;如果你要最小化它只需让偏导为-0&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#如果你要最小化它只需让偏导为-0&#34;&gt;#&lt;/a&gt; 💡 如果你要最小化它，只需让偏导为 0：&lt;/h3&gt;
\begin{equation}
\sum_{m=1}^{M} \omega_m (S - S^{(m)}) = 0
\quad \Rightarrow \quad
S = \sum_{m=1}^{M} \omega_m S^{(m)}
\end{equation}
&lt;p&gt;也就是说，&lt;strong&gt;最优解 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 是所有矩阵的 &lt;strong&gt;加权平均&lt;/strong&gt;！&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;需要我帮你把这推导写成 LaTeX 公式或加到你自己的代码推导里也可以继续说哈～&lt;/p&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;details class=&#34;danger&#34;&gt;&lt;summary&gt;第二项偏导&lt;/summary&gt;&lt;div&gt;
&lt;p&gt;太好了！你这个问题非常经典，咱们现在就来一步步推导怎么用 &lt;strong&gt;Lagrange 乘子法&lt;/strong&gt;（Lagrange multipliers）来求解权重 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的最优解。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;你给的目标函数是&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#你给的目标函数是&#34;&gt;#&lt;/a&gt; 🔢 你给的目标函数是：&lt;/h2&gt;
\begin{equation}
\min_{\{ \omega_m \}} \quad \sum_{m=1}^M \omega_m \| S - S^{(m)} \|_F^2 + \lambda \sum_{m=1}^M \omega_m \log \omega_m
\end{equation}
&lt;p&gt;带有约束：&lt;/p&gt;
\begin{equation}
\sum_{m=1}^M \omega_m = 1, \quad \omega_m \geq 0
\end{equation}
&lt;p&gt;其中 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是固定的（或者在交替优化里暂时固定），所以我们只针对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 来优化。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;️-第一步写出-lagrangian-拉格朗日函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#️-第一步写出-lagrangian-拉格朗日函数&#34;&gt;#&lt;/a&gt; ✏️ 第一步：写出 Lagrangian 拉格朗日函数&lt;/h2&gt;
&lt;p&gt;为了处理约束 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sum \omega_m = 1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.00001em;vertical-align:-0.25001em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，引入拉格朗日乘子 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;μ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\mu&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.625em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;μ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，构造：&lt;/p&gt;
\begin{equation}
\mathcal{L}(\omega_1, \ldots, \omega_M, \mu) = \sum_{m=1}^M \omega_m \| S - S^{(m)} \|_F^2 + \lambda \sum_{m=1}^M \omega_m \log \omega_m - \mu \left( \sum_{m=1}^M \omega_m - 1 \right)
\end{equation}
&lt;hr&gt;
&lt;h2 id=&#34;第二步对每个-omega_m-求偏导数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第二步对每个-omega_m-求偏导数&#34;&gt;#&lt;/a&gt; 🧮 第二步：对每个 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 求偏导数&lt;/h2&gt;
&lt;p&gt;我们令每个偏导为 0：&lt;/p&gt;
\begin{equation}
\frac{\partial \mathcal{L}}{\partial \omega_m} = \| S - S^{(m)} \|_F^2 + \lambda(1 + \log \omega_m) - \mu = 0
\end{equation}
&lt;p&gt;整理一下：&lt;/p&gt;
\begin{equation}
\lambda \log \omega_m = \mu - \lambda - \| S - S^{(m)} \|_F^2
\end{equation}
&lt;p&gt;再除以 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;λ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\lambda&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;λ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 并指数两边：&lt;/p&gt;
\begin{equation}
\log \omega_m = \frac{\mu - \lambda - \| S - S^{(m)} \|_F^2}{\lambda}
\Rightarrow \omega_m = \exp\left( \frac{\mu - \lambda - \| S - S^{(m)} \|_F^2}{\lambda} \right)
\end{equation}
&lt;p&gt;整理一下：&lt;/p&gt;
\begin{equation}
\omega_m = C \cdot \exp\left( -\frac{1}{\lambda} \| S - S^{(m)} \|_F^2 \right)
\end{equation}
&lt;p&gt;其中 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;exp&lt;/mi&gt;&lt;mo&gt;⁡&lt;/mo&gt;&lt;mrow&gt;&lt;mo fence=&#34;true&#34;&gt;(&lt;/mo&gt;&lt;mfrac&gt;&lt;mrow&gt;&lt;mi&gt;μ&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mi&gt;λ&lt;/mi&gt;&lt;/mrow&gt;&lt;mi&gt;λ&lt;/mi&gt;&lt;/mfrac&gt;&lt;mo fence=&#34;true&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;C = \exp\left( \frac{\mu - \lambda}{\lambda} \right)&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.80002em;vertical-align:-0.65002em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;exp&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;minner&#34;&gt;&lt;span class=&#34;mopen delimcenter&#34; style=&#34;top:0em;&#34;&gt;&lt;span class=&#34;delimsizing size2&#34;&gt;(&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mopen nulldelimiter&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mfrac&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.9322159999999999em;&#34;&gt;&lt;span style=&#34;top:-2.6550000000000002em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;λ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.23em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;frac-line&#34; style=&#34;border-bottom-width:0.04em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.446108em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;μ&lt;/span&gt;&lt;span class=&#34;mbin mtight&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;λ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.345em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose nulldelimiter&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose delimcenter&#34; style=&#34;top:0em;&#34;&gt;&lt;span class=&#34;delimsizing size2&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是一个&lt;strong&gt;所有 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的共同常数&lt;/strong&gt;。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;第三步用约束条件求出-c&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第三步用约束条件求出-c&#34;&gt;#&lt;/a&gt; ✅ 第三步：用约束条件求出 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;C&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;由于所有 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 要满足：&lt;/p&gt;
\begin{equation}
\sum_{m=1}^M \omega_m = 1
\end{equation}
&lt;p&gt;我们将上面形式代入得：&lt;/p&gt;
\begin{equation}
\sum_{m=1}^M C \cdot \exp\left( -\frac{1}{\lambda} \| S - S^{(m)} \|_F^2 \right) = 1
\Rightarrow
C = \frac{1}{\sum_{m=1}^M \exp\left( -\frac{1}{\lambda} \| S - S^{(m)} \|_F^2 \right)}
\end{equation}
&lt;hr&gt;
&lt;h2 id=&#34;最终结果-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最终结果-2&#34;&gt;#&lt;/a&gt; 🎉 最终结果：&lt;/h2&gt;
\begin{equation}
\boxed{
\omega_m = \frac{ \exp\left( -\frac{1}{\lambda} \| S - S^{(m)} \|_F^2 \right) }{ \sum_{j=1}^M \exp\left( -\frac{1}{\lambda} \| S - S^{(j)} \|_F^2 \right) }
}
\end{equation}
&lt;p&gt;这其实就是一个 &lt;strong&gt;softmax&lt;/strong&gt; 形式！每个 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S^{(m)}&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8879999999999999em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8879999999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mopen mtight&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mclose mtight&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的一个相似度评分（用负的距离衡量），用 softmax 来归一化。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;补充说明&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#补充说明&#34;&gt;#&lt;/a&gt; 📌 补充说明&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;如果 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;λ&lt;/mi&gt;&lt;mo&gt;→&lt;/mo&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\lambda \to 0&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;λ&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;→&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;：权重趋向于 “winner takes all”（只选最小误差的那个）&lt;/li&gt;
&lt;li&gt;如果 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;λ&lt;/mi&gt;&lt;mo&gt;→&lt;/mo&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∞&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\lambda \to \infty&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;λ&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;→&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∞&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;：所有权重接近均匀平均&lt;/li&gt;
&lt;li&gt;这个方法就是你之前代码中那个权重更新公式的数学基础&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;p&gt;如果你想我也可以帮你推对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;S&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的梯度，或者画图解释这个 softmax 权重的直觉含义 😄 想继续哪一块？&lt;/p&gt;
&lt;p&gt;当然可以！我们就专注于这一步：&lt;strong&gt;如何对每个 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 求偏导数&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;你给的函数是：&lt;/p&gt;
\begin{equation}
\mathcal{L}(\omega_1, \ldots, \omega_M, \mu) = \sum_{m=1}^M \omega_m \|S - S^{(m)}\|_F^2 + \lambda \sum_{m=1}^M \omega_m \log \omega_m - \mu \left( \sum_{m=1}^M \omega_m - 1 \right)
\end{equation}
&lt;p&gt;我们现在只关注其中一个 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，要对它&lt;strong&gt;求偏导数&lt;/strong&gt;。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;拆开看mathcall-对于单个-omega_m-是&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#拆开看mathcall-对于单个-omega_m-是&#34;&gt;#&lt;/a&gt; 🔍 拆开看，(\mathcal {L}) 对于单个 (\omega_m) 是：&lt;/h2&gt;
&lt;p&gt;选定一个 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，(\mathcal {L}$ 中关于 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的部分是：&lt;/p&gt;
\begin{equation}
\omega_m \|S - S^{(m)}\|_F^2 + \lambda \omega_m \log \omega_m - \mu \omega_m
\end{equation}
&lt;p&gt;这是三项：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;线性项：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;msubsup&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mi&gt;F&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msubsup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m \|S - S^{(m)}\|_F^2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.163331em;vertical-align:-0.275331em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8879999999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mopen mtight&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mclose mtight&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8141079999999999em;&#34;&gt;&lt;span style=&#34;top:-2.424669em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.13889em;&#34;&gt;F&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.275331em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;熵正则项：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;λ&lt;/mi&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;log&lt;/mi&gt;&lt;mo&gt;⁡&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\lambda \omega_m \log \omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;λ&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;lo&lt;span style=&#34;margin-right:0.01389em;&#34;&gt;g&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;约束乘子项：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mi&gt;μ&lt;/mi&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;-\mu \omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.7777700000000001em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;μ&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;hr&gt;
&lt;h2 id=&#34;逐项对-omega_m-求导&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逐项对-omega_m-求导&#34;&gt;#&lt;/a&gt; 🧮 逐项对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 求导&lt;/h2&gt;
&lt;h3 id=&#34;第一项&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第一项&#34;&gt;#&lt;/a&gt; 第一项：&lt;/h3&gt;
\begin{equation}
\frac{\partial}{\partial \omega_m} \left( \omega_m \cdot \|S - S^{(m)}\|_F^2 \right) = \|S - S^{(m)}\|_F^2
\end{equation}
&lt;p&gt;这是因为 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;msubsup&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;∥&lt;/mi&gt;&lt;mi&gt;F&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msubsup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\|S - S^{(m)}\|_F^2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.163331em;vertical-align:-0.275331em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8879999999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mopen mtight&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mclose mtight&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;∥&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8141079999999999em;&#34;&gt;&lt;span style=&#34;top:-2.424669em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.13889em;&#34;&gt;F&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.275331em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是常数，对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega_m&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.151392em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;m&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 直接是乘法。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;第二项关键点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第二项关键点&#34;&gt;#&lt;/a&gt; 第二项（关键点）：&lt;/h3&gt;
\begin{equation}
\frac{\partial}{\partial \omega_m} \left( \omega_m \log \omega_m \right)
\end{equation}
&lt;p&gt;我们来慢慢推一下这个常见表达式的导数：&lt;/p&gt;
&lt;p&gt;令：&lt;/p&gt;
\begin{equation}
f(\omega) = \omega \log \omega
\end{equation}
&lt;p&gt;用乘积法则：&lt;/p&gt;
\begin{equation}
f&#39;(\omega) = \frac{d}{d\omega} \omega \cdot \log \omega = 1 \cdot \log \omega + \omega \cdot \frac{1}{\omega} = \log \omega + 1
\end{equation}
&lt;p&gt;所以：&lt;/p&gt;
\begin{equation}
\frac{\partial}{\partial \omega_m} \left( \lambda \omega_m \log \omega_m \right) = \lambda (\log \omega_m + 1)
\end{equation}
&lt;hr&gt;
&lt;h3 id=&#34;第三项&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第三项&#34;&gt;#&lt;/a&gt; 第三项：&lt;/h3&gt;
\begin{equation}
\frac{\partial}{\partial \omega_m} (-\mu \omega_m) = -\mu
\end{equation}
&lt;hr&gt;
&lt;h2 id=&#34;把三项加起来得到偏导&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#把三项加起来得到偏导&#34;&gt;#&lt;/a&gt; 🔚 把三项加起来，得到偏导：&lt;/h2&gt;
\begin{equation}
\frac{\partial \mathcal{L}}{\partial \omega_m} = \|S - S^{(m)}\|_F^2 + \lambda (\log \omega_m + 1) - \mu
\end{equation}
&lt;p&gt;然后我们令偏导为 0，得到最优条件：&lt;/p&gt;
\begin{equation}
\|S - S^{(m)}\|_F^2 + \lambda (\log \omega_m + 1) - \mu = 0
\end{equation}
&lt;p&gt;就是我们之前推导的式子啦！&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;总结一下你学到什么&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结一下你学到什么&#34;&gt;#&lt;/a&gt; 🎯 总结一下你学到什么：&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;log&lt;/mi&gt;&lt;mo&gt;⁡&lt;/mo&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\omega \log \omega&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;lo&lt;span style=&#34;margin-right:0.01389em;&#34;&gt;g&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 求导是 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;log&lt;/mi&gt;&lt;mo&gt;⁡&lt;/mo&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\log \omega + 1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;lo&lt;span style=&#34;margin-right:0.01389em;&#34;&gt;g&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;（这是熵类正则常见的导数）&lt;/li&gt;
&lt;li&gt;在加权平均里用 softmax，其实就是从这个偏导数出发&lt;/li&gt;
&lt;li&gt;拉格朗日乘子 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;μ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\mu&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.625em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;μ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 用于处理总和为 1 的约束&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;p&gt;如果你想，我还可以做成一张「可视化推导卡片」，更方便你日后复习！要不要试试？&lt;/p&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;h3 id=&#34;3-空间域的划分&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-空间域的划分&#34;&gt;#&lt;/a&gt; 3. 空间域的划分&lt;/h3&gt;
&lt;p&gt;得到共识相似矩阵 S 后，EnSDD 进一步使用 Louvain 算法进行社区发现（即聚类），并通过自适应分辨率调整（利用二分搜索确定最佳分辨率参数），将 SRT 数据中的点划分为不同的空间域。这样既能保证空间域的连贯性，也能在预设的聚类数下获得较优的划分结果。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;4-后续分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-后续分析&#34;&gt;#&lt;/a&gt; 4. 后续分析&lt;/h3&gt;
&lt;p&gt;在共识相似矩阵和空间域划分的基础上，EnSDD 还进一步进行：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;差异表达基因（SVGs）的识别&lt;/strong&gt;：利用 Wilcoxon 检验比较各空间域之间的基因表达水平，识别出在特定空间域中具有显著表达变化的基因。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;局部空间自相关分析&lt;/strong&gt;：采用 Local Getis and Ord’s Gi 统计量，评估基因表达在局部空间内的聚集或分散趋势，从而揭示基因的空间自相关特征。&lt;/li&gt;
&lt;/ul&gt;
&lt;details class=&#34;danger&#34;&gt;&lt;summary&gt;SA&lt;/summary&gt;&lt;div&gt;
&lt;h3 id=&#34;空间自相关spatial-auto-correlation-sa的使用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#空间自相关spatial-auto-correlation-sa的使用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;空间自相关（Spatial Auto-correlation, SA）的使用&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;在 EnSDD 研究中，空间自相关用于分析 &lt;strong&gt;基因表达在空间上的依赖性&lt;/strong&gt;，即在组织切片中，基因的表达水平是否在空间上呈现聚集或分散模式。这有助于识别 &lt;strong&gt;空间可变基因（SVGs, Spatially Variable Genes）&lt;/strong&gt;，即在特定空间区域内具有特定表达模式的基因。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;1-什么是空间自相关&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-什么是空间自相关&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. 什么是空间自相关？&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;空间自相关（SA）是指某一变量（这里是基因表达水平）在空间上的分布模式是否表现出 &lt;strong&gt;相似性或相关性&lt;/strong&gt;。一般来说：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;正空间自相关（Positive SA）&lt;/strong&gt;：相邻位置的基因表达水平相似，呈现聚集模式。例如，在大脑皮层某个区域，如果某个基因的表达量高，其周围位置的表达量也较高。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;负空间自相关（Negative SA）&lt;/strong&gt;：相邻位置的基因表达水平相反，呈现分散模式。例如，某些基因在神经组织和周围支持细胞中表现出相反的表达模式。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;EnSDD 采用 &lt;strong&gt;Local Getis and Ord’s Gi 统计量&lt;/strong&gt; 来定量衡量某个基因在局部空间中的自相关性。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;2-local-getis-and-ords-g_i-统计量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-local-getis-and-ords-g_i-统计量&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. Local Getis and Ord’s &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 统计量&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;EnSDD 通过 &lt;strong&gt;Local Getis and Ord’s &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 统计量来评估基因表达的空间聚集性。这一统计量用于衡量每个基因在空间中的局部自相关性，数学表达如下：&lt;/p&gt;
\begin{align}
G_i(k) = \frac{\sum\limits_{j} c_{ij}(k) x_j - V_i \mu}{\sigma \left\{(n-1)B_{1i} - V_i^2\right\}^{1/2}}, \quad i \neq j
\end{align}
&lt;p&gt;其中：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;x_j&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.716668em;vertical-align:-0.286108em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.311664em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.286108em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：第 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;j&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.85396em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个空间点的基因表达水平。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;μ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\mu&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.625em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;μ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;, &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;σ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sigma&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;σ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：所有空间点（去除第 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.65952em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个点）的基因表达的均值和标准差。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;c_{ij}(k)&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.036108em;vertical-align:-0.286108em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.311664em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.286108em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03148em;&#34;&gt;k&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：空间权重矩阵，表示空间点 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.65952em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 与 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;j&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.85396em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 之间的距离权重（例如，最近的 k 个点的权重为 1，其余为 0）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;V&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;msub&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;/msub&gt;&lt;msub&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;V_i = \sum_j c_{ij}&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;V&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.22222em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.185818em;vertical-align:-0.43581800000000004em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.16195399999999993em;&#34;&gt;&lt;span style=&#34;top:-2.40029em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.43581800000000004em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.311664em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.286108em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：第 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.65952em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个点的总空间权重。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mrow&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;msub&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;/msub&gt;&lt;msubsup&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;/mrow&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msubsup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;B_{1i} = \sum_j c_{ij}^2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.05017em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.2499259999999999em;vertical-align:-0.43581800000000004em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.16195399999999993em;&#34;&gt;&lt;span style=&#34;top:-2.40029em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.43581800000000004em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8141079999999999em;&#34;&gt;&lt;span style=&#34;top:-2.441336em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.394772em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：空间权重的平方和。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;n&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：所有空间点的总数。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;解释：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果 &lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 值 &lt;strong&gt;大于 0&lt;/strong&gt;，表示该基因的高表达区域在局部空间中聚集（正空间自相关）。&lt;/li&gt;
&lt;li&gt;如果 &lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 值 &lt;strong&gt;小于 0&lt;/strong&gt;，表示该基因在该区域的表达呈现离散模式（负空间自相关）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;EnSDD 采用 &lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;6&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;k = 6&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03148em;&#34;&gt;k&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;6&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 作为最近邻窗口大小，计算基因在每个空间点上的 &lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 统计量，并使用 &lt;strong&gt;Wilcoxon 检验&lt;/strong&gt; 进一步确认哪些基因在特定空间域上表现出显著的空间可变性。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;3-sa-在-ensdd-中的应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-sa-在-ensdd-中的应用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. SA 在 EnSDD 中的应用&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;EnSDD 主要利用 &lt;strong&gt;Local Getis and Ord’s &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 统计量来：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;筛选空间可变基因（SVGs）&lt;/strong&gt;：识别在不同空间域（Spatial Domain）中表达模式具有明显局部聚集或分散特征的基因。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;分析组织结构中的基因表达模式&lt;/strong&gt;：
&lt;ul&gt;
&lt;li&gt;例如，在 &lt;strong&gt;人类 DLPFC（前额叶皮层）数据&lt;/strong&gt; 中，EnSDD 发现 &lt;strong&gt;Layer 3 被进一步细分&lt;/strong&gt;，并通过 &lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 统计量证实该区域内确实存在两个不同的基因表达聚集区域。&lt;/li&gt;
&lt;li&gt;在 &lt;strong&gt;乳腺癌数据&lt;/strong&gt; 中，利用 &lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 统计量找到了一些 &lt;strong&gt;与癌症进展相关的特异性基因（如 HEBP1、FAM234B、CSTA）&lt;/strong&gt;，它们在某些肿瘤区域内高度聚集。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;hr&gt;
&lt;h2 id=&#34;4-具体实现&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-具体实现&#34;&gt;#&lt;/a&gt; &lt;strong&gt;4. 具体实现&lt;/strong&gt;&lt;/h2&gt;
&lt;h3 id=&#34;步骤-1计算局部空间自相关&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#步骤-1计算局部空间自相关&#34;&gt;#&lt;/a&gt; &lt;strong&gt;步骤 1：计算局部空间自相关&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;对于每个基因：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;构建 &lt;strong&gt;空间权重矩阵&lt;/strong&gt;，选取最近的 &lt;strong&gt;6 个相邻点&lt;/strong&gt; 作为参考。&lt;/li&gt;
&lt;li&gt;计算 &lt;strong&gt;每个点的 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 统计量&lt;/strong&gt;，得到基因的局部空间聚集度信息。&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;步骤-2wilcoxon-检验&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#步骤-2wilcoxon-检验&#34;&gt;#&lt;/a&gt; &lt;strong&gt;步骤 2：Wilcoxon 检验&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;对比不同空间域之间的基因表达水平，检验在某个空间域中是否存在显著表达变化的基因。&lt;/p&gt;
&lt;h3 id=&#34;步骤-3可视化和分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#步骤-3可视化和分析&#34;&gt;#&lt;/a&gt; &lt;strong&gt;步骤 3：可视化和分析&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;局部空间自相关（SA）热图&lt;/strong&gt;：展示不同基因在不同空间点上的 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 值，识别高表达聚集区域。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;空间表达模式图&lt;/strong&gt;：在组织切片上可视化基因的表达水平，观察其空间分布。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;5-实例解析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-实例解析&#34;&gt;#&lt;/a&gt; &lt;strong&gt;5. 实例解析&lt;/strong&gt;&lt;/h2&gt;
&lt;h3 id=&#34;案例-1人类前额叶皮层dlpfc&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#案例-1人类前额叶皮层dlpfc&#34;&gt;#&lt;/a&gt; &lt;strong&gt;案例 1：人类前额叶皮层（DLPFC）&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;在 DLPFC 数据集中，EnSDD 发现：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在某些切片中，&lt;strong&gt;Layer 3 被自动分成两个子区域&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;通过 &lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 统计量计算，发现 &lt;strong&gt;129 个基因在这两个子区域的表达显著不同&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;进一步分析发现这些基因 &lt;strong&gt;与神经功能和甲状腺癌相关&lt;/strong&gt;，揭示了 Layer 3 内部可能存在未被人工标注的异质性。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;案例-2乳腺癌肿瘤区域&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#案例-2乳腺癌肿瘤区域&#34;&gt;#&lt;/a&gt; &lt;strong&gt;案例 2：乳腺癌肿瘤区域&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;EnSDD 识别了 &lt;strong&gt;肿瘤中心区域（IDC_5）&lt;/strong&gt; 和 &lt;strong&gt;周围免疫浸润区域&lt;/strong&gt;，并通过 &lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 统计量找到了一组特异性基因：
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;在 IDC_5 高表达的基因&lt;/strong&gt;：HEBP1（与乳腺癌进展相关）&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;在肿瘤边界高表达的基因&lt;/strong&gt;：FAM234B（与肿瘤免疫浸润相关）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这些基因的空间表达模式揭示了 &lt;strong&gt;不同肿瘤区域的分子特征和潜在生物学机制&lt;/strong&gt;，并可能成为新的肿瘤治疗靶点。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;6-总结&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6-总结&#34;&gt;#&lt;/a&gt; &lt;strong&gt;6. 总结&lt;/strong&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;空间自相关（SA）是 EnSDD 识别空间可变基因（SVGs）的关键步骤&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Local Getis and Ord’s &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; 统计量用于衡量基因在局部空间的聚集或分散模式。&lt;/li&gt;
&lt;li&gt;通过 SA 分析，EnSDD 发现了新的 &lt;strong&gt;组织异质性&lt;/strong&gt;，并揭示了 &lt;strong&gt;肿瘤微环境&lt;/strong&gt; 中的关键分子特征。&lt;/li&gt;
&lt;li&gt;该方法在 &lt;strong&gt;人类大脑 DLPFC、小鼠大脑、乳腺癌、前列腺癌和卵巢癌&lt;/strong&gt; 数据中均表现良好，能够有效提升空间转录组数据的生物学解释能力。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;如果你对实现细节或代码感兴趣，可以让我帮你进一步解析如何在 Python 或 R 中实现 Local Getis and Ord’s &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 统计量计算！🚀&lt;/p&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;details class=&#34;danger&#34;&gt;&lt;summary&gt;RCTD&lt;/summary&gt;&lt;div&gt;
&lt;h3 id=&#34;rctdrobust-cell-type-decomposition&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rctdrobust-cell-type-decomposition&#34;&gt;#&lt;/a&gt; &lt;strong&gt;RCTD（Robust Cell Type Decomposition）&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;在 EnSDD 研究中，&lt;strong&gt;RCTD（Robust Cell Type Decomposition）&lt;/strong&gt; 主要用于 &lt;strong&gt;推测空间转录组数据（SRT）中的细胞类型组成&lt;/strong&gt;，即利用 &lt;strong&gt;单细胞转录组测序（scRNA-seq）数据&lt;/strong&gt; 作为参考，对空间转录组数据中的每个 spot 进行 &lt;strong&gt;细胞类型分解（deconvolution）&lt;/strong&gt;。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;1-什么是-rctd&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-什么是-rctd&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. 什么是 RCTD？&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;RCTD&lt;/strong&gt; 是一种 &lt;strong&gt;基于权重优化的去卷积方法&lt;/strong&gt;，用于从空间转录组数据中估计每个 spot（空间点）中 &lt;strong&gt;不同细胞类型的组成比例&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;在空间转录组数据（SRT）中，每个 spot 包含多个细胞的混合信号，而单细胞 RNA 测序（scRNA-seq）数据可以提供 &lt;strong&gt;单细胞级别的基因表达信息&lt;/strong&gt;。RCTD 通过匹配 SRT 和 scRNA-seq 数据，&lt;strong&gt;估算每个 spot 内不同细胞类型的比例&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;关键思想：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;输入数据：&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;空间转录组数据（SRT）&lt;/strong&gt;：基因表达矩阵，每个 spot 可能包含多个细胞的混合基因表达。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;单细胞 RNA-seq 数据（scRNA-seq）&lt;/strong&gt;：提供每种细胞类型的基因表达模式。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;输出数据：&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;每个 spot 内部的 &lt;strong&gt;细胞类型组成比例&lt;/strong&gt;，例如：&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Spot 1: 70% 肿瘤细胞, 20% 巨噬细胞, 10% 成纤维细胞&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Spot 2: 50% 神经元, 30% 星形胶质细胞, 20% 少突胶质细胞&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;应用场景：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;分析肿瘤微环境（TME）&lt;/strong&gt;，推测肿瘤区域内不同免疫细胞的分布情况。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;探索大脑结构&lt;/strong&gt;，研究不同皮层层次的细胞组成差异。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;研究发育过程&lt;/strong&gt;，分析不同组织区域的细胞类型变化。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;2-rctd-计算过程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-rctd-计算过程&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. RCTD 计算过程&lt;/strong&gt;&lt;/h2&gt;
&lt;h3 id=&#34;1-计算细胞类型的特征&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-计算细胞类型的特征&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(1) 计算细胞类型的 “特征”&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;RCTD 通过 scRNA-seq 数据，获取每种细胞类型的特征基因表达模式。例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;细胞类型 A：基因 1 高表达，基因 2 低表达。&lt;/li&gt;
&lt;li&gt;细胞类型 B：基因 1 低表达，基因 2 高表达。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这些信息用于 &lt;strong&gt;构建细胞类型的特征矩阵&lt;/strong&gt;。&lt;/p&gt;
&lt;h3 id=&#34;2-计算-srt-数据中每个-spot-的基因表达模式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-计算-srt-数据中每个-spot-的基因表达模式&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(2) 计算 SRT 数据中每个 spot 的基因表达模式&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;每个 spot 含有多个细胞，因此它的基因表达是 &lt;strong&gt;所有细胞类型的混合&lt;/strong&gt;。RCTD 需要解出每个 spot 内 &lt;strong&gt;不同细胞类型的贡献比例&lt;/strong&gt;。&lt;/p&gt;
&lt;h3 id=&#34;3-通过权重优化分解细胞类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-通过权重优化分解细胞类型&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(3) 通过权重优化分解细胞类型&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;RCTD 假设 SRT 中每个 spot 的基因表达 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;X&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;X&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07847em;&#34;&gt;X&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 由 &lt;strong&gt;不同细胞类型的加权平均表达&lt;/strong&gt; 组成：&lt;/p&gt;
\begin{align}
X = W \cdot C + \epsilon
\end{align}
&lt;p&gt;其中：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;X&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;X&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07847em;&#34;&gt;X&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是 SRT 数据的基因表达矩阵（待解）。&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;C&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是 scRNA-seq 参考数据中每种细胞类型的基因表达模式（已知）。&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;W&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;W&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是权重矩阵（待求解），表示每种细胞类型在每个 spot 的贡献比例。&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;ϵ&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\epsilon&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.43056em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;ϵ&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是噪声项。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;RCTD 采用 &lt;strong&gt;贝叶斯方法 + 线性优化&lt;/strong&gt; 来求解 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;W&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;W&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，从而估计每个 spot 内部的细胞类型组成。&lt;/p&gt;
&lt;h3 id=&#34;4-归一化-计算细胞类型分布&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-归一化-计算细胞类型分布&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(4) 归一化 &amp;amp; 计算细胞类型分布&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;为了确保所有细胞类型的比例总和为 1，RCTD 进行归一化处理，最终输出每个 spot 的细胞组成。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;3-rctd-在-ensdd-研究中的应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-rctd-在-ensdd-研究中的应用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. RCTD 在 EnSDD 研究中的应用&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;EnSDD 通过 RCTD 进行细胞类型推测，帮助分析 &lt;strong&gt;不同空间域的细胞组成&lt;/strong&gt;，特别是在 &lt;strong&gt;肿瘤微环境分析&lt;/strong&gt; 方面表现突出。例如：&lt;/p&gt;
&lt;h3 id=&#34;1-在乳腺癌数据中的应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-在乳腺癌数据中的应用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(1) 在乳腺癌数据中的应用&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;目标&lt;/strong&gt;：分析肿瘤中心（IDC_5）与肿瘤边缘的细胞类型组成差异。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;结果&lt;/strong&gt;：
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;IDC_5 肿瘤中心&lt;/strong&gt;：癌细胞比例高，免疫细胞（如巨噬细胞、树突状细胞）比例低。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;肿瘤边缘区域&lt;/strong&gt;：免疫细胞（如巨噬细胞和树突状细胞）显著富集，可能与 &lt;strong&gt;肿瘤免疫逃逸机制&lt;/strong&gt; 相关。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;细胞比例结果（示例）：&lt;/strong&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Spot&lt;/th&gt;
&lt;th&gt;癌细胞&lt;/th&gt;
&lt;th&gt;巨噬细胞&lt;/th&gt;
&lt;th&gt;树突状细胞&lt;/th&gt;
&lt;th&gt;CD4+ T 细胞&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;1&lt;/td&gt;
&lt;td&gt;70%&lt;/td&gt;
&lt;td&gt;10%&lt;/td&gt;
&lt;td&gt;10%&lt;/td&gt;
&lt;td&gt;10%&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;2&lt;/td&gt;
&lt;td&gt;40%&lt;/td&gt;
&lt;td&gt;30%&lt;/td&gt;
&lt;td&gt;20%&lt;/td&gt;
&lt;td&gt;10%&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;2-在前列腺癌数据中的应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-在前列腺癌数据中的应用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(2) 在前列腺癌数据中的应用&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;目标&lt;/strong&gt;：研究肿瘤区域（Tumor）和肿瘤边界（Ecotone）的细胞类型差异。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;结果&lt;/strong&gt;：
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;肿瘤区域&lt;/strong&gt;：以 &lt;strong&gt;LE-KLK3 阳性上皮细胞&lt;/strong&gt; 为主。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;肿瘤边界（Ecotone）&lt;/strong&gt;：更高比例的 &lt;strong&gt;免疫细胞（MNP 和 B 细胞）&lt;/strong&gt;，可能影响肿瘤的进展和免疫治疗反应。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3-在卵巢癌数据中的应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-在卵巢癌数据中的应用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(3) 在卵巢癌数据中的应用&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;目标&lt;/strong&gt;：分析肿瘤、肿瘤 - 基质交界（Ecotone）和基质区域的细胞组成。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;结果&lt;/strong&gt;：
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;肿瘤区域&lt;/strong&gt;：EOC（上皮性卵巢癌细胞）占比高。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;肿瘤 - 基质交界&lt;/strong&gt;：富含 &lt;strong&gt;上皮细胞、成纤维细胞（CAFs）、间皮细胞&lt;/strong&gt;，可能在肿瘤侵袭过程中发挥作用。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h2 id=&#34;4-rctd-与其他方法的对比&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-rctd-与其他方法的对比&#34;&gt;#&lt;/a&gt; &lt;strong&gt;4. RCTD 与其他方法的对比&lt;/strong&gt;&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;方法&lt;/th&gt;
&lt;th&gt;原理&lt;/th&gt;
&lt;th&gt;适用数据&lt;/th&gt;
&lt;th&gt;主要特点&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;RCTD&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;基于权重优化的细胞去卷积&lt;/td&gt;
&lt;td&gt;scRNA-seq + SRT&lt;/td&gt;
&lt;td&gt;计算准确，适用于高噪声数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;Seurat (SPOTlight)&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;线性回归 + NMF&lt;/td&gt;
&lt;td&gt;scRNA-seq + SRT&lt;/td&gt;
&lt;td&gt;适用于简单组织&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;Stereoscope&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;贝叶斯概率模型&lt;/td&gt;
&lt;td&gt;scRNA-seq + SRT&lt;/td&gt;
&lt;td&gt;适用于大规模数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;Cell2location&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;空间层次贝叶斯模型&lt;/td&gt;
&lt;td&gt;scRNA-seq + SRT&lt;/td&gt;
&lt;td&gt;适用于大规模数据，推测稀有细胞类型&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;相比 Seurat 和 Stereoscope，&lt;strong&gt;RCTD 对噪声的鲁棒性更强，适用于高复杂度的组织，如癌症组织和大脑皮层&lt;/strong&gt;。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;5-结论&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-结论&#34;&gt;#&lt;/a&gt; &lt;strong&gt;5. 结论&lt;/strong&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;RCTD 用于估计 SRT 数据中每个 spot 的细胞组成&lt;/strong&gt;，帮助 EnSDD 解析不同空间域的细胞类型分布。&lt;/li&gt;
&lt;li&gt;通过 &lt;strong&gt;scRNA-seq 参考数据&lt;/strong&gt;，RCTD 能够揭示 &lt;strong&gt;肿瘤微环境、神经组织层次结构等&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;在 &lt;strong&gt;乳腺癌、前列腺癌、卵巢癌&lt;/strong&gt; 数据中，RCTD 发现了 &lt;strong&gt;肿瘤 - 免疫相互作用的关键特征&lt;/strong&gt;，有助于癌症生物标志物发现和治疗策略优化。&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;details class=&#34;danger&#34;&gt;&lt;summary&gt;RCTD&lt;/summary&gt;&lt;div&gt;
&lt;h3 id=&#34;puritypur纯度&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#puritypur纯度&#34;&gt;#&lt;/a&gt; &lt;strong&gt;Purity（Pur，纯度）&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;Purity（纯度）&lt;/strong&gt; 是一个用于评估聚类（Clustering）质量的指标，衡量聚类结果与真实类别标签（Ground Truth）的一致性。它的取值范围为 &lt;strong&gt;$$\begin{align}0, 1\end{align}$$&lt;/strong&gt;，值越高，表示聚类结果越接近真实分类。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;1-purity-公式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-purity-公式&#34;&gt;#&lt;/a&gt; &lt;strong&gt;1. Purity 公式&lt;/strong&gt;&lt;/h2&gt;
\begin{align}
\text{Purity} = \frac{1}{N} \sum_{l=1}^{L} \max_{t} |u_l \cap v_t|
\end{align}
&lt;p&gt;其中：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;N&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：样本总数（数据点总数）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;L&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;L&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;L&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：预测聚类的数量（即 EnSDD 识别出的空间域数）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;T&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：真实类别（Ground Truth）数量（如人工标注的组织结构）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;u_l&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.33610799999999996em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：第 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;l&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个预测聚类（即 EnSDD 识别出的某个空间域）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;v&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;v_t&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;v&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2805559999999999em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;：第 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;t&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.61508em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个真实类别（如已知组织切片的层级）。&lt;/li&gt;
