&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;解释：&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;对于每个预测的聚类&lt;/strong&gt; &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;u_l&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.33610799999999996em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，找出其中占比最多的真实类别 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;v&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;v_t&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;v&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2805559999999999em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;求所有预测聚类的占比最多真实类别样本数的总和&lt;/strong&gt;，并除以总样本数 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;N&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，得到纯度值。&lt;/li&gt;
&lt;/ol&gt;
&lt;hr&gt;
&lt;h2 id=&#34;2-purity-计算示例&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-purity-计算示例&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2. Purity 计算示例&lt;/strong&gt;&lt;/h2&gt;
&lt;h3 id=&#34;1-示例数据&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-示例数据&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(1) 示例数据&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;假设我们有 10 个数据点，它们的真实类别（Ground Truth）和聚类算法（如 EnSDD）给出的预测聚类如下：&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;数据点编号&lt;/th&gt;
&lt;th&gt;真实类别 (Ground Truth)&lt;/th&gt;
&lt;th&gt;预测聚类 (Clustering)&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;1&lt;/td&gt;
&lt;td&gt;A&lt;/td&gt;
&lt;td&gt;1&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;2&lt;/td&gt;
&lt;td&gt;A&lt;/td&gt;
&lt;td&gt;1&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;3&lt;/td&gt;
&lt;td&gt;A&lt;/td&gt;
&lt;td&gt;2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;4&lt;/td&gt;
&lt;td&gt;B&lt;/td&gt;
&lt;td&gt;2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;5&lt;/td&gt;
&lt;td&gt;B&lt;/td&gt;
&lt;td&gt;2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;6&lt;/td&gt;
&lt;td&gt;B&lt;/td&gt;
&lt;td&gt;3&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;7&lt;/td&gt;
&lt;td&gt;C&lt;/td&gt;
&lt;td&gt;3&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;8&lt;/td&gt;
&lt;td&gt;C&lt;/td&gt;
&lt;td&gt;3&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;9&lt;/td&gt;
&lt;td&gt;C&lt;/td&gt;
&lt;td&gt;3&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;10&lt;/td&gt;
&lt;td&gt;C&lt;/td&gt;
&lt;td&gt;3&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;2-计算每个聚类的最大类别&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-计算每个聚类的最大类别&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(2) 计算每个聚类的最大类别&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;聚类 1（u₁）&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;真实类别 A：2 个&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;最大类别：A（2）&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;聚类 2（u₂）&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;真实类别 A：1 个&lt;/li&gt;
&lt;li&gt;真实类别 B：2 个&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;最大类别：B（2）&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;聚类 3（u₃）&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;真实类别 B：1 个&lt;/li&gt;
&lt;li&gt;真实类别 C：4 个&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;最大类别：C（4）&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3-计算-purity&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-计算-purity&#34;&gt;#&lt;/a&gt; &lt;strong&gt;(3) 计算 Purity&lt;/strong&gt;&lt;/h3&gt;
\begin{align}
\text{Purity} = \frac{2 + 2 + 4}{10} = \frac{8}{10} = 0.8
\end{align}
&lt;hr&gt;
&lt;h2 id=&#34;3-purity-在-ensdd-论文中的应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-purity-在-ensdd-论文中的应用&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3. Purity 在 EnSDD 论文中的应用&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;在 EnSDD 研究中，Purity 主要用于 &lt;strong&gt;评估空间域划分（Spatial Domain Detection）的准确性&lt;/strong&gt;，即检查 EnSDD 生成的空间域与人工标注的组织结构（如大脑层次结构或肿瘤组织分区）的匹配程度。&lt;/p&gt;
&lt;h3 id=&#34;实验结果示例&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实验结果示例&#34;&gt;#&lt;/a&gt; &lt;strong&gt;实验结果示例&lt;/strong&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;在 &lt;strong&gt;人类大脑 DLPFC 数据集&lt;/strong&gt; 中：
&lt;ul&gt;
&lt;li&gt;EnSDD 纯度（Purity）= &lt;strong&gt;0.704&lt;/strong&gt;，优于 STAGATE（0.678）和 spaVAE（0.672）。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;在 &lt;strong&gt;乳腺癌数据&lt;/strong&gt; 中：
&lt;ul&gt;
&lt;li&gt;EnSDD 纯度（Purity）= &lt;strong&gt;0.668&lt;/strong&gt;，高于其他方法。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这些结果表明，EnSDD 生成的空间域划分与真实组织结构的匹配度较高，能够更好地识别不同的组织区域。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;4-purity-与-adjusted-rand-indexari的区别&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-purity-与-adjusted-rand-indexari的区别&#34;&gt;#&lt;/a&gt; &lt;strong&gt;4. Purity 与 Adjusted Rand Index（ARI）的区别&lt;/strong&gt;&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;指标&lt;/th&gt;
&lt;th&gt;适用情况&lt;/th&gt;
&lt;th&gt;计算方法&lt;/th&gt;
&lt;th&gt;取值范围&lt;/th&gt;
&lt;th&gt;主要特点&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;Purity（纯度）&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;评估聚类质量&lt;/td&gt;
&lt;td&gt;计算每个预测聚类中最大类别样本数的比例&lt;/td&gt;
&lt;td&gt;&lt;strong&gt;[0,1]&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;直观易懂，但不能惩罚错误分类&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;ARI（调整兰德指数）&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;评估聚类与真实类别的一致性&lt;/td&gt;
&lt;td&gt;计算正确分类与随机分类的差值&lt;/td&gt;
&lt;td&gt;&lt;strong&gt;[-1,1]&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;适用于类数量不均衡的数据，惩罚错误分类&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;strong&gt;总结：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Purity 直观易懂，适合快速评估聚类质量&lt;/strong&gt;，但它 &lt;strong&gt;不考虑错误分类的影响&lt;/strong&gt;，如果一个大类被错误拆分成多个小类，Purity 仍然可能较高。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;ARI 更加严格&lt;/strong&gt;，它不仅考虑正确分类，还会对错误分类进行惩罚，因此对于聚类方法的评估更为精确。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;在 EnSDD 论文中，&lt;strong&gt;Purity 和 ARI 一起使用&lt;/strong&gt;，以确保空间域检测方法的可靠性。&lt;/p&gt;
&lt;hr&gt;
&lt;h2 id=&#34;5-结论-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-结论-2&#34;&gt;#&lt;/a&gt; &lt;strong&gt;5. 结论&lt;/strong&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Purity 衡量聚类质量，数值越高，说明 EnSDD 预测的空间域更接近真实组织结构。&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;与 ARI 结合使用时，Purity 提供直观的匹配度衡量，而 ARI 可检测错误分类的影响。&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;在 EnSDD 研究中，Purity 证明了该方法比 STAGATE、spaVAE 等方法具有更好的空间域检测能力。&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;如果你想了解 &lt;strong&gt;代码如何计算 Purity&lt;/strong&gt; 或者 &lt;strong&gt;如何优化空间域划分算法&lt;/strong&gt;，可以告诉我，我可以进一步解析！&lt;/p&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;hr&gt;
&lt;h3 id=&#34;总结-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结-2&#34;&gt;#&lt;/a&gt; 总结&lt;/h3&gt;
&lt;p&gt;在 Methods 部分，论文的关键在于如何将来自不同方法的聚类结果转化为二值相似矩阵，并利用上述优化模型进行加权融合，生成一个能够反映综合信息的共识相似矩阵。通过引入负熵正则化项，模型在防止过拟合的同时，也为各基础方法赋予了合理的权重。最终，这一共识相似矩阵被用来指导 Louvain 算法实现空间域的自动划分，进而为后续的基因表达和细胞类型分布分析提供基础。&lt;/p&gt;
&lt;h1 id=&#34;代码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#代码&#34;&gt;#&lt;/a&gt; 代码&lt;/h1&gt;
&lt;p&gt;由于代码是 R 语言书写的，不熟悉的地方很多，特此全面的记录解读一番。&lt;/p&gt;
&lt;h2 id=&#34;run_individual_clustering&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#run_individual_clustering&#34;&gt;#&lt;/a&gt; run_individual_clustering&lt;/h2&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;apply_BayesSpace &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; platform &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Visium&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; n.PCs &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;15&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; n.HVGs &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;2000&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                             n.setting &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; nrep &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;50000&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;### extract dataset&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  exp_data &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;list&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;counts &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; as.matrix&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;assays&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;SCT&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;counts&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; logcounts &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; as.matrix&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;assays&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;SCT&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;data&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  df &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; Seurat.data&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;meta.data&lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;x&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;y&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;pixel_x&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;pixel_y&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  temp_colnames &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; colnames&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;df&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  temp_colnames &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; sub&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;x&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;row&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; temp_colnames&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  temp_colnames &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; sub&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;y&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;col&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; temp_colnames&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  colnames&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;df&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; temp_colnames&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sce &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; SingleCellExperiment&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;SingleCellExperiment&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;assay &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; exp_data&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; colData &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; df&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  dec &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; scran&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;modelGeneVar&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  top &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; scran&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;getTopHVGs&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;dec&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; n &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; n.HVGs&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  set.seed&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;102&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sce &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; scater&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;runPCA&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; subset_row&lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;top&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sce &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; BayesSpace&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;spatialPreprocess&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; platform&lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;platform&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; skip.PCA&lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;literal&#34;&gt;TRUE&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;platform &lt;span class=&#34;operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Visium&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;gamma&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; 3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;platform &lt;span class=&#34;operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;ST&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;built_in&#34;&gt;gamma&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; 2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  set.seed&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;150&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;# if(is.choose.n.cell.type)&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#   sce &amp;lt;- BayesSpace::qTune(sce = sce, qs = seq(n.min, n.max), platform = platform, nrep = nrep, gamma = gamma)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#   logliks &amp;lt;- attr(sce, &amp;quot;q.logliks&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#   opt_k &amp;lt;- logliks$q[which(logliks$loglik == max(logliks$loglik))]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#   sce &amp;lt;- BayesSpace::spatialCluster(sce = sce, q = opt_k, platform = platform, nrep = nrep, gamma = gamma)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#   #BayesSpace::clusterPlot(sce)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#   res.cluster &amp;lt;- sce$spatial.cluster&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#   names(res.cluster) &amp;lt;- rownames(sce@colData)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;# &amp;#125;else&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sce &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; BayesSpace&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;spatialCluster&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; sce&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; q &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; n.setting&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; d &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; n.PCs&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; platform &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; platform&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; nrep &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; nrep&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;gamma&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;gamma&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;# BayesSpace::clusterPlot(sce)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  res.cluster &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; sce&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;spatial.cluster&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;names&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res.cluster&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; rownames&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;colData&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;# &amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;return&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res.cluster&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;details class=&#34;danger&#34;&gt;&lt;summary&gt;BayesSpace&lt;/summary&gt;&lt;div&gt;
&lt;p&gt;当然可以，我们来&lt;strong&gt;逐行解读&lt;/strong&gt;这个  &lt;code&gt;apply_BayesSpace&lt;/code&gt;  函数。它的功能是：在一个  &lt;code&gt;Seurat&lt;/code&gt;  对象上使用  &lt;code&gt;BayesSpace&lt;/code&gt;  包进行&lt;strong&gt;空间转录组聚类分析&lt;/strong&gt;。你这段代码流程很完整，也有些细节挺有意思，我会分块讲解，穿插解释函数作用和每一步背后的意图。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;函数定义和参数说明&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#函数定义和参数说明&#34;&gt;#&lt;/a&gt; 🧠 函数定义和参数说明：&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;apply_BayesSpace &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; platform &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Visium&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; n.PCs &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;15&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; n.HVGs &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;2000&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                             n.setting &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; nrep &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;50000&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Seurat.data&lt;/code&gt; ：传入一个处理过的 Seurat 对象，假设已经做完 SCTransform。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;platform&lt;/code&gt; ：平台类型，如  &lt;code&gt;&amp;quot;Visium&amp;quot;&lt;/code&gt;  或  &lt;code&gt;&amp;quot;ST&amp;quot;&lt;/code&gt; （决定空间结构等处理方式）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;n.PCs&lt;/code&gt; ：PCA 主成分数量，默认为 15。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;n.HVGs&lt;/code&gt; ：选择前多少个高变基因（Highly Variable Genes）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;n.setting&lt;/code&gt; ：聚类数量，即  &lt;code&gt;q&lt;/code&gt;  值，默认是 7 类。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;nrep&lt;/code&gt; ：MCMC 采样的迭代次数，BayesSpace 聚类时使用，默认 50000。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;步骤一从-seurat-对象中提取数据&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#步骤一从-seurat-对象中提取数据&#34;&gt;#&lt;/a&gt; 📦 步骤一：从 Seurat 对象中提取数据&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;exp_data &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;list&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;counts &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; as.matrix&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;assays&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;SCT&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;counts&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                 logcounts &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; as.matrix&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;assays&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;SCT&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;data&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;提取标准化前后的表达矩阵：
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;counts&lt;/code&gt; : 原始计数&lt;/li&gt;
&lt;li&gt;&lt;code&gt;logcounts&lt;/code&gt; : SCT 标准化后的 log-scale 表达值&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;df &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; Seurat.data&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;meta.data&lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;x&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;y&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;pixel_x&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;pixel_y&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;从元数据中提取空间坐标。&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;temp_colnames &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; colnames&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;df&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;temp_colnames &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; sub&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;x&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;row&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; temp_colnames&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;temp_colnames &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; sub&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;y&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;col&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; temp_colnames&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;colnames&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;df&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; temp_colnames&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;BayesSpace&lt;/code&gt;  需要用  &lt;code&gt;row&lt;/code&gt; ,  &lt;code&gt;col&lt;/code&gt;  命名空间位置，所以这里做了列名替换。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;步骤二构造-singlecellexperiment-对象&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#步骤二构造-singlecellexperiment-对象&#34;&gt;#&lt;/a&gt; 📦 步骤二：构造  &lt;code&gt;SingleCellExperiment&lt;/code&gt;  对象&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sce &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; SingleCellExperiment&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;SingleCellExperiment&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;assay &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; exp_data&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; colData &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; df&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;创建一个符合 Bioconductor 标准的数据容器，包含表达矩阵和元数据。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;BayesSpace&lt;/code&gt;  是以  &lt;code&gt;SingleCellExperiment&lt;/code&gt;  为输入格式。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;步骤三寻找高变基因并-pca&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#步骤三寻找高变基因并-pca&#34;&gt;#&lt;/a&gt; 📈 步骤三：寻找高变基因并 PCA&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;dec &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; scran&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;modelGeneVar&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;top &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; scran&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;getTopHVGs&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;dec&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; n &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; n.HVGs&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;用  &lt;code&gt;scran&lt;/code&gt;  估计每个基因的变异程度，选择前  &lt;code&gt;n.HVGs&lt;/code&gt;  个变异最大的基因（通常对降维和聚类效果好）。&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;set.seed&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;102&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sce &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; scater&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;runPCA&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; subset_row&lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;top&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;在 top HVGs 上做 PCA 降维。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;步骤四预处理空间信息&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#步骤四预处理空间信息&#34;&gt;#&lt;/a&gt; 🧼 步骤四：预处理空间信息&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sce &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; BayesSpace&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;spatialPreprocess&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; platform&lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;platform&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; skip.PCA&lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;literal&#34;&gt;TRUE&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;执行  &lt;code&gt;BayesSpace&lt;/code&gt;  所需的空间预处理：
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;skip.PCA=TRUE&lt;/code&gt;  表示我们已经做过 PCA，不重复。&lt;/li&gt;
&lt;li&gt;添加空间网格、邻接矩阵等结构信息。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;️-步骤五设置-gamma-超参数平台特异&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#️-步骤五设置-gamma-超参数平台特异&#34;&gt;#&lt;/a&gt; 🎚️ 步骤五：设置  &lt;code&gt;gamma&lt;/code&gt;  超参数（平台特异）&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;platform &lt;span class=&#34;operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Visium&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;gamma&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; 3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;platform &lt;span class=&#34;operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;ST&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;gamma&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; 2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;gamma&lt;/code&gt;  是 BayesSpace 聚类模型的平滑参数，控制聚类边界的 “平滑程度”。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;步骤六执行-bayesspace-聚类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#步骤六执行-bayesspace-聚类&#34;&gt;#&lt;/a&gt; 🔁 步骤六：执行 BayesSpace 聚类&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;set.seed&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;150&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sce &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; BayesSpace&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;spatialCluster&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; sce&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; q &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; n.setting&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; d &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; n.PCs&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                  platform &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; platform&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; nrep &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; nrep&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;gamma&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;gamma&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;开始空间聚类：
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;q&lt;/code&gt; : 聚类的簇数&lt;/li&gt;
&lt;li&gt;&lt;code&gt;d&lt;/code&gt; : 使用的 PCA 数量（如前 15 个）&lt;/li&gt;
&lt;li&gt;&lt;code&gt;nrep&lt;/code&gt; : MCMC 迭代次数（越多越稳定但越慢）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;步骤七提取聚类结果&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#步骤七提取聚类结果&#34;&gt;#&lt;/a&gt; 📊 步骤七：提取聚类结果&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;res.cluster &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; sce&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;spatial.cluster&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;names&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res.cluster&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; rownames&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;sce&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;colData&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;聚类结果是一个向量（每个 spot 的聚类标签）。&lt;/li&gt;
&lt;li&gt;给结果加上对应 spot 的名字。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;注释掉的代码自动寻找最佳聚类数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#注释掉的代码自动寻找最佳聚类数&#34;&gt;#&lt;/a&gt; 🔁（注释掉的代码）自动寻找最佳聚类数&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# sce &amp;lt;- BayesSpace::qTune(...) &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# opt_k &amp;lt;- ...&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# sce &amp;lt;- BayesSpace::spatialCluster(q = opt_k, ...)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;这段注释代码原本用于自动寻找最优  &lt;code&gt;q&lt;/code&gt;  值（聚类数），通过比较对数似然。但作者这里选择手动设定  &lt;code&gt;n.setting&lt;/code&gt; 。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;返回结果&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#返回结果&#34;&gt;#&lt;/a&gt; 🔚 返回结果&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;return&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res.cluster&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;返回一个聚类结果向量，用户可以根据它进行可视化、下游分析等。&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;总结一句话&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结一句话&#34;&gt;#&lt;/a&gt; ✅ 总结一句话：&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;这个函数将 Seurat 对象转换为  &lt;code&gt;SingleCellExperiment&lt;/code&gt; ，挑选高变基因做 PCA，然后用  &lt;code&gt;BayesSpace&lt;/code&gt;  进行空间聚类分析，并返回每个 spot 的聚类标签。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;hr&gt;
&lt;p&gt;你可以配合  &lt;code&gt;BayesSpace::clusterPlot(sce)&lt;/code&gt;  进行可视化，也可以把这个结果加到 Seurat 对象里，继续做差异分析。&lt;/p&gt;
&lt;p&gt;如果你还想了解聚类原理或者对某个包函数不理解，可以继续问我！&lt;/p&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;apply_SpaGCN &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; SpaGCN_beta &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;55&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; SpaGCN_alpha &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; SpaGCN_p &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0.5&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         SpaGCN_l &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0.5&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; num.cluster &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; res.setting &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; SpaGCN_lr &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0.05&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         SpaGCN_epoches &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;200&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; platform &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Visium&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  temp &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; Seurat.data&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;images&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  counts_path &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;counts_path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  meta_path &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;loc_path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  img_path &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;img_path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;### for install python scripts in R package&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;# EnSDD_pyexec(pyfile = system.file(&amp;quot;python&amp;quot;, &amp;quot;apply_spaGCN.py&amp;quot;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#                                   package = &amp;quot;EnSDD&amp;quot;))&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  reticulate&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;source_python&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;system.file&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;python&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;apply_spaGCN.py&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                    package &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;EnSDD&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;# reticulate::source_python(&amp;#x27;/home/vision/Downloads/LHS/EnDecon/EnSDD/inst/python/apply_spaGCN.py&amp;#x27;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  run_spaGCN&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;counts_path&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; meta_path&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; img_path&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; platform &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; platform&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; res_setting_by_user &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; res.setting&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             b &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;as.integer&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;SpaGCN_beta&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; a &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; SpaGCN_alpha&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; p &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; SpaGCN_p&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             n_clusters &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;as.integer&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;num.cluster&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; lr &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; SpaGCN_lr&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             max_epochs &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;as.integer&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;SpaGCN_epoches&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  res.path &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; paste0&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;dirname&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;img_path&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;/spaGCN_res&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;/spaGCN_label.txt&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  res_temp &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; read.table&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res.path&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; sep &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;\t&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  res &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; res_temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;V2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;names&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; res_temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;V1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;built_in&#34;&gt;sum&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res &lt;span class=&#34;operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;!=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    res &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; res &lt;span class=&#34;operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  res &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; res&lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;colnames&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  unlink&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;paste0&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;dirname&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;img_path&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;/spaGCN_res&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; recursive&lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;literal&#34;&gt;TRUE&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;built_in&#34;&gt;return&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;details class=&#34;danger&#34;&gt;&lt;summary&gt;SpaGCN&lt;/summary&gt;&lt;div&gt;
&lt;p&gt;当然可以！下面我来&lt;strong&gt;逐行解读&lt;/strong&gt;这段  &lt;code&gt;apply_SpaGCN&lt;/code&gt;  函数的 R 代码。这段代码的功能是：调用 Python 实现的 &lt;strong&gt;SpaGCN&lt;/strong&gt; 空间聚类算法，并返回聚类结果。它通过  &lt;code&gt;reticulate&lt;/code&gt;  接口从 R 中运行 Python 脚本。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;函数定义及参数说明&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#函数定义及参数说明&#34;&gt;#&lt;/a&gt; 🧠 函数定义及参数说明&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;apply_SpaGCN &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         SpaGCN_beta &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;55&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         SpaGCN_alpha &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         SpaGCN_p &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0.5&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         SpaGCN_l &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0.5&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         num.cluster &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         res.setting &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         SpaGCN_lr &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0.05&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         SpaGCN_epoches &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;200&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                         platform &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Visium&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Seurat.data&lt;/code&gt; : Seurat 对象（空间数据），包含图像路径信息&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SpaGCN_beta&lt;/code&gt; ,  &lt;code&gt;SpaGCN_alpha&lt;/code&gt; ,  &lt;code&gt;SpaGCN_p&lt;/code&gt; ,  &lt;code&gt;SpaGCN_l&lt;/code&gt; : 是 SpaGCN 聚类算法的超参数，控制空间权重、邻域强度等&lt;/li&gt;
&lt;li&gt;&lt;code&gt;num.cluster&lt;/code&gt; : 聚类簇数量&lt;/li&gt;
&lt;li&gt;&lt;code&gt;res.setting&lt;/code&gt; : 聚类分辨率设置（用户自定义）&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SpaGCN_lr&lt;/code&gt; : 学习率&lt;/li&gt;
&lt;li&gt;&lt;code&gt;SpaGCN_epoches&lt;/code&gt; : 训练迭代次数&lt;/li&gt;
&lt;li&gt;&lt;code&gt;platform&lt;/code&gt; : 平台，如 &amp;quot;Visium&amp;quot;，决定空间坐标解读方式&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;1-提取图像路径&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-提取图像路径&#34;&gt;#&lt;/a&gt; 📦 1. 提取图像路径&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;temp &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; Seurat.data&lt;span class=&#34;operator&#34;&gt;@&lt;/span&gt;images&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;counts_path &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;counts_path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;meta_path &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;loc_path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;img_path &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;img_path&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;假设  &lt;code&gt;Seurat.data@images&lt;/code&gt;  存放了一些自定义字段（比如用  &lt;code&gt;$counts_path&lt;/code&gt;  来表示 count 矩阵路径、meta 信息和图像路径）：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;counts_path&lt;/code&gt; : 表达矩阵（spot × gene）的文本路径&lt;/li&gt;
&lt;li&gt;&lt;code&gt;meta_path&lt;/code&gt; : spot 的空间位置信息&lt;/li&gt;
&lt;li&gt;&lt;code&gt;img_path&lt;/code&gt; : H&amp;amp;E 图像文件路径&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;⚠️ 这些字段可能是你自己前期写入  &lt;code&gt;SeuratObject@images&lt;/code&gt;  的，不是默认字段。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;2-加载-python-脚本&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-加载-python-脚本&#34;&gt;#&lt;/a&gt; 🐍 2. 加载 Python 脚本&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;reticulate&lt;span class=&#34;operator&#34;&gt;::&lt;/span&gt;source_python&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;system.file&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;python&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;apply_spaGCN.py&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; package &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;EnSDD&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;source_python(...)&lt;/code&gt; ：通过 R 的  &lt;code&gt;reticulate&lt;/code&gt;  包加载 Python 脚本&lt;/li&gt;
&lt;li&gt;&lt;code&gt;system.file(...)&lt;/code&gt; ：定位 R 包  &lt;code&gt;EnSDD&lt;/code&gt;  中的  &lt;code&gt;apply_spaGCN.py&lt;/code&gt;  脚本路径
&lt;ul&gt;
&lt;li&gt;假设你安装了一个 R 包叫  &lt;code&gt;EnSDD&lt;/code&gt; ，它里面封装了运行 SpaGCN 所需的 Python 脚本&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;📝 被注释的  &lt;code&gt;EnSDD_pyexec(...)&lt;/code&gt;  也可能是某个自定义封装，但你实际使用的是  &lt;code&gt;reticulate&lt;/code&gt; 。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;3-调用-python-的-run_spagcn-函数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-调用-python-的-run_spagcn-函数&#34;&gt;#&lt;/a&gt; 🚀 3. 调用 Python 的  &lt;code&gt;run_spaGCN&lt;/code&gt;  函数&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;run_spaGCN&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;counts_path&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; meta_path&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; img_path&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           platform &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; platform&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           res_setting_by_user &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; res.setting&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           b &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;as.integer&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;SpaGCN_beta&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           a &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; SpaGCN_alpha&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           p &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; SpaGCN_p&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           n_clusters &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;as.integer&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;num.cluster&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           lr &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; SpaGCN_lr&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           max_epochs &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;as.integer&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;SpaGCN_epoches&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;这个函数在  &lt;code&gt;apply_spaGCN.py&lt;/code&gt;  中定义，接收参数并执行 SpaGCN 空间聚类任务&lt;/li&gt;
&lt;li&gt;SpaGCN 是一个 GCN（图卷积网络）框架，结合空间坐标和图像信息进行聚类&lt;/li&gt;
&lt;li&gt;参数解析：
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;b = beta&lt;/code&gt; ：控制空间光滑性&lt;/li&gt;
&lt;li&gt;&lt;code&gt;a = alpha&lt;/code&gt; 、 &lt;code&gt;p&lt;/code&gt; ：控制边权的计算&lt;/li&gt;
&lt;li&gt;&lt;code&gt;n_clusters&lt;/code&gt; ：聚类个数&lt;/li&gt;
&lt;li&gt;&lt;code&gt;res_setting_by_user&lt;/code&gt; : 分辨率&lt;/li&gt;
&lt;li&gt;&lt;code&gt;lr&lt;/code&gt; : 学习率&lt;/li&gt;
&lt;li&gt;&lt;code&gt;max_epochs&lt;/code&gt; : 迭代次数&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;✅ 此处训练过程全在 Python 中执行，输出为文件结果。&lt;/p&gt;
&lt;hr&gt;
&lt;h3 id=&#34;4-加载结果并处理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-加载结果并处理&#34;&gt;#&lt;/a&gt; 📁 4. 加载结果并处理&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;res.path &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; paste0&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;dirname&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;img_path&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;/spaGCN_res&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;/spaGCN_label.txt&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;res_temp &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; read.table&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res.path&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; sep &lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;\t&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;res &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; res_temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;V2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;names&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; res_temp&lt;span class=&#34;operator&#34;&gt;$&lt;/span&gt;V1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;Python 会在图片所在文件夹下创建  &lt;code&gt;spaGCN_res/spaGCN_label.txt&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;文件中记录的是： &lt;code&gt;spot名称 \t 聚类标签&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;把  &lt;code&gt;V2&lt;/code&gt;  作为聚类标签， &lt;code&gt;V1&lt;/code&gt;  为 spot 名，转换为一个 R 命名向量&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;5-spagcn-聚类结果中可能含有-0-类-调整为从1开始&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-spagcn-聚类结果中可能含有-0-类-调整为从1开始&#34;&gt;#&lt;/a&gt; 🔢 5. SpaGCN 聚类结果中可能含有 &amp;quot;0&amp;quot; 类 → 调整为从 1 开始&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;built_in&#34;&gt;sum&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res &lt;span class=&#34;operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;operator&#34;&gt;!=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  res &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; res &lt;span class=&#34;operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;如果存在 0 类，就全部 +1，使得聚类编号从 1 开始（防止误差）&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;6-根据-seurat-的列顺序排列聚类结果并清理中间文件夹&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6-根据-seurat-的列顺序排列聚类结果并清理中间文件夹&#34;&gt;#&lt;/a&gt; ✅ 6. 根据 Seurat 的列顺序排列聚类结果，并清理中间文件夹&lt;/h3&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;res &lt;span class=&#34;operator&#34;&gt;&amp;lt;-&lt;/span&gt; res&lt;span class=&#34;punctuation&#34;&gt;[&lt;/span&gt;colnames&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;Seurat.data&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;unlink&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;paste0&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;dirname&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;img_path&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;/spaGCN_res&amp;quot;&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;,&lt;/span&gt; recursive&lt;span class=&#34;operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;literal&#34;&gt;TRUE&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;return&lt;/span&gt;&lt;span class=&#34;punctuation&#34;&gt;(&lt;/span&gt;res&lt;span class=&#34;punctuation&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;确保返回的聚类向量顺序和 Seurat 中列顺序一致&lt;/li&gt;
&lt;li&gt;删除 SpaGCN 临时输出文件夹，避免污染&lt;/li&gt;
&lt;li&gt;返回：spot-level 聚类标签&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h3 id=&#34;总结一句话-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结一句话-2&#34;&gt;#&lt;/a&gt; 🎉 总结一句话：&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;apply_SpaGCN()&lt;/code&gt;  是一个 R 函数，用于封装和调用 Python 的  &lt;code&gt;SpaGCN&lt;/code&gt;  空间聚类过程，输入是 Seurat 对象，输出是每个 spot 的聚类标签。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;hr&gt;
&lt;p&gt;如果你想看  &lt;code&gt;apply_spaGCN.py&lt;/code&gt;  文件里  &lt;code&gt;run_spaGCN()&lt;/code&gt;  是如何实现的，也可以把那个 Python 文件贴给我，我可以继续帮你逐行解读～&lt;/p&gt;
&lt;p&gt;或者你想把这个结果接回 Seurat 进行可视化的话，也可以问我哦。&lt;/p&gt;
&lt;/div&gt;&lt;/details&gt;
&lt;figure class=&#34;highlight r&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span